#[derive(Debug)]
struct SnapshotPageStore<'a> {
    pager: &'a PagerHandle,
    wal: &'a WalHandle,
    snapshot_lsn: u64,
}

impl PageStore for SnapshotPageStore<'_> {
    fn page_size(&self) -> u32 {
        self.pager.page_size()
    }

    fn allocate_page(&mut self) -> Result<PageId> {
        Err(DbError::internal(
            "snapshot page store does not support allocation",
        ))
    }

    fn free_page(&mut self, _page_id: PageId) -> Result<()> {
        Err(DbError::internal(
            "snapshot page store does not support free",
        ))
    }

    fn read_page(&self, page_id: PageId) -> Result<Arc<[u8]>> {
        if let Some(page) =
            self.wal
                .read_page_at_snapshot(self.pager, page_id, self.snapshot_lsn)?
        {
            Ok(page)
        } else {
            self.pager.read_page_from_disk(page_id)
        }
    }

    fn advise_sequential(&self) -> Result<()> {
        self.pager.advise_sequential()
    }

    fn write_page(&mut self, _page_id: PageId, _data: &[u8]) -> Result<()> {
        Err(DbError::internal(
            "snapshot page store does not support writes",
        ))
    }
}

struct OverflowPayloadCursor<'a, S: PageStore> {
    store: &'a S,
    next_page_id: PageId,
    page: Option<Arc<[u8]>>,
    chunk_offset: usize,
    chunk_remaining: usize,
    remaining: usize,
}

impl<'a, S: PageStore> OverflowPayloadCursor<'a, S> {
    fn new(store: &'a S, pointer: OverflowPointer) -> Self {
        Self {
            store,
            next_page_id: pointer.head_page_id,
            page: None,
            chunk_offset: OVERFLOW_HEADER_SIZE,
            chunk_remaining: 0,
            remaining: pointer.logical_len as usize,
        }
    }

    fn read_i64(&mut self) -> Result<i64> {
        let mut bytes = [0_u8; 8];
        self.read_exact(&mut bytes)?;
        Ok(i64::from_le_bytes(bytes))
    }

    fn read_u32(&mut self) -> Result<u32> {
        let mut bytes = [0_u8; 4];
        self.read_exact(&mut bytes)?;
        Ok(u32::from_le_bytes(bytes))
    }

    fn read_vec(&mut self, len: usize) -> Result<Vec<u8>> {
        let mut bytes = vec![0_u8; len];
        self.read_exact(&mut bytes)?;
        Ok(bytes)
    }

    fn read_exact(&mut self, out: &mut [u8]) -> Result<()> {
        if out.len() > self.remaining {
            return Err(DbError::corruption("overflow payload length mismatch"));
        }
        let mut written = 0;
        while written < out.len() {
            self.ensure_chunk()?;
            let take = (out.len() - written).min(self.chunk_remaining);
            if take == 0 {
                return Err(DbError::corruption("overflow payload truncated"));
            }
            let page = self
                .page
                .as_ref()
                .ok_or_else(|| DbError::corruption("overflow payload page is missing"))?;
            out[written..written + take]
                .copy_from_slice(&page[self.chunk_offset..self.chunk_offset + take]);
            self.chunk_offset += take;
            self.chunk_remaining -= take;
            self.remaining -= take;
            written += take;
        }
        Ok(())
    }

    fn skip(&mut self, len: usize) -> Result<()> {
        if len > self.remaining {
            return Err(DbError::corruption("overflow payload length mismatch"));
        }
        let mut skipped = 0;
        while skipped < len {
            self.ensure_chunk()?;
            let take = (len - skipped).min(self.chunk_remaining);
            if take == 0 {
                return Err(DbError::corruption("overflow payload truncated"));
            }
            self.chunk_offset += take;
            self.chunk_remaining -= take;
            self.remaining -= take;
            skipped += take;
        }
        Ok(())
    }

    fn ensure_chunk(&mut self) -> Result<()> {
        while self.chunk_remaining == 0 {
            if self.remaining == 0 {
                return Ok(());
            }
            if self.next_page_id == 0 {
                return Err(DbError::corruption("overflow payload truncated"));
            }
            let page = self.store.read_page(self.next_page_id)?;
            if page.len() < OVERFLOW_HEADER_SIZE {
                return Err(DbError::corruption("overflow page shorter than header"));
            }
            let next_page_id = u32::from_le_bytes(page[0..4].try_into().expect("header next page"));
            let chunk_len = u32::from_le_bytes(page[4..8].try_into().expect("header chunk len"));
            let chunk_end = OVERFLOW_HEADER_SIZE + chunk_len as usize;
            if chunk_end > page.len() {
                return Err(DbError::corruption(
                    "overflow chunk length exceeds page payload",
                ));
            }
            self.next_page_id = next_page_id;
            self.page = Some(page);
            self.chunk_offset = OVERFLOW_HEADER_SIZE;
            self.chunk_remaining = chunk_len as usize;
        }
        Ok(())
    }
}

#[derive(Debug)]
struct DbTxnPageStore<'a> {
    db: &'a crate::db::Db,
}

impl PageStore for DbTxnPageStore<'_> {
    fn page_size(&self) -> u32 {
        self.db.config().page_size
    }

    fn allocate_page(&mut self) -> Result<PageId> {
        self.db.allocate_page()
    }

    fn free_page(&mut self, page_id: PageId) -> Result<()> {
        self.db.free_page(page_id)
    }

    fn read_page(&self, page_id: PageId) -> Result<Arc<[u8]>> {
        self.db.read_page_in_write_txn(page_id)
    }

    fn advise_sequential(&self) -> Result<()> {
        self.db.advise_sequential()
    }

    fn write_page(&mut self, page_id: PageId, data: &[u8]) -> Result<()> {
        self.db.write_page(page_id, data)
    }

    fn write_page_owned(&mut self, page_id: PageId, data: Vec<u8>) -> Result<()> {
        self.db.write_page_owned(page_id, data)
    }
}

fn covering_payloads_for_index(
    index: &IndexSchema,
    table: &TableSchema,
) -> Option<RuntimeCoveringPayloads> {
    let columns = covering_payload_column_names(index, table)?;
    Some(RuntimeCoveringPayloads::new(columns))
}

fn covering_payload_column_names(index: &IndexSchema, table: &TableSchema) -> Option<Vec<String>> {
    if index.kind != IndexKind::Btree
        || index.predicate_sql.is_some()
        || index.include_columns.is_empty()
        || !generated_columns_are_stored(table)
    {
        return None;
    }

    let mut columns: Vec<String> = Vec::new();
    for column in index
        .columns
        .iter()
        .map(|column| column.column_name.as_deref())
        .chain(
            index
                .include_columns
                .iter()
                .map(|column| Some(column.as_str())),
        )
    {
        let column = column?;
        schema_column_index(table, column)?;
        if !columns
            .iter()
            .any(|existing| identifiers_equal(existing, column))
        {
            columns.push(column.to_string());
        }
    }
    if columns.is_empty() {
        None
    } else {
        Some(columns)
    }
}

fn covering_payload_values_for_row(
    index: &IndexSchema,
    table: &TableSchema,
    row_values: &[Value],
) -> Option<Vec<Value>> {
    let columns = covering_payload_column_names(index, table)?;
    columns
        .iter()
        .map(|column| {
            schema_column_index(table, column)
                .and_then(|offset| row_values.get(offset))
                .cloned()
        })
        .collect()
}

fn build_runtime_index(
    index: &IndexSchema,
    runtime: &EngineRuntime,
    page_size: u32,
) -> Result<RuntimeIndex> {
    let table = runtime.catalog.table(&index.table_name).ok_or_else(|| {
        DbError::corruption(format!(
            "index {} references missing table {}",
            index.name, index.table_name
        ))
    })?;
    let source = runtime.table_row_source(&index.table_name).ok_or_else(|| {
        DbError::corruption(format!("table data for {} is missing", index.table_name))
    })?;

    match index.kind {
        IndexKind::Btree => {
            let int64_keys = btree_uses_typed_int64_keys(index, table);
            let mut covering = covering_payloads_for_index(index, table);
            if index.unique && int64_keys {
                let mut keys = HashMap::with_capacity_and_hasher(
                    source.row_count(),
                    Int64HashBuilder::default(),
                );
                for row in source.rows() {
                    let row = row?;
                    let Some(key) = compute_index_key(runtime, index, table, row.values())? else {
                        continue;
                    };
                    let RuntimeBtreeKey::Int64(key) = key else {
                        return Err(DbError::internal(
                            "typed INT64 runtime index received an encoded key",
                        ));
                    };
                    if keys.insert(key, row.row_id()).is_some() {
                        return Err(DbError::corruption(format!(
                            "unique index {} contains duplicate keys",
                            index.name
                        )));
                    }
                    if let Some(covering) = covering.as_mut() {
                        if let Some(values) =
                            covering_payload_values_for_row(index, table, row.values())
                        {
                            covering.insert_row_values(row.row_id(), values);
                        }
                    }
                }
                Ok(RuntimeIndex::Btree {
                    keys: RuntimeBtreeKeys::UniqueInt64(keys),
                    covering,
                })
            } else if index.unique {
                let mut keys = BTreeMap::<Vec<u8>, i64>::new();
                for row in source.rows() {
                    let row = row?;
                    let Some(key) = compute_index_key(runtime, index, table, row.values())? else {
                        continue;
                    };
                    let RuntimeBtreeKey::Encoded(key) = key else {
                        return Err(DbError::internal(
                            "encoded runtime index received an INT64 key",
                        ));
                    };
                    if keys.insert(key, row.row_id()).is_some() {
                        return Err(DbError::corruption(format!(
                            "unique index {} contains duplicate keys",
                            index.name
                        )));
                    }
                    if let Some(covering) = covering.as_mut() {
                        if let Some(values) =
                            covering_payload_values_for_row(index, table, row.values())
                        {
                            covering.insert_row_values(row.row_id(), values);
                        }
                    }
                }
                Ok(RuntimeIndex::Btree {
                    keys: RuntimeBtreeKeys::UniqueEncoded(keys),
                    covering,
                })
            } else if int64_keys {
                let mut keys: Int64Map<Vec<i64>> = HashMap::with_capacity_and_hasher(
                    source.row_count(),
                    Int64HashBuilder::default(),
                );
                for row in source.rows() {
                    let row = row?;
                    let Some(key) = compute_index_key(runtime, index, table, row.values())? else {
                        continue;
                    };
                    let RuntimeBtreeKey::Int64(key) = key else {
                        return Err(DbError::internal(
                            "typed INT64 runtime index received an encoded key",
                        ));
                    };
                    keys.entry(key).or_default().push(row.row_id());
                    if let Some(covering) = covering.as_mut() {
                        if let Some(values) =
                            covering_payload_values_for_row(index, table, row.values())
                        {
                            covering.insert_row_values(row.row_id(), values);
                        }
                    }
                }
                Ok(RuntimeIndex::Btree {
                    keys: RuntimeBtreeKeys::NonUniqueInt64(keys),
                    covering,
                })
            } else {
                let mut keys = BTreeMap::<Vec<u8>, Vec<i64>>::new();
                for row in source.rows() {
                    let row = row?;
                    let Some(key) = compute_index_key(runtime, index, table, row.values())? else {
                        continue;
                    };
                    let RuntimeBtreeKey::Encoded(key) = key else {
                        return Err(DbError::internal(
                            "encoded runtime index received an INT64 key",
                        ));
                    };
                    keys.entry(key).or_default().push(row.row_id());
                    if let Some(covering) = covering.as_mut() {
                        if let Some(values) =
                            covering_payload_values_for_row(index, table, row.values())
                        {
                            covering.insert_row_values(row.row_id(), values);
                        }
                    }
                }
                Ok(RuntimeIndex::Btree {
                    keys: RuntimeBtreeKeys::NonUniqueEncoded(keys),
                    covering,
                })
            }
        }
        IndexKind::Trigram => {
            let mut trigram = TrigramIndex::new(page_size, 100_000);
            let mut builder = TrigramIndexBuilder::new();
            for row in source.rows() {
                let row = row?;
                if !row_satisfies_index_predicate(runtime, index, table, row.values())? {
                    continue;
                }
                if let Value::Text(text) =
                    compute_index_values(runtime, index, table, row.values())?
                        .into_iter()
                        .next()
                        .ok_or_else(|| {
                            DbError::constraint("trigram index requires a single text expression")
                        })?
                {
                    builder.insert(row.row_id() as u64, &text);
                }
            }
            builder.finish_into(&mut trigram)?;
            Ok(RuntimeIndex::Trigram { index: trigram })
        }
        IndexKind::Spatial => {
            let backend = spatial_index_backend(index, table)?;
            let mut spatial = SpatialRuntimeIndex::new(backend);
            for row in source.rows() {
                let row = row?;
                if let Some(value) =
                    spatial_index_value_for_row(runtime, index, table, row.values())?
                {
                    spatial.insert(row.row_id(), value).map_err(spatial_error)?;
                }
            }
            Ok(RuntimeIndex::Spatial { index: spatial })
        }
        IndexKind::FullText => {
            let config = index
                .full_text
                .clone()
                .ok_or_else(|| DbError::corruption("fulltext index is missing analyzer config"))?;
            let mut fulltext = FullTextIndex::new(config);
            for row in source.rows() {
                let row = row?;
                if !row_satisfies_index_predicate(runtime, index, table, row.values())? {
                    continue;
                }
                let fields = full_text_fields_for_row(runtime, index, table, row.values())?;
                let field_refs = fields.iter().map(Option::as_deref).collect::<Vec<_>>();
                fulltext.insert_document(row.row_id() as u64, &field_refs);
            }
            Ok(RuntimeIndex::FullText { index: fulltext })
        }
    }
}

pub(super) fn compute_index_key(
    runtime: &EngineRuntime,
    index: &IndexSchema,
    table: &TableSchema,
    row_values: &[Value],
) -> Result<Option<RuntimeBtreeKey>> {
    if !row_satisfies_index_predicate(runtime, index, table, row_values)? {
        return Ok(None);
    }
    if btree_uses_typed_int64_keys(index, table) {
        let [column] = index.columns.as_slice() else {
            return Err(DbError::internal(
                "typed INT64 runtime indexes require exactly one indexed column",
            ));
        };
        if let Some(column_name) = &column.column_name {
            let position = column_position(table, column_name).ok_or_else(|| {
                DbError::constraint(format!("index column {} does not exist", column_name))
            })?;
            let Value::Int64(value) = row_values
                .get(position)
                .ok_or_else(|| DbError::internal("row is shorter than table schema"))?
            else {
                return Err(DbError::internal(
                    "typed INT64 runtime index expected an INT64 row value",
                ));
            };
            return Ok(Some(RuntimeBtreeKey::Int64(*value)));
        }
    }
    let values = compute_index_values(runtime, index, table, row_values)?;
    if index.unique && values.iter().any(|value| matches!(value, Value::Null)) {
        return Ok(None);
    }
    let key = if values.len() == 1 {
        encode_index_key(&values[0])?
    } else {
        Row::new(values).encode()?
    };
    Ok(Some(RuntimeBtreeKey::Encoded(key)))
}

pub(super) fn spatial_index_backend(
    index: &IndexSchema,
    table: &TableSchema,
) -> Result<SpatialIndexBackend> {
    let column_index = spatial_index_column_index(index, table)?;
    match table.columns[column_index].column_type {
        ColumnType::Geography => Ok(SpatialIndexBackend::GeographyS2),
        ColumnType::Geometry => Ok(SpatialIndexBackend::GeometryQuadCell),
        _ => Err(DbError::internal(format!(
            "SPATIAL index {} targets a non-spatial column",
            index.name
        ))),
    }
}

pub(super) fn spatial_index_value_for_row(
    runtime: &EngineRuntime,
    index: &IndexSchema,
    table: &TableSchema,
    row_values: &[Value],
) -> Result<Option<SpatialValue>> {
    if !row_satisfies_index_predicate(runtime, index, table, row_values)? {
        return Ok(None);
    }
    let column_index = spatial_index_column_index(index, table)?;
    let value = row_values
        .get(column_index)
        .ok_or_else(|| DbError::internal("row is shorter than table schema"))?;
    let Some((is_geography, spatial)) = spatial_value_from_db(value)? else {
        return Ok(None);
    };
    match (table.columns[column_index].column_type, is_geography) {
        (ColumnType::Geography, true) | (ColumnType::Geometry, false) => Ok(Some(spatial)),
        (ColumnType::Geography, false) => Err(DbError::constraint(format!(
            "SPATIAL index {} expected GEOGRAPHY values",
            index.name
        ))),
        (ColumnType::Geometry, true) => Err(DbError::constraint(format!(
            "SPATIAL index {} expected GEOMETRY values",
            index.name
        ))),
        _ => Err(DbError::internal(format!(
            "SPATIAL index {} targets a non-spatial column",
            index.name
        ))),
    }
}

fn spatial_index_column_index(index: &IndexSchema, table: &TableSchema) -> Result<usize> {
    if index.kind != IndexKind::Spatial || index.columns.len() != 1 {
        return Err(DbError::internal(format!(
            "SPATIAL index {} must target exactly one column",
            index.name
        )));
    }
    let column_name = index.columns[0].column_name.as_deref().ok_or_else(|| {
        DbError::internal(format!(
            "SPATIAL index {} must target a plain column",
            index.name
        ))
    })?;
    if index.columns[0].expression_sql.is_some() {
        return Err(DbError::internal(format!(
            "SPATIAL index {} cannot target an expression",
            index.name
        )));
    }
    table
        .columns
        .iter()
        .position(|entry| identifiers_equal(&entry.name, column_name))
        .ok_or_else(|| DbError::constraint(format!("index column {} does not exist", column_name)))
}

fn btree_uses_typed_int64_keys(index: &IndexSchema, table: &TableSchema) -> bool {
    let [column] = index.columns.as_slice() else {
        return false;
    };
    if column.expression_sql.is_some() {
        return false;
    }
    let Some(column_name) = &column.column_name else {
        return false;
    };
    column_schema(table, column_name).is_some_and(|column| {
        column.column_type == crate::catalog::ColumnType::Int64 && !column.nullable
    })
}

pub(super) fn compute_index_values(
    runtime: &EngineRuntime,
    index: &IndexSchema,
    table: &TableSchema,
    row_values: &[Value],
) -> Result<Vec<Value>> {
    let row_materialized = if generated_columns_are_stored(table) {
        Cow::Borrowed(row_values)
    } else {
        let mut materialized = row_values.to_vec();
        runtime.apply_virtual_generated_columns(table, &mut materialized)?;
        Cow::Owned(materialized)
    };
    let row_for_eval = row_materialized.as_ref();
    let dataset = table_row_dataset(table, row_for_eval, &table.name);
    let bindings = dataset.rows.first().map(Vec::as_slice).unwrap_or(&[]);
    index
        .columns
        .iter()
        .map(|column| {
            if let Some(column_name) = &column.column_name {
                let position = column_position(table, column_name).ok_or_else(|| {
                    DbError::constraint(format!("index column {} does not exist", column_name))
                })?;
                Ok(row_for_eval[position].clone())
            } else if let Some(expression_sql) = &column.expression_sql {
                let expr = crate::sql::parser::parse_expression_sql(expression_sql)?;
                runtime.eval_expr(&expr, &dataset, bindings, &[], &BTreeMap::new(), None)
            } else {
                Err(DbError::constraint("index column definition is empty"))
            }
        })
        .collect()
}

pub(super) fn full_text_fields_for_row(
    runtime: &EngineRuntime,
    index: &IndexSchema,
    table: &TableSchema,
    row_values: &[Value],
) -> Result<Vec<Option<String>>> {
    if !row_satisfies_index_predicate(runtime, index, table, row_values)? {
        return Ok(Vec::new());
    }
    compute_index_values(runtime, index, table, row_values)?
        .into_iter()
        .map(|value| match value {
            Value::Text(text) => Ok(Some(text)),
            Value::Null => Ok(None),
            other => Err(DbError::constraint(format!(
                "fulltext index requires TEXT columns, got {other:?}"
            ))),
        })
        .collect()
}

pub(super) fn row_satisfies_index_predicate(
    runtime: &EngineRuntime,
    index: &IndexSchema,
    table: &TableSchema,
    row_values: &[Value],
) -> Result<bool> {
    let Some(predicate_sql) = &index.predicate_sql else {
        return Ok(true);
    };
    let expr = crate::sql::parser::parse_expression_sql(predicate_sql)?;
    let row_materialized = if generated_columns_are_stored(table) {
        Cow::Borrowed(row_values)
    } else {
        let mut materialized = row_values.to_vec();
        runtime.apply_virtual_generated_columns(table, &mut materialized)?;
        Cow::Owned(materialized)
    };
    let row_for_eval = row_materialized.as_ref();
    let dataset = table_row_dataset(table, row_for_eval, &table.name);
    let bindings = dataset.rows.first().map(Vec::as_slice).unwrap_or(&[]);
    Ok(matches!(
        runtime.eval_expr(&expr, &dataset, bindings, &[], &BTreeMap::new(), None)?,
        Value::Bool(true)
    ))
}

pub(crate) fn row_satisfies_expression(
    runtime: &EngineRuntime,
    table_name: &str,
    column_names: &[String],
    row_values: &[Value],
    expr: &Expr,
) -> Result<bool> {
    if column_names.len() != row_values.len() {
        return Err(DbError::internal(
            "row filter evaluation received mismatched column/value counts",
        ));
    }
    let dataset = Dataset::with_rows(
        column_names
            .iter()
            .map(|column| ColumnBinding::visible(Some(table_name.to_string()), column.clone()))
            .collect(),
        vec![row_values.to_vec()],
    );
    let row = dataset.rows.first().map(Vec::as_slice).unwrap_or(&[]);
    Ok(matches!(
        runtime.eval_expr(expr, &dataset, row, &[], &BTreeMap::new(), None)?,
        Value::Bool(true)
    ))
}

pub(super) fn table_row_dataset(table: &TableSchema, row: &[Value], table_name: &str) -> Dataset {
    Dataset::with_rows(
        table
            .columns
            .iter()
            .map(|column| ColumnBinding::visible(Some(table_name.to_string()), column.name.clone()))
            .collect(),
        vec![row.to_vec()],
    )
}

fn table_bindings_with_hidden_row_id(table: &TableSchema, table_name: &str) -> Vec<ColumnBinding> {
    let mut columns = table
        .columns
        .iter()
        .map(|column| {
            ColumnBinding::visible_source(
                Some(table_name.to_string()),
                Some(table.name.clone()),
                column.name.clone(),
            )
        })
        .collect::<Vec<_>>();
    columns.push(ColumnBinding::hidden_source(
        Some(table_name.to_string()),
        Some(table.name.clone()),
        FTS_HIDDEN_ROW_ID_COLUMN.to_string(),
    ));
    columns
}

fn decode_root_header(page_bytes: &[u8]) -> Result<Option<RootHeader>> {
    if page_bytes.iter().all(|byte| *byte == 0) {
        return Ok(None);
    }
    if page_bytes.len() < ENGINE_ROOT_HEADER_SIZE {
        return Err(DbError::corruption("catalog root page is truncated"));
    }
    if page_bytes[0..ENGINE_ROOT_MAGIC.len()] != ENGINE_ROOT_MAGIC {
        return Err(DbError::corruption("catalog root page magic is invalid"));
    }
    let version = u32::from_le_bytes(page_bytes[8..12].try_into().expect("version"));
    if version != ENGINE_ROOT_VERSION {
        return Err(DbError::corruption(format!(
            "unsupported catalog root version {version}"
        )));
    }
    Ok(Some(RootHeader {
        schema_cookie: u32::from_le_bytes(page_bytes[12..16].try_into().expect("cookie")),
        payload_checksum: u32::from_le_bytes(page_bytes[16..20].try_into().expect("checksum")),
        pointer: OverflowPointer {
            head_page_id: u32::from_le_bytes(page_bytes[20..24].try_into().expect("head page")),
            logical_len: u32::from_le_bytes(page_bytes[24..28].try_into().expect("logical len")),
            flags: page_bytes[28],
        },
    }))
}

fn encode_root_header(page_size: u32, header: RootHeader) -> Vec<u8> {
    let mut page = vec![0_u8; page_size as usize];
    page[0..8].copy_from_slice(&ENGINE_ROOT_MAGIC);
    page[8..12].copy_from_slice(&ENGINE_ROOT_VERSION.to_le_bytes());
    page[12..16].copy_from_slice(&header.schema_cookie.to_le_bytes());
    page[16..20].copy_from_slice(&header.payload_checksum.to_le_bytes());
    page[20..24].copy_from_slice(&header.pointer.head_page_id.to_le_bytes());
    page[24..28].copy_from_slice(&header.pointer.logical_len.to_le_bytes());
    page[28] = header.pointer.flags;
    page
}

#[cfg(test)]
fn encode_runtime_payload(runtime: &EngineRuntime) -> Result<Vec<u8>> {
    let mut output = Vec::new();
    output.extend_from_slice(LEGACY_RUNTIME_PAYLOAD_MAGIC);
    encode_u32(&mut output, runtime.catalog.schema_cookie);
    encode_u32(&mut output, runtime.catalog.tables.len() as u32);
    for table in runtime.catalog.tables.values() {
        encode_string(&mut output, &table.name)?;
        encode_u32(&mut output, table.columns.len() as u32);
        for column in &table.columns {
            encode_string(&mut output, &column.name)?;
            output.push(encode_column_type(column.column_type));
            output.push(u8::from(column.nullable));
            encode_optional_string(&mut output, column.default_sql.as_deref())?;
            output.push(u8::from(column.primary_key));
            output.push(u8::from(column.unique));
            output.push(u8::from(column.auto_increment));
            encode_u32(&mut output, column.checks.len() as u32);
            for check in &column.checks {
                encode_optional_string(&mut output, check.name.as_deref())?;
                encode_string(&mut output, &check.expression_sql)?;
            }
            output.push(u8::from(column.foreign_key.is_some()));
            if let Some(foreign_key) = &column.foreign_key {
                encode_foreign_key(&mut output, foreign_key)?;
            }
        }
        encode_u32(&mut output, table.checks.len() as u32);
        for check in &table.checks {
            encode_optional_string(&mut output, check.name.as_deref())?;
            encode_string(&mut output, &check.expression_sql)?;
        }
        encode_u32(&mut output, table.foreign_keys.len() as u32);
        for foreign_key in &table.foreign_keys {
            encode_foreign_key(&mut output, foreign_key)?;
        }
        encode_strings(&mut output, &table.primary_key_columns)?;
        encode_i64(&mut output, table.next_row_id);
        let data = runtime
            .tables
            .get(&table.name)
            .map(|source| source.resident_data().clone())
            .unwrap_or_default();
        encode_u32(&mut output, data.rows.len() as u32);
        for row in data.rows {
            encode_i64(&mut output, row.row_id);
            let encoded = Row::new(row.values).encode()?;
            encode_bytes(&mut output, &encoded)?;
        }
    }

    encode_u32(&mut output, runtime.catalog.indexes.len() as u32);
    for index in runtime.catalog.indexes.values() {
        encode_string(&mut output, &index.name)?;
        encode_string(&mut output, &index.table_name)?;
        output.push(index.kind as u8);
        output.push(u8::from(index.unique));
        encode_u32(&mut output, index.columns.len() as u32);
        for column in &index.columns {
            encode_optional_string(&mut output, column.column_name.as_deref())?;
            encode_optional_string(&mut output, column.expression_sql.as_deref())?;
        }
        encode_optional_string(&mut output, index.predicate_sql.as_deref())?;
        output.push(u8::from(index.fresh));
    }
    encode_u32(&mut output, runtime.catalog.views.len() as u32);
    for view in runtime.catalog.views.values() {
        encode_string(&mut output, &view.name)?;
        encode_string(&mut output, &view.sql_text)?;
        encode_strings(&mut output, &view.column_names)?;
        encode_strings(&mut output, &view.dependencies)?;
    }

    encode_u32(&mut output, runtime.catalog.triggers.len() as u32);
    for trigger in runtime.catalog.triggers.values() {
        encode_string(&mut output, &trigger.name)?;
        encode_string(&mut output, &trigger.target_name)?;
        output.push(trigger.kind as u8);
        output.push(trigger.event as u8);
        output.push(u8::from(trigger.on_view));
        encode_string(&mut output, &trigger.action_sql)?;
    }
    encode_schemas_section(&mut output, &runtime.catalog.schemas)?;
    encode_index_include_columns_section(&mut output, &runtime.catalog.indexes)?;
    encode_full_text_options_section(&mut output, &runtime.catalog.indexes)?;
    encode_generated_columns_section(&mut output, &runtime.catalog.tables)?;
    encode_spatial_columns_section(&mut output, &runtime.catalog.tables)?;
    encode_enum_columns_section(&mut output, &runtime.catalog.tables)?;
    Ok(output)
}

fn decode_runtime_payload(bytes: &[u8]) -> Result<EngineRuntime> {
    let mut cursor = Cursor::new(bytes);
    let magic = cursor.read_slice(9)?;
    if magic != LEGACY_RUNTIME_PAYLOAD_MAGIC {
        return Err(DbError::corruption("catalog state magic is invalid"));
    }
    let mut runtime = EngineRuntime::empty(cursor.read_u32()?);
    let table_count = cursor.read_u32()?;
    for _ in 0..table_count {
        let table_name = cursor.read_string()?;
        let column_count = cursor.read_u32()?;
        let mut table = TableSchema {
            name: table_name.clone(),
            temporary: false,
            columns: Vec::with_capacity(column_count as usize),
            checks: Vec::new(),
            foreign_keys: Vec::new(),
            primary_key_columns: Vec::new(),
            next_row_id: 1,
            pk_index_root: None,
        };
        for _ in 0..column_count {
            let name = cursor.read_string()?;
            let column_type = decode_column_type(cursor.read_u8()?)?;
            let nullable = cursor.read_bool()?;
            let default_sql = cursor.read_optional_string()?;
            let primary_key = cursor.read_bool()?;
            let unique = cursor.read_bool()?;
            let auto_increment = cursor.read_bool()?;
            let check_count = cursor.read_u32()?;
            let mut checks = Vec::with_capacity(check_count as usize);
            for _ in 0..check_count {
                checks.push(crate::catalog::CheckConstraint {
                    name: cursor.read_optional_string()?,
                    expression_sql: cursor.read_string()?,
                });
            }
            let has_fk = cursor.read_bool()?;
            let foreign_key = if has_fk {
                Some(decode_foreign_key(&mut cursor)?)
            } else {
                None
            };
            table.columns.push(crate::catalog::ColumnSchema {
                name,
                column_type,
                spatial_type: None,
                enum_type: None,
                nullable,
                default_sql,
                generated_sql: None,
                generated_stored: true,
                primary_key,
                unique,
                auto_increment,
                checks,
                foreign_key,
            });
        }
        let table_check_count = cursor.read_u32()?;
        for _ in 0..table_check_count {
            table.checks.push(crate::catalog::CheckConstraint {
                name: cursor.read_optional_string()?,
                expression_sql: cursor.read_string()?,
            });
        }
        let fk_count = cursor.read_u32()?;
        for _ in 0..fk_count {
            table.foreign_keys.push(decode_foreign_key(&mut cursor)?);
        }
        table.primary_key_columns = cursor.read_strings()?;
        table.next_row_id = cursor.read_i64()?;
        let row_count = cursor.read_u32()?;
        let mut data = TableData::default();
        for _ in 0..row_count {
            let row_id = cursor.read_i64()?;
            let row_bytes_len = cursor.read_u32()? as usize;
            let row_bytes = cursor.read_slice(row_bytes_len)?;
            let row = Row::decode(row_bytes)?;
            data.push_row(StoredRow {
                row_id,
                values: row.into_values(),
            });
        }
        runtime
            .catalog_mut()
            .tables
            .insert(table_name.clone(), table);
        runtime.tables_mut().insert(table_name, data.into());
    }

    let index_count = cursor.read_u32()?;
    for _ in 0..index_count {
        let name = cursor.read_string()?;
        let table_name = cursor.read_string()?;
        let kind = decode_index_kind(cursor.read_u8()?)?;
        let unique = cursor.read_bool()?;
        let column_count = cursor.read_u32()?;
        let mut columns = Vec::with_capacity(column_count as usize);
        for _ in 0..column_count {
            columns.push(crate::catalog::IndexColumn {
                column_name: cursor.read_optional_string()?,
                expression_sql: cursor.read_optional_string()?,
            });
        }
        let predicate_sql = cursor.read_optional_string()?;
        let fresh = cursor.read_bool()?;
        runtime.catalog_mut().indexes.insert(
            name.clone(),
            crate::catalog::IndexSchema {
                name,
                table_name,
                kind,
                unique,
                columns,
                include_columns: Vec::new(),
                predicate_sql,
                full_text: None,
                fresh,
            },
        );
    }
    let view_count = cursor.read_u32()?;
    for _ in 0..view_count {
        let view = crate::catalog::ViewSchema {
            name: cursor.read_string()?,
            temporary: false,
            sql_text: cursor.read_string()?,
            column_names: cursor.read_strings()?,
            dependencies: cursor.read_strings()?,
        };
        runtime.catalog_mut().views.insert(view.name.clone(), view);
    }

    let trigger_count = cursor.read_u32()?;
    for _ in 0..trigger_count {
        let trigger = crate::catalog::TriggerSchema {
            name: cursor.read_string()?,
            target_name: cursor.read_string()?,
            kind: decode_trigger_kind(cursor.read_u8()?)?,
            event: decode_trigger_event(cursor.read_u8()?)?,
            on_view: cursor.read_bool()?,
            action_sql: cursor.read_string()?,
        };
        runtime
            .catalog_mut()
            .triggers
            .insert(trigger.name.clone(), trigger);
    }
    if cursor.offset < cursor.bytes.len() {
        decode_schemas_section(&mut cursor, &mut runtime.catalog_mut().schemas)?;
    }
    if cursor.offset < cursor.bytes.len() {
        decode_index_include_columns_section(&mut cursor, &mut runtime.catalog_mut().indexes)?;
    }
    if cursor.offset < cursor.bytes.len() {
        decode_full_text_options_section(&mut cursor, &mut runtime.catalog_mut().indexes)?;
    }
    if cursor.offset < cursor.bytes.len() {
        decode_generated_columns_section(&mut cursor, &mut runtime.catalog_mut().tables)?;
    }
    if cursor.offset < cursor.bytes.len() {
        decode_spatial_columns_section(&mut cursor, &mut runtime.catalog_mut().tables)?;
    }
    if cursor.offset < cursor.bytes.len() {
        decode_enum_columns_section(&mut cursor, &mut runtime.catalog_mut().tables)?;
    }
    if cursor.offset < cursor.bytes.len() {
        decode_pk_index_roots_section(&mut cursor, &mut runtime.catalog_mut().tables)?;
    }
    Ok(runtime)
}

#[cfg(test)]
fn encode_manifest_payload(
    runtime: &EngineRuntime,
    table_states: &BTreeMap<String, PersistedTableState>,
) -> Result<Vec<u8>> {
    Ok(encode_manifest_payload_with_offsets(runtime, table_states)?.bytes)
}

fn encode_manifest_payload_with_offsets(
    runtime: &EngineRuntime,
    table_states: &BTreeMap<String, PersistedTableState>,
) -> Result<ManifestEncoding> {
    let mut output = Vec::new();
    let mut table_next_row_id_offsets = BTreeMap::new();
    let mut table_state_offsets = BTreeMap::new();
    let mut table_pk_index_root_offsets = BTreeMap::new();
    output.extend_from_slice(MANIFEST_PAYLOAD_MAGIC);
    encode_u32(&mut output, runtime.catalog.schema_cookie);
    encode_u32(&mut output, runtime.catalog.tables.len() as u32);
    for table in runtime.catalog.tables.values() {
        encode_string(&mut output, &table.name)?;
        encode_u32(&mut output, table.columns.len() as u32);
        for column in &table.columns {
            encode_string(&mut output, &column.name)?;
            output.push(encode_column_type(column.column_type));
            output.push(u8::from(column.nullable));
            encode_optional_string(&mut output, column.default_sql.as_deref())?;
            output.push(u8::from(column.primary_key));
            output.push(u8::from(column.unique));
            output.push(u8::from(column.auto_increment));
            encode_u32(&mut output, column.checks.len() as u32);
            for check in &column.checks {
                encode_optional_string(&mut output, check.name.as_deref())?;
                encode_string(&mut output, &check.expression_sql)?;
            }
            output.push(u8::from(column.foreign_key.is_some()));
            if let Some(foreign_key) = &column.foreign_key {
                encode_foreign_key(&mut output, foreign_key)?;
            }
        }
        encode_u32(&mut output, table.checks.len() as u32);
        for check in &table.checks {
            encode_optional_string(&mut output, check.name.as_deref())?;
            encode_string(&mut output, &check.expression_sql)?;
        }
        encode_u32(&mut output, table.foreign_keys.len() as u32);
        for foreign_key in &table.foreign_keys {
            encode_foreign_key(&mut output, foreign_key)?;
        }
        encode_strings(&mut output, &table.primary_key_columns)?;
        table_next_row_id_offsets.insert(table.name.clone(), output.len());
        encode_i64(&mut output, table.next_row_id);
        table_state_offsets.insert(table.name.clone(), output.len());
        let state = table_states.get(&table.name).copied().unwrap_or_default();
        encode_u32(&mut output, state.checksum);
        encode_u32(&mut output, state.pointer.head_page_id);
        encode_u32(&mut output, state.pointer.logical_len);
        output.push(state.pointer.flags);
    }

    encode_u32(&mut output, runtime.catalog.indexes.len() as u32);
    for index in runtime.catalog.indexes.values() {
        encode_string(&mut output, &index.name)?;
        encode_string(&mut output, &index.table_name)?;
        output.push(index.kind as u8);
        output.push(u8::from(index.unique));
        encode_u32(&mut output, index.columns.len() as u32);
        for column in &index.columns {
            encode_optional_string(&mut output, column.column_name.as_deref())?;
            encode_optional_string(&mut output, column.expression_sql.as_deref())?;
        }
        encode_optional_string(&mut output, index.predicate_sql.as_deref())?;
        output.push(u8::from(index.fresh));
    }
    encode_u32(&mut output, runtime.catalog.views.len() as u32);
    for view in runtime.catalog.views.values() {
        encode_string(&mut output, &view.name)?;
        encode_string(&mut output, &view.sql_text)?;
        encode_strings(&mut output, &view.column_names)?;
        encode_strings(&mut output, &view.dependencies)?;
    }

    encode_u32(&mut output, runtime.catalog.triggers.len() as u32);
    for trigger in runtime.catalog.triggers.values() {
        encode_string(&mut output, &trigger.name)?;
        encode_string(&mut output, &trigger.target_name)?;
        output.push(trigger.kind as u8);
        output.push(trigger.event as u8);
        output.push(u8::from(trigger.on_view));
        encode_string(&mut output, &trigger.action_sql)?;
    }

    let table_stats = runtime
        .catalog
        .table_stats
        .iter()
        .filter(|(name, _)| runtime.catalog.tables.contains_key(*name))
        .collect::<Vec<_>>();
    encode_u32(&mut output, table_stats.len() as u32);
    for (name, stats) in table_stats {
        encode_string(&mut output, name)?;
        encode_i64(&mut output, stats.row_count);
    }

    let index_stats = runtime
        .catalog
        .index_stats
        .iter()
        .filter(|(name, _)| runtime.catalog.indexes.contains_key(*name))
        .collect::<Vec<_>>();
    encode_u32(&mut output, index_stats.len() as u32);
    for (name, stats) in index_stats {
        encode_string(&mut output, name)?;
        encode_i64(&mut output, stats.entry_count);
        encode_i64(&mut output, stats.distinct_key_count);
    }
    encode_schemas_section(&mut output, &runtime.catalog.schemas)?;
    encode_index_include_columns_section(&mut output, &runtime.catalog.indexes)?;
    encode_full_text_options_section(&mut output, &runtime.catalog.indexes)?;
    encode_generated_columns_section(&mut output, &runtime.catalog.tables)?;
    encode_spatial_columns_section(&mut output, &runtime.catalog.tables)?;
    encode_enum_columns_section(&mut output, &runtime.catalog.tables)?;
    encode_pk_index_roots_section(
        &mut output,
        &runtime.catalog.tables,
        Some(&mut table_pk_index_root_offsets),
    )?;
    Ok(ManifestEncoding {
        bytes: output,
        table_next_row_id_offsets,
        table_state_offsets,
        table_pk_index_root_offsets,
    })
}

fn patch_manifest_table_next_row_id(
    payload: &mut [u8],
    offset: usize,
    next_row_id: i64,
) -> Result<()> {
    let end = offset
        .checked_add(8)
        .ok_or_else(|| DbError::internal("manifest next_row_id offset overflow"))?;
    if end > payload.len() {
        return Err(DbError::internal(
            "manifest next_row_id offset exceeded payload length",
        ));
    }
    payload[offset..end].copy_from_slice(&next_row_id.to_le_bytes());
    Ok(())
}

fn patch_manifest_table_state(
    payload: &mut [u8],
    offset: usize,
    state: PersistedTableState,
) -> Result<()> {
    let end = offset
        .checked_add(13)
        .ok_or_else(|| DbError::internal("manifest table-state offset overflow"))?;
    if end > payload.len() {
        return Err(DbError::internal(
            "manifest table-state offset exceeded payload length",
        ));
    }
    payload[offset..offset + 4].copy_from_slice(&state.checksum.to_le_bytes());
    payload[offset + 4..offset + 8].copy_from_slice(&state.pointer.head_page_id.to_le_bytes());
    payload[offset + 8..offset + 12].copy_from_slice(&state.pointer.logical_len.to_le_bytes());
    payload[offset + 12] = state.pointer.flags;
    Ok(())
}

fn patch_manifest_table_pk_index_root(
    payload: &mut [u8],
    offset: usize,
    pk_index_root: Option<PageId>,
) -> Result<()> {
    let end = offset
        .checked_add(4)
        .ok_or_else(|| DbError::internal("manifest pk_index_root offset overflow"))?;
    if end > payload.len() {
        return Err(DbError::internal(
            "manifest pk_index_root offset exceeded payload length",
        ));
    }
    payload[offset..end].copy_from_slice(&pk_index_root.unwrap_or(0).to_le_bytes());
    Ok(())
}

fn decode_manifest_payload<S: PageStore>(_store: &S, bytes: &[u8]) -> Result<EngineRuntime> {
    let mut cursor = Cursor::new(bytes);
    let magic = cursor.read_slice(MANIFEST_PAYLOAD_MAGIC.len())?;
    if magic != MANIFEST_PAYLOAD_MAGIC {
        return Err(DbError::corruption("catalog manifest magic is invalid"));
    }
    let mut runtime = EngineRuntime::empty(cursor.read_u32()?);
    let table_count = cursor.read_u32()?;
    for _ in 0..table_count {
        let table_name = cursor.read_string()?;
        let column_count = cursor.read_u32()?;
        let mut table = TableSchema {
            name: table_name.clone(),
            temporary: false,
            columns: Vec::with_capacity(column_count as usize),
            checks: Vec::new(),
            foreign_keys: Vec::new(),
            primary_key_columns: Vec::new(),
            next_row_id: 1,
            pk_index_root: None,
        };
        for _ in 0..column_count {
            let name = cursor.read_string()?;
            let column_type = decode_column_type(cursor.read_u8()?)?;
            let nullable = cursor.read_bool()?;
            let default_sql = cursor.read_optional_string()?;
            let primary_key = cursor.read_bool()?;
            let unique = cursor.read_bool()?;
            let auto_increment = cursor.read_bool()?;
            let check_count = cursor.read_u32()?;
            let mut checks = Vec::with_capacity(check_count as usize);
            for _ in 0..check_count {
                checks.push(crate::catalog::CheckConstraint {
                    name: cursor.read_optional_string()?,
                    expression_sql: cursor.read_string()?,
                });
            }
            let has_fk = cursor.read_bool()?;
            let foreign_key = if has_fk {
                Some(decode_foreign_key(&mut cursor)?)
            } else {
                None
            };
            table.columns.push(crate::catalog::ColumnSchema {
                name,
                column_type,
                spatial_type: None,
                enum_type: None,
                nullable,
                default_sql,
                generated_sql: None,
                generated_stored: true,
                primary_key,
                unique,
                auto_increment,
                checks,
                foreign_key,
            });
        }
        let table_check_count = cursor.read_u32()?;
        for _ in 0..table_check_count {
            table.checks.push(crate::catalog::CheckConstraint {
                name: cursor.read_optional_string()?,
                expression_sql: cursor.read_string()?,
            });
        }
        let fk_count = cursor.read_u32()?;
        for _ in 0..fk_count {
            table.foreign_keys.push(decode_foreign_key(&mut cursor)?);
        }
        table.primary_key_columns = cursor.read_strings()?;
        table.next_row_id = cursor.read_i64()?;
        let state = PersistedTableState {
            checksum: cursor.read_u32()?,
            pointer: OverflowPointer {
                head_page_id: cursor.read_u32()?,
                logical_len: cursor.read_u32()?,
                flags: cursor.read_u8()?,
            },
            row_count: 0,
            tail: OverflowTailInfo::default(),
            pk_index_root: None,
        };
        runtime
            .catalog_mut()
            .tables
            .insert(table_name.clone(), table);
        let has_data = state.pointer.head_page_id != 0 && state.pointer.logical_len != 0;
        if has_data {
            // Defer row data loading to first statement execution.
            runtime.deferred_tables_mut().insert(table_name.clone());
        }
        runtime
            .persisted_tables_mut()
            .insert(table_name.clone(), state);
        if !has_data {
            // Empty tables are immediately available.
            runtime
                .tables_mut()
                .insert(table_name, TableData::default().into());
        }
    }

    let index_count = cursor.read_u32()?;
    for _ in 0..index_count {
        let name = cursor.read_string()?;
        let table_name = cursor.read_string()?;
        let kind = decode_index_kind(cursor.read_u8()?)?;
        let unique = cursor.read_bool()?;
        let column_count = cursor.read_u32()?;
        let mut columns = Vec::with_capacity(column_count as usize);
        for _ in 0..column_count {
            columns.push(crate::catalog::IndexColumn {
                column_name: cursor.read_optional_string()?,
                expression_sql: cursor.read_optional_string()?,
            });
        }
        let predicate_sql = cursor.read_optional_string()?;
        let fresh = cursor.read_bool()?;
        runtime.catalog_mut().indexes.insert(
            name.clone(),
            crate::catalog::IndexSchema {
                name,
                table_name,
                kind,
                unique,
                columns,
                include_columns: Vec::new(),
                predicate_sql,
                full_text: None,
                fresh,
            },
        );
    }
    let view_count = cursor.read_u32()?;
    for _ in 0..view_count {
        let view = crate::catalog::ViewSchema {
            name: cursor.read_string()?,
            temporary: false,
            sql_text: cursor.read_string()?,
            column_names: cursor.read_strings()?,
            dependencies: cursor.read_strings()?,
        };
        runtime.catalog_mut().views.insert(view.name.clone(), view);
    }

    let trigger_count = cursor.read_u32()?;
    for _ in 0..trigger_count {
        let trigger = crate::catalog::TriggerSchema {
            name: cursor.read_string()?,
            target_name: cursor.read_string()?,
            kind: decode_trigger_kind(cursor.read_u8()?)?,
            event: decode_trigger_event(cursor.read_u8()?)?,
            on_view: cursor.read_bool()?,
            action_sql: cursor.read_string()?,
        };
        runtime
            .catalog_mut()
            .triggers
            .insert(trigger.name.clone(), trigger);
    }
    if cursor.offset < cursor.bytes.len() {
        let table_stats_count = cursor.read_u32()?;
        for _ in 0..table_stats_count {
            let name = cursor.read_string()?;
            let stats = crate::catalog::TableStats {
                row_count: cursor.read_i64()?,
            };
            if let Some(state) = runtime.persisted_tables_mut().get_mut(&name) {
                state.row_count = usize::try_from(stats.row_count.max(0)).unwrap_or(usize::MAX);
            }
            runtime.catalog_mut().table_stats.insert(name, stats);
        }
    }
    if cursor.offset < cursor.bytes.len() {
        let index_stats_count = cursor.read_u32()?;
        for _ in 0..index_stats_count {
            let name = cursor.read_string()?;
            let stats = crate::catalog::IndexStats {
                entry_count: cursor.read_i64()?,
                distinct_key_count: cursor.read_i64()?,
            };
            runtime.catalog_mut().index_stats.insert(name, stats);
        }
    }
    if cursor.offset < cursor.bytes.len() {
        decode_schemas_section(&mut cursor, &mut runtime.catalog_mut().schemas)?;
    }
    if cursor.offset < cursor.bytes.len() {
        decode_index_include_columns_section(&mut cursor, &mut runtime.catalog_mut().indexes)?;
    }
    if cursor.offset < cursor.bytes.len() {
        decode_full_text_options_section(&mut cursor, &mut runtime.catalog_mut().indexes)?;
    }
    if cursor.offset < cursor.bytes.len() {
        decode_generated_columns_section(&mut cursor, &mut runtime.catalog_mut().tables)?;
    }
    if cursor.offset < cursor.bytes.len() {
        decode_spatial_columns_section(&mut cursor, &mut runtime.catalog_mut().tables)?;
    }
    if cursor.offset < cursor.bytes.len() {
        decode_enum_columns_section(&mut cursor, &mut runtime.catalog_mut().tables)?;
    }
    if cursor.offset < cursor.bytes.len() {
        decode_pk_index_roots_section(&mut cursor, &mut runtime.catalog_mut().tables)?;
    }
    let table_pk_roots = runtime
        .catalog
        .tables
        .iter()
        .map(|(table_name, table)| (table_name.clone(), table.pk_index_root))
        .collect::<Vec<_>>();
    for (table_name, pk_index_root) in table_pk_roots {
        if let Some(state) = runtime.persisted_tables_mut().get_mut(&table_name) {
            state.pk_index_root = pk_index_root;
        }
    }
    Ok(runtime)
}

fn encode_table_payload(data: &TableData) -> Result<Vec<u8>> {
    if data.rows.is_empty() {
        return Ok(Vec::new());
    }
    let mut output = Vec::with_capacity(TABLE_PAYLOAD_MAGIC.len() + 4 + data.rows.len() * 32);
    output.extend_from_slice(TABLE_PAYLOAD_MAGIC);
    encode_u32(&mut output, data.rows.len() as u32);
    let mut encoded_row = Vec::with_capacity(64);
    for row in &data.rows {
        encode_i64(&mut output, row.row_id);
        Row::encode_values_into(&row.values, &mut encoded_row)?;
        let row_body_len = encoded_row
            .len()
            .saturating_add(TABLE_PAYLOAD_ROW_BODY_PADDING_BYTES);
        encode_u32(
            &mut output,
            u32::try_from(row_body_len)
                .map_err(|_| DbError::constraint("table row body length exceeds u32"))?,
        );
        output.extend_from_slice(&encoded_row);
        output.extend(std::iter::repeat_n(
            0u8,
            row_body_len.saturating_sub(encoded_row.len()),
        ));
    }
    Ok(output)
}

fn encoded_table_row_len(row: &StoredRow, scratch: &mut Vec<u8>) -> Result<usize> {
    scratch.clear();
    Row::encode_values_into(&row.values, scratch)?;
    Ok(8usize
        .saturating_add(4)
        .saturating_add(scratch.len())
        .saturating_add(TABLE_PAYLOAD_ROW_BODY_PADDING_BYTES))
}

fn resident_table_should_use_paged_storage(
    data: &TableData,
    previous_state: PersistedTableState,
    delta: &PagedMutationDelta,
    page_size: u32,
) -> Result<bool> {
    if data.rows.is_empty() {
        return Ok(false);
    }

    let target_chunk_bytes = paged_table_target_chunk_bytes(page_size);
    if previous_state.pointer.head_page_id != 0
        && previous_state.pointer.logical_len as usize > target_chunk_bytes
    {
        return Ok(true);
    }

    let append_only =
        delta.append_count > 0 && delta.updated_rows.is_empty() && delta.deleted_rows.is_empty();
    let mut encoded_len = if append_only && previous_state.pointer.head_page_id != 0 {
        previous_state.pointer.logical_len as usize
    } else {
        TABLE_PAYLOAD_MAGIC.len() + 4
    };
    let start = if append_only && previous_state.pointer.head_page_id != 0 {
        data.rows.len().saturating_sub(delta.append_count)
    } else {
        0
    };
    let mut scratch = Vec::with_capacity(64);
    for row in &data.rows[start..] {
        encoded_len = encoded_len.saturating_add(encoded_table_row_len(row, &mut scratch)?);
        if encoded_len > target_chunk_bytes {
            return Ok(true);
        }
    }
    Ok(false)
}

fn paged_table_target_chunk_bytes(page_size: u32) -> usize {
    (page_size as usize)
        .saturating_mul(PAGED_TABLE_TARGET_CHUNK_PAGES)
        .max(TABLE_PAYLOAD_MAGIC.len() + 4)
}

fn paged_table_checkpoint_compaction_min_bytes(page_size: u32) -> usize {
    paged_table_target_chunk_bytes(page_size).saturating_div(2)
}

fn finalize_encoded_paged_table_chunk(
    mut payload: Vec<u8>,
    row_count: usize,
) -> Result<EncodedPagedTableChunk> {
    if payload.len() < TABLE_PAYLOAD_MAGIC.len() + 4 {
        return Err(DbError::internal(
            "paged table chunk payload shorter than header",
        ));
    }
    payload[TABLE_PAYLOAD_MAGIC.len()..TABLE_PAYLOAD_MAGIC.len() + 4].copy_from_slice(
        &u32::try_from(row_count)
            .map_err(|_| DbError::constraint("paged table chunk row count exceeds u32"))?
            .to_le_bytes(),
    );
    let checksum = crc32c_parts(&[payload.as_slice()]);
    Ok(EncodedPagedTableChunk {
        payload,
        checksum,
        row_count,
    })
}

fn encode_paged_table_chunks_from_rows(
    rows: &[StoredRow],
    page_size: u32,
) -> Result<Vec<EncodedPagedTableChunk>> {
    if rows.is_empty() {
        return Ok(Vec::new());
    }

    let target_chunk_bytes = paged_table_target_chunk_bytes(page_size);
    let mut chunks = Vec::new();
    let mut chunk = Vec::with_capacity(target_chunk_bytes);
    chunk.extend_from_slice(TABLE_PAYLOAD_MAGIC);
    chunk.extend_from_slice(&0_u32.to_le_bytes());
    let mut chunk_row_count = 0usize;
    let mut encoded_row = Vec::with_capacity(64);

    for row in rows {
        encoded_row.clear();
        Row::encode_values_into(&row.values, &mut encoded_row)?;
        let encoded_row_len = 8usize.saturating_add(4).saturating_add(encoded_row.len());
        if chunk_row_count > 0 && chunk.len().saturating_add(encoded_row_len) > target_chunk_bytes {
            chunks.push(finalize_encoded_paged_table_chunk(chunk, chunk_row_count)?);
            chunk = Vec::with_capacity(target_chunk_bytes);
            chunk.extend_from_slice(TABLE_PAYLOAD_MAGIC);
            chunk.extend_from_slice(&0_u32.to_le_bytes());
            chunk_row_count = 0;
        }
        encode_i64(&mut chunk, row.row_id);
        encode_bytes(&mut chunk, &encoded_row)?;
        chunk_row_count += 1;
    }

    if chunk_row_count > 0 {
        chunks.push(finalize_encoded_paged_table_chunk(chunk, chunk_row_count)?);
    }
    Ok(chunks)
}

fn encode_paged_table_chunks(
    data: &TableData,
    page_size: u32,
) -> Result<Vec<EncodedPagedTableChunk>> {
    encode_paged_table_chunks_from_rows(&data.rows, page_size)
}

fn encode_paged_table_manifest_payload(manifest: &PersistedPagedTableManifest) -> Result<Vec<u8>> {
    let mut output = Vec::with_capacity(
        TABLE_PAGED_MANIFEST_MAGIC.len() + 4 + manifest.chunks.len().saturating_mul(30),
    );
    output.extend_from_slice(TABLE_PAGED_MANIFEST_MAGIC);
    encode_u32(
        &mut output,
        u32::try_from(manifest.chunks.len())
            .map_err(|_| DbError::constraint("paged table chunk count exceeds u32"))?,
    );
    for chunk in &manifest.chunks {
        encode_u32(&mut output, chunk.checksum);
        encode_u32(&mut output, chunk.pointer.head_page_id);
        encode_u32(&mut output, chunk.pointer.logical_len);
        output.push(chunk.pointer.flags);
        encode_u32(
            &mut output,
            u32::try_from(chunk.row_count)
                .map_err(|_| DbError::constraint("paged table chunk row count exceeds u32"))?,
        );
        encode_u32(
            &mut output,
            u32::try_from(chunk.tombstoned_row_ids.len()).map_err(|_| {
                DbError::constraint("paged table chunk tombstone count exceeds u32")
            })?,
        );
        for row_id in &chunk.tombstoned_row_ids {
            encode_i64(&mut output, *row_id);
        }
        output.push(if chunk.overlay_pointer.is_some() {
            1
        } else {
            0
        });
        if let Some(overlay_pointer) = chunk.overlay_pointer {
            encode_u32(&mut output, overlay_pointer.head_page_id);
            encode_u32(&mut output, overlay_pointer.logical_len);
            output.push(overlay_pointer.flags);
            encode_u32(
                &mut output,
                chunk.overlay_checksum.ok_or_else(|| {
                    DbError::internal("paged table chunk overlay checksum missing")
                })?,
            );
        }
    }
    Ok(output)
}

pub(crate) fn decode_paged_table_manifest_payload(
    bytes: &[u8],
) -> Result<PersistedPagedTableManifest> {
    let mut cursor = Cursor::new(bytes);
    let magic = cursor.read_slice(TABLE_PAGED_MANIFEST_MAGIC.len())?;
    if magic != TABLE_PAGED_MANIFEST_MAGIC {
        return Err(DbError::corruption("paged table manifest magic is invalid"));
    }
    let chunk_count = cursor.read_u32()? as usize;
    let mut chunks = Vec::with_capacity(chunk_count);
    for _ in 0..chunk_count {
        let checksum = cursor.read_u32()?;
        let pointer = OverflowPointer {
            head_page_id: cursor.read_u32()?,
            logical_len: cursor.read_u32()?,
            flags: cursor.read_u8()?,
        };
        let row_count = cursor.read_u32()? as usize;
        let tombstoned_row_ids_len = cursor.read_u32()? as usize;
        let mut tombstoned_row_ids = Vec::with_capacity(tombstoned_row_ids_len);
        for _ in 0..tombstoned_row_ids_len {
            tombstoned_row_ids.push(cursor.read_i64()?);
        }
        let has_overlay = cursor.read_bool()?;
        let mut overlay_pointer = None;
        let mut overlay_checksum = None;
        if has_overlay {
            overlay_pointer = Some(OverflowPointer {
                head_page_id: cursor.read_u32()?,
                logical_len: cursor.read_u32()?,
                flags: cursor.read_u8()?,
            });
            overlay_checksum = Some(cursor.read_u32()?);
        }
        chunks.push(PersistedTableChunkState {
            checksum,
            pointer,
            row_count,
            tombstoned_row_ids,
            overlay_pointer,
            overlay_checksum,
        });
    }
    if cursor.offset != cursor.bytes.len() {
        return Err(DbError::corruption(
            "paged table manifest payload had trailing bytes",
        ));
    }
    Ok(PersistedPagedTableManifest { chunks })
}

fn read_paged_table_chunk_payloads<S: PageStore>(
    store: &S,
    state: PersistedTableState,
) -> Result<Vec<TablePageManifestChunk>> {
    if state.pointer.head_page_id == 0 || state.pointer.logical_len == 0 {
        return Ok(Vec::new());
    }
    let manifest_payload = read_overflow(store, state.pointer)?;
    if crc32c_parts(&[manifest_payload.as_slice()]) != state.checksum {
        return Err(DbError::corruption(
            "paged table manifest checksum mismatch",
        ));
    }
    let manifest = decode_paged_table_manifest_payload(&manifest_payload)?;
    let mut chunks = Vec::with_capacity(manifest.chunks.len());
    let mut total_row_count = 0usize;
    for chunk in manifest.chunks {
        let payload = Arc::new(read_overflow(store, chunk.pointer)?);
        if crc32c_parts(&[payload.as_slice()]) != chunk.checksum {
            return Err(DbError::corruption("paged table chunk checksum mismatch"));
        }
        let tombstoned_row_ids = Arc::new(
            chunk
                .tombstoned_row_ids
                .iter()
                .copied()
                .collect::<BTreeSet<_>>(),
        );
        let mut overlay_payload = None;
        if let Some(overlay_pointer) = chunk.overlay_pointer {
            let p = Arc::new(read_overflow(store, overlay_pointer)?);
            if Some(crc32c_parts(&[p.as_slice()])) != chunk.overlay_checksum {
                return Err(DbError::corruption(
                    "paged table overlay chunk checksum mismatch",
                ));
            }
            overlay_payload = Some(p);
        }
        total_row_count = total_row_count.saturating_add(chunk.row_count);
        chunks.push(TablePageManifestChunk {
            pointer: chunk.pointer,
            checksum: chunk.checksum,
            row_count: chunk.row_count,
            payload,
            tombstoned_row_ids,
            overlay_pointer: chunk.overlay_pointer,
            overlay_checksum: chunk.overlay_checksum,
            overlay_payload,
        });
    }
    if state.row_count != 0 && total_row_count != state.row_count {
        return Err(DbError::corruption(
            "paged table manifest row count mismatch",
        ));
    }
    Ok(chunks)
}

fn visit_table_payload_rows_from_bytes<F>(bytes: &[u8], visitor: &mut F) -> Result<usize>
where
    F: FnMut(i64, &[Value]) -> Result<()>,
{
    if bytes.is_empty() {
        return Ok(0);
    }
    let mut cursor = Cursor::new(bytes);
    let magic = cursor.read_slice(TABLE_PAYLOAD_MAGIC.len())?;
    if magic != TABLE_PAYLOAD_MAGIC {
        return Err(DbError::corruption("table payload magic is invalid"));
    }
    let row_count = cursor.read_u32()? as usize;
    for _ in 0..row_count {
        let row_id = cursor.read_i64()?;
        let row_bytes_len = cursor.read_u32()? as usize;
        let row_bytes = cursor.read_slice(row_bytes_len)?;
        let row = Row::decode(row_bytes)?;
        visitor(row_id, row.values())?;
    }
    Ok(row_count)
}

fn visit_table_payload_projected_values_from_bytes<F>(
    bytes: &[u8],
    projection_indexes: &[usize],
    tombstoned_row_ids: Option<&[i64]>,
    visitor: &mut F,
) -> Result<usize>
where
    F: FnMut(i64, &[Value]) -> Result<()>,
{
    if bytes.is_empty() {
        return Ok(0);
    }
    let mut cursor = Cursor::new(bytes);
    let magic = cursor.read_slice(TABLE_PAYLOAD_MAGIC.len())?;
    if magic != TABLE_PAYLOAD_MAGIC {
        return Err(DbError::corruption("table payload magic is invalid"));
    }
    let row_count = cursor.read_u32()? as usize;
    let mut visible_count = 0usize;
    for _ in 0..row_count {
        let row_id = cursor.read_i64()?;
        let row_bytes_len = cursor.read_u32()? as usize;
        let row_bytes = cursor.read_slice(row_bytes_len)?;
        if tombstoned_row_ids.is_some_and(|row_ids| row_ids.contains(&row_id)) {
            continue;
        }
        let values = Row::decode_projection_with_overflow::<crate::storage::page::InMemoryPageStore>(
            row_bytes,
            None,
            projection_indexes,
        )?;
        visitor(row_id, &values)?;
        visible_count += 1;
    }
    Ok(visible_count)
}

fn visit_table_payload_rows_from_pointer<S: PageStore, F>(
    store: &S,
    pointer: OverflowPointer,
    visitor: &mut F,
) -> Result<usize>
where
    F: FnMut(i64, &[Value]) -> Result<()>,
{
    if pointer.head_page_id == 0 || pointer.logical_len == 0 {
        return Ok(0);
    }
    if pointer.is_compressed() {
        let payload = read_overflow(store, pointer)?;
        return visit_table_payload_rows_from_bytes(&payload, visitor);
    }

    let mut cursor = OverflowPayloadCursor::new(store, pointer);
    let mut magic = [0_u8; TABLE_PAYLOAD_MAGIC.len()];
    cursor.read_exact(&mut magic)?;
    if magic != *TABLE_PAYLOAD_MAGIC {
        return Err(DbError::corruption("table payload magic is invalid"));
    }
    let row_count = cursor.read_u32()? as usize;
    for _ in 0..row_count {
        let row_id = cursor.read_i64()?;
        let row_bytes_len = cursor.read_u32()? as usize;
        let row_bytes = cursor.read_vec(row_bytes_len)?;
        let row = Row::decode(&row_bytes)?;
        visitor(row_id, row.values())?;
    }
    Ok(row_count)
}

fn visit_table_payload_projected_values_from_pointer<S: PageStore, F>(
    store: &S,
    pointer: OverflowPointer,
    projection_indexes: &[usize],
    visitor: &mut F,
) -> Result<usize>
where
    F: FnMut(i64, &[Value]) -> Result<()>,
{
    if pointer.head_page_id == 0 || pointer.logical_len == 0 {
        return Ok(0);
    }
    if pointer.is_compressed() {
        let payload = read_overflow(store, pointer)?;
        return visit_table_payload_projected_values_from_bytes(
            &payload,
            projection_indexes,
            None,
            visitor,
        );
    }

    let mut cursor = OverflowPayloadCursor::new(store, pointer);
    let mut magic = [0_u8; TABLE_PAYLOAD_MAGIC.len()];
    cursor.read_exact(&mut magic)?;
    if magic != *TABLE_PAYLOAD_MAGIC {
        return Err(DbError::corruption("table payload magic is invalid"));
    }
    let row_count = cursor.read_u32()? as usize;
    for _ in 0..row_count {
        let row_id = cursor.read_i64()?;
        let row_bytes_len = cursor.read_u32()? as usize;
        let row_bytes = cursor.read_vec(row_bytes_len)?;
        let values = Row::decode_projection_with_overflow::<crate::storage::page::InMemoryPageStore>(
            &row_bytes,
            None,
            projection_indexes,
        )?;
        visitor(row_id, &values)?;
    }
    Ok(row_count)
}

fn visit_table_payload_int64_column_from_bytes<F>(
    bytes: &[u8],
    column_index: usize,
    tombstoned_row_ids: Option<&[i64]>,
    visitor: &mut F,
) -> Result<usize>
where
    F: FnMut(i64, Option<i64>) -> Result<()>,
{
    if bytes.is_empty() {
        return Ok(0);
    }
    let mut cursor = Cursor::new(bytes);
    let magic = cursor.read_slice(TABLE_PAYLOAD_MAGIC.len())?;
    if magic != TABLE_PAYLOAD_MAGIC {
        return Err(DbError::corruption("table payload magic is invalid"));
    }
    let row_count = cursor.read_u32()? as usize;
    let mut visible_count = 0usize;
    for _ in 0..row_count {
        let row_id = cursor.read_i64()?;
        let row_bytes_len = cursor.read_u32()? as usize;
        let row_bytes = cursor.read_slice(row_bytes_len)?;
        if tombstoned_row_ids.is_some_and(|row_ids| row_ids.binary_search(&row_id).is_ok()) {
            continue;
        }
        visitor(row_id, Row::decode_int64_at(row_bytes, column_index)?)?;
        visible_count += 1;
    }
    Ok(visible_count)
}

fn visit_table_payload_int64_column_from_pointer<S: PageStore, F>(
    store: &S,
    pointer: OverflowPointer,
    column_index: usize,
    visitor: &mut F,
) -> Result<usize>
where
    F: FnMut(i64, Option<i64>) -> Result<()>,
{
    if pointer.head_page_id == 0 || pointer.logical_len == 0 {
        return Ok(0);
    }
    if pointer.is_compressed() {
        let payload = read_overflow(store, pointer)?;
        return visit_table_payload_int64_column_from_bytes(&payload, column_index, None, visitor);
    }

    let mut cursor = OverflowPayloadCursor::new(store, pointer);
    let mut magic = [0_u8; TABLE_PAYLOAD_MAGIC.len()];
    cursor.read_exact(&mut magic)?;
    if magic != *TABLE_PAYLOAD_MAGIC {
        return Err(DbError::corruption("table payload magic is invalid"));
    }
    let row_count = cursor.read_u32()? as usize;
    for _ in 0..row_count {
        let row_id = cursor.read_i64()?;
        let row_bytes_len = cursor.read_u32()? as usize;
        let row_bytes = cursor.read_vec(row_bytes_len)?;
        visitor(row_id, Row::decode_int64_at(&row_bytes, column_index)?)?;
    }
    Ok(row_count)
}

fn visit_persisted_table_int64_column<S: PageStore, F>(
    store: &S,
    state: PersistedTableState,
    column_index: usize,
    mut visitor: F,
) -> Result<usize>
where
    F: FnMut(i64, Option<i64>) -> Result<()>,
{
    if state.pointer.head_page_id == 0 || state.pointer.logical_len == 0 {
        return Ok(0);
    }
    if !state.pointer.is_table_paged_manifest() {
        let row_count = visit_table_payload_int64_column_from_pointer(
            store,
            state.pointer,
            column_index,
            &mut visitor,
        )?;
        if state.row_count != 0 && row_count != state.row_count {
            return Err(DbError::corruption("table payload row count mismatch"));
        }
        return Ok(row_count);
    }

    let manifest_payload = read_overflow(store, state.pointer)?;
    if crc32c_parts(&[manifest_payload.as_slice()]) != state.checksum {
        return Err(DbError::corruption(
            "paged table manifest checksum mismatch",
        ));
    }
    let manifest = decode_paged_table_manifest_payload(&manifest_payload)?;
    let mut total_row_count = 0usize;
    for chunk in manifest.chunks {
        let mut count = 0usize;
        let tombstones = if chunk.tombstoned_row_ids.is_empty() {
            None
        } else {
            Some(chunk.tombstoned_row_ids.as_slice())
        };

        let base_payload = read_overflow(store, chunk.pointer)?;
        count += visit_table_payload_int64_column_from_bytes(
            &base_payload,
            column_index,
            tombstones,
            &mut visitor,
        )?;

        if let Some(overlay_pointer) = chunk.overlay_pointer {
            let overlay_payload = read_overflow(store, overlay_pointer)?;
            count += visit_table_payload_int64_column_from_bytes(
                &overlay_payload,
                column_index,
                None,
                &mut visitor,
            )?;
        }

        if count != chunk.row_count {
            return Err(DbError::corruption("paged table chunk row count mismatch"));
        }
        total_row_count = total_row_count.saturating_add(count);
    }
    if state.row_count != 0 && total_row_count != state.row_count {
        return Err(DbError::corruption(
            "paged table manifest row count mismatch",
        ));
    }
    Ok(total_row_count)
}

fn visit_persisted_table_projected_values<S: PageStore, F>(
    store: &S,
    state: PersistedTableState,
    projection_indexes: &[usize],
    mut visitor: F,
) -> Result<usize>
where
    F: FnMut(i64, &[Value]) -> Result<()>,
{
    if state.pointer.head_page_id == 0 || state.pointer.logical_len == 0 {
        return Ok(0);
    }
    if !state.pointer.is_table_paged_manifest() {
        let row_count = visit_table_payload_projected_values_from_pointer(
            store,
            state.pointer,
            projection_indexes,
            &mut visitor,
        )?;
        if state.row_count != 0 && row_count != state.row_count {
            return Err(DbError::corruption("table payload row count mismatch"));
        }
        return Ok(row_count);
    }

    let manifest_payload = read_overflow(store, state.pointer)?;
    if crc32c_parts(&[manifest_payload.as_slice()]) != state.checksum {
        return Err(DbError::corruption(
            "paged table manifest checksum mismatch",
        ));
    }
    let manifest = decode_paged_table_manifest_payload(&manifest_payload)?;
    let mut total_row_count = 0usize;
    for chunk in manifest.chunks {
        let mut count = 0usize;
        let tombstones = if chunk.tombstoned_row_ids.is_empty() {
            None
        } else {
            Some(chunk.tombstoned_row_ids.as_slice())
        };

        let base_payload = read_overflow(store, chunk.pointer)?;
        count += visit_table_payload_projected_values_from_bytes(
            &base_payload,
            projection_indexes,
            tombstones,
            &mut visitor,
        )?;

        if let Some(overlay_pointer) = chunk.overlay_pointer {
            let overlay_payload = read_overflow(store, overlay_pointer)?;
            count += visit_table_payload_projected_values_from_bytes(
                &overlay_payload,
                projection_indexes,
                None,
                &mut visitor,
            )?;
        }

        if count != chunk.row_count {
            return Err(DbError::corruption("paged table chunk row count mismatch"));
        }
        total_row_count = total_row_count.saturating_add(count);
    }
    if state.row_count != 0 && total_row_count != state.row_count {
        return Err(DbError::corruption(
            "paged table manifest row count mismatch",
        ));
    }
    Ok(total_row_count)
}

fn visit_persisted_table_rows<S: PageStore, F>(
    store: &S,
    state: PersistedTableState,
    mut visitor: F,
) -> Result<usize>
where
    F: FnMut(i64, &[Value]) -> Result<()>,
{
    if state.pointer.head_page_id == 0 || state.pointer.logical_len == 0 {
        return Ok(0);
    }
    if !state.pointer.is_table_paged_manifest() {
        let row_count = visit_table_payload_rows_from_pointer(store, state.pointer, &mut visitor)?;
        if state.row_count != 0 && row_count != state.row_count {
            return Err(DbError::corruption("table payload row count mismatch"));
        }
        return Ok(row_count);
    }

    let manifest_payload = read_overflow(store, state.pointer)?;
    if crc32c_parts(&[manifest_payload.as_slice()]) != state.checksum {
        return Err(DbError::corruption(
            "paged table manifest checksum mismatch",
        ));
    }
    let manifest = decode_paged_table_manifest_payload(&manifest_payload)?;
    let mut total_row_count = 0usize;
    for chunk in manifest.chunks {
        let mut count = 0usize;

        let base_payload = read_overflow(store, chunk.pointer)?;
        for row in decode_table_payload_rows(&base_payload)? {
            if !chunk.tombstoned_row_ids.contains(&row.row_id) {
                visitor(row.row_id, &row.values)?;
                count += 1;
            }
        }

        if let Some(overlay_pointer) = chunk.overlay_pointer {
            let overlay_payload = read_overflow(store, overlay_pointer)?;
            for row in decode_table_payload_rows(&overlay_payload)? {
                visitor(row.row_id, &row.values)?;
                count += 1;
            }
        }

        if count != chunk.row_count {
            return Err(DbError::corruption("paged table chunk row count mismatch"));
        }
        total_row_count = total_row_count.saturating_add(count);
    }
    if state.row_count != 0 && total_row_count != state.row_count {
        return Err(DbError::corruption(
            "paged table manifest row count mismatch",
        ));
    }
    Ok(total_row_count)
}

fn visit_persisted_table_rows_until<S: PageStore, F>(
    store: &S,
    state: PersistedTableState,
    mut visitor: F,
) -> Result<usize>
where
    F: FnMut(i64, &[Value]) -> Result<bool>,
{
    if state.pointer.head_page_id == 0 || state.pointer.logical_len == 0 {
        return Ok(0);
    }
    if !state.pointer.is_table_paged_manifest() {
        let mut stopped = false;
        let row_count =
            visit_table_payload_rows_from_pointer(store, state.pointer, &mut |row_id, values| {
                if stopped {
                    return Ok(());
                }
                stopped = visitor(row_id, values)?;
                Ok(())
            })?;
        if !stopped && state.row_count != 0 && row_count != state.row_count {
            return Err(DbError::corruption("table payload row count mismatch"));
        }
        return Ok(row_count);
    }

    let manifest_payload = read_overflow(store, state.pointer)?;
    if crc32c_parts(&[manifest_payload.as_slice()]) != state.checksum {
        return Err(DbError::corruption(
            "paged table manifest checksum mismatch",
        ));
    }
    let manifest = decode_paged_table_manifest_payload(&manifest_payload)?;
    let mut visited_row_count = 0usize;
    let mut total_row_count = 0usize;
    for chunk in manifest.chunks {
        let mut count = 0usize;

        let base_payload = read_overflow(store, chunk.pointer)?;
        for row in decode_table_payload_rows(&base_payload)? {
            if chunk.tombstoned_row_ids.contains(&row.row_id) {
                continue;
            }
            visited_row_count = visited_row_count.saturating_add(1);
            count += 1;
            if visitor(row.row_id, &row.values)? {
                return Ok(visited_row_count);
            }
        }

        if let Some(overlay_pointer) = chunk.overlay_pointer {
            let overlay_payload = read_overflow(store, overlay_pointer)?;
            for row in decode_table_payload_rows(&overlay_payload)? {
                visited_row_count = visited_row_count.saturating_add(1);
                count += 1;
                if visitor(row.row_id, &row.values)? {
                    return Ok(visited_row_count);
                }
            }
        }

        if count != chunk.row_count {
            return Err(DbError::corruption("paged table chunk row count mismatch"));
        }
        total_row_count = total_row_count.saturating_add(count);
    }
    if state.row_count != 0 && total_row_count != state.row_count {
        return Err(DbError::corruption(
            "paged table manifest row count mismatch",
        ));
    }
    Ok(visited_row_count)
}

fn decode_table_payload_rows(bytes: &[u8]) -> Result<Vec<StoredRow>> {
    let mut rows = Vec::new();
    visit_table_payload_rows_from_bytes(bytes, &mut |row_id, values| {
        rows.push(StoredRow {
            row_id,
            values: values.to_vec(),
        });
        Ok(())
    })?;
    Ok(rows)
}

fn encode_legacy_table_payload_from_manifest(manifest: &TablePageManifest) -> Result<Vec<u8>> {
    if manifest.row_count() == 0 {
        return Ok(Vec::new());
    }
    let mut rows = Vec::with_capacity(manifest.row_count());
    for row in manifest.rows() {
        let row = row?;
        rows.push(StoredRow {
            row_id: row.row_id(),
            values: row.values().to_vec(),
        });
    }
    encode_table_payload(&TableData::from_rows(rows))
}

pub(crate) fn read_table_payload_row_count_from_bytes(bytes: &[u8]) -> Result<usize> {
    let mut cursor = Cursor::new(bytes);
    let magic = cursor.read_slice(TABLE_PAYLOAD_MAGIC.len())?;
    if magic != TABLE_PAYLOAD_MAGIC {
        return Err(DbError::corruption("table payload magic is invalid"));
    }
    Ok(cursor.read_u32()? as usize)
}

fn apply_paged_row_changes_to_manifest(
    manifest: &TablePageManifest,
    row_changes: &BTreeMap<i64, Option<Vec<Value>>>,
) -> Result<TablePageManifest> {
    if row_changes.is_empty() {
        return Ok(manifest.clone());
    }

    let mut new_chunks = Vec::with_capacity(manifest.chunks.len());
    for chunk in manifest.chunks.iter() {
        let mut new_tombstones: BTreeSet<i64> = chunk.tombstoned_row_ids.iter().copied().collect();
        // Use BTreeMap so each row_id appears at most once in the overlay.
        let mut overlay_rows: BTreeMap<i64, StoredRow> = BTreeMap::new();
        let mut chunk_changed = false;

        // Scan the base payload: tombstone touched rows and queue their
        // replacements in the overlay map.
        let previous_rows = decode_table_payload_rows(chunk.payload.as_slice())?;
        for previous_row in previous_rows {
            match row_changes.get(&previous_row.row_id) {
                Some(Some(next_values)) => {
                    chunk_changed = true;
                    new_tombstones.insert(previous_row.row_id);
                    overlay_rows.insert(
                        previous_row.row_id,
                        StoredRow {
                            row_id: previous_row.row_id,
                            values: next_values.clone(),
                        },
                    );
                }
                Some(None) => {
                    chunk_changed = true;
                    new_tombstones.insert(previous_row.row_id);
                }
                None => {}
            }
        }

        // Scan any existing overlay: replace rows that are re-updated,
        // keep untouched rows, drop rows that are deleted.
        if let Some(overlay_payload) = &chunk.overlay_payload {
            let previous_overlay_rows = decode_table_payload_rows(overlay_payload.as_slice())?;
            for previous_row in previous_overlay_rows {
                match row_changes.get(&previous_row.row_id) {
                    Some(Some(next_values)) => {
                        chunk_changed = true;
                        overlay_rows.insert(
                            previous_row.row_id,
                            StoredRow {
                                row_id: previous_row.row_id,
                                values: next_values.clone(),
                            },
                        );
                    }
                    Some(None) => {
                        chunk_changed = true;
                        overlay_rows.remove(&previous_row.row_id);
                    }
                    None => {
                        overlay_rows
                            .entry(previous_row.row_id)
                            .or_insert(previous_row);
                    }
                }
            }
        }

        if !chunk_changed {
            new_chunks.push(chunk.clone());
            continue;
        }

        let overlay_payload = if overlay_rows.is_empty() {
            None
        } else {
            let rows: Vec<StoredRow> = overlay_rows.into_values().collect();
            Some(Arc::new(encode_table_payload(&TableData::from_rows(rows))?))
        };

        new_chunks.push(TablePageManifestChunk {
            pointer: chunk.pointer,
            checksum: chunk.checksum,
            row_count: chunk.row_count,
            payload: Arc::clone(&chunk.payload),
            tombstoned_row_ids: Arc::new(new_tombstones),
            overlay_pointer: None,
            overlay_checksum: None,
            overlay_payload,
        });
    }

    TablePageManifest::from_chunks(new_chunks)
}

fn read_table_page_manifest_from_state<S: PageStore>(
    store: &S,
    state: PersistedTableState,
) -> Result<TablePageManifest> {
    if state.pointer.head_page_id == 0 || state.pointer.logical_len == 0 {
        return TablePageManifest::from_chunks(Vec::new());
    }
    if state.pointer.is_table_paged_manifest() {
        return TablePageManifest::from_chunks(read_paged_table_chunk_payloads(store, state)?);
    }
    let payload = Arc::new(read_overflow(store, state.pointer)?);
    if crc32c_parts(&[payload.as_slice()]) != state.checksum {
        return Err(DbError::corruption("table payload checksum mismatch"));
    }
    TablePageManifest::from_payload(payload)
}

fn decode_persisted_table_data<S: PageStore>(
    store: &S,
    state: PersistedTableState,
) -> Result<TableData> {
    let manifest = read_table_page_manifest_from_state(store, state)?;
    let mut rows = Vec::with_capacity(manifest.row_count());
    for row in manifest.rows() {
        let row = row?;
        rows.push(StoredRow {
            row_id: row.row_id(),
            values: row.values().to_vec(),
        });
    }
    Ok(TableData::from_rows(rows))
}

fn free_persisted_table_bytes<S: PageStore>(
    store: &mut S,
    state: PersistedTableState,
) -> Result<()> {
    if state.pointer.head_page_id == 0 {
        return Ok(());
    }
    if state.pointer.is_table_paged_manifest() {
        let manifest_payload = read_overflow(store, state.pointer)?;
        let manifest = decode_paged_table_manifest_payload(&manifest_payload)?;
        for chunk in manifest.chunks {
            if chunk.pointer.head_page_id != 0 {
                free_overflow(store, chunk.pointer.head_page_id)?;
            }
        }
        free_overflow(store, state.pointer.head_page_id)?;
        return Ok(());
    }
    free_overflow(store, state.pointer.head_page_id)?;
    Ok(())
}

fn wrap_legacy_table_state_as_paged_manifest<S: PageStore>(
    store: &mut S,
    state: PersistedTableState,
) -> Result<PersistedTableState> {
    if state.pointer.head_page_id == 0 || state.pointer.logical_len == 0 {
        return Ok(state);
    }
    let row_count = if state.row_count == 0 {
        read_table_payload_row_count(store, state.pointer)?
    } else {
        state.row_count
    };
    let manifest = PersistedPagedTableManifest {
        chunks: vec![PersistedTableChunkState {
            pointer: state.pointer.with_table_paged_manifest(false),
            checksum: state.checksum,
            row_count,
            tombstoned_row_ids: Vec::new(),
            overlay_pointer: None,
            overlay_checksum: None,
        }],
    };
    let manifest_payload = encode_paged_table_manifest_payload(&manifest)?;
    let checksum = crc32c_parts(&[manifest_payload.as_slice()]);
    let pointer = write_overflow(store, &manifest_payload, CompressionMode::Never)?
        .with_table_paged_manifest(true);
    let tail = read_uncompressed_overflow_tail(store, pointer)?.unwrap_or_default();
    Ok(PersistedTableState {
        pointer,
        checksum,
        row_count,
        tail,
        pk_index_root: state.pk_index_root,
    })
}

fn append_paged_table_chunks<S: PageStore>(
    store: &mut S,
    mut previous_state: PersistedTableState,
    appended_chunks: &[EncodedPagedTableChunk],
    row_count: usize,
) -> Result<PersistedTableState> {
    if previous_state.pointer.head_page_id == 0 {
        return persist_paged_table(store, previous_state, appended_chunks, row_count);
    }
    if !previous_state.pointer.is_table_paged_manifest() {
        previous_state = wrap_legacy_table_state_as_paged_manifest(store, previous_state)?;
    }
    if appended_chunks.is_empty() {
        return Ok(previous_state);
    }

    let manifest_payload = read_overflow(store, previous_state.pointer)?;
    if crc32c_parts(&[manifest_payload.as_slice()]) != previous_state.checksum {
        return Err(DbError::corruption(
            "paged table manifest checksum mismatch",
        ));
    }
    let mut manifest = decode_paged_table_manifest_payload(&manifest_payload)?;
    manifest.chunks.reserve(appended_chunks.len());
    for chunk in appended_chunks {
        let pointer = write_overflow(store, &chunk.payload, CompressionMode::Never)?;
        manifest.chunks.push(PersistedTableChunkState {
            pointer,
            checksum: chunk.checksum,
            row_count: chunk.row_count,
            tombstoned_row_ids: Vec::new(),
            overlay_pointer: None,
            overlay_checksum: None,
        });
    }

    let updated_manifest_payload = encode_paged_table_manifest_payload(&manifest)?;
    let checksum = crc32c_parts(&[updated_manifest_payload.as_slice()]);
    let pointer = rewrite_overflow(
        store,
        previous_state.pointer.with_table_paged_manifest(false),
        &updated_manifest_payload,
        CompressionMode::Never,
    )?
    .with_table_paged_manifest(true);
    let tail = read_uncompressed_overflow_tail(store, pointer)?.unwrap_or_default();
    Ok(PersistedTableState {
        pointer,
        checksum,
        row_count,
        tail,
        pk_index_root: previous_state.pk_index_root,
    })
}

fn persisted_paged_chunk_is_plain(chunk: &PersistedTableChunkState) -> bool {
    chunk.tombstoned_row_ids.is_empty()
        && chunk.overlay_pointer.is_none()
        && chunk.overlay_checksum.is_none()
}

fn table_page_manifest_chunk_is_plain(chunk: &TablePageManifestChunk) -> bool {
    chunk.tombstoned_row_ids.is_empty()
        && chunk.overlay_pointer.is_none()
        && chunk.overlay_checksum.is_none()
        && chunk.overlay_payload.is_none()
}

fn persisted_chunk_from_current(
    pointer: OverflowPointer,
    checksum: u32,
    row_count: usize,
    current_chunk: &TablePageManifestChunk,
) -> TablePageManifestChunk {
    TablePageManifestChunk {
        pointer,
        checksum,
        row_count,
        payload: Arc::clone(&current_chunk.payload),
        tombstoned_row_ids: Arc::clone(&current_chunk.tombstoned_row_ids),
        overlay_pointer: None,
        overlay_checksum: None,
        overlay_payload: None,
    }
}

fn try_append_only_paged_table_from_manifest<S: PageStore>(
    store: &mut S,
    previous_state: PersistedTableState,
    manifest: &TablePageManifest,
) -> Result<Option<(PersistedTableState, Vec<TablePageManifestChunk>)>> {
    if previous_state.pointer.head_page_id == 0 || !previous_state.pointer.is_table_paged_manifest()
    {
        return Ok(None);
    }
    if manifest.chunks.is_empty() {
        return Ok(None);
    }

    let manifest_payload = read_overflow(store, previous_state.pointer)?;
    if crc32c_parts(&[manifest_payload.as_slice()]) != previous_state.checksum {
        return Err(DbError::corruption(
            "paged table manifest checksum mismatch",
        ));
    }
    let previous_manifest = decode_paged_table_manifest_payload(&manifest_payload)?;
    if previous_manifest.chunks.is_empty() || manifest.chunks.len() < previous_manifest.chunks.len()
    {
        return Ok(None);
    }

    let previous_tail_index = previous_manifest.chunks.len() - 1;
    let mut first_changed_index = None;
    let mut current_checksums = Vec::with_capacity(manifest.chunks.len());
    for (index, current_chunk) in manifest.chunks.iter().enumerate() {
        if !table_page_manifest_chunk_is_plain(current_chunk) {
            return Ok(None);
        }
        let checksum = crc32c_parts(&[current_chunk.payload.as_slice()]);
        current_checksums.push(checksum);
        let Some(previous_chunk) = previous_manifest.chunks.get(index) else {
            continue;
        };
        if !persisted_paged_chunk_is_plain(previous_chunk) {
            return Ok(None);
        }
        if previous_chunk.checksum == checksum
            && previous_chunk.row_count == current_chunk.row_count
        {
            continue;
        }
        if index != previous_tail_index {
            return Ok(None);
        }
        first_changed_index = Some(index);
    }

    if first_changed_index.is_none() && manifest.chunks.len() == previous_manifest.chunks.len() {
        return Ok(None);
    }

    let mut new_chunks = Vec::with_capacity(manifest.chunks.len());
    let mut persisted_chunks = Vec::with_capacity(manifest.chunks.len());

    for (index, current_chunk) in manifest.chunks.iter().enumerate() {
        let checksum = current_checksums[index];
        if let Some(previous_chunk) = previous_manifest.chunks.get(index) {
            if previous_chunk.checksum == checksum
                && previous_chunk.row_count == current_chunk.row_count
            {
                new_chunks.push(previous_chunk.clone());
                persisted_chunks.push(persisted_chunk_from_current(
                    previous_chunk.pointer,
                    previous_chunk.checksum,
                    previous_chunk.row_count,
                    current_chunk,
                ));
                continue;
            }

            let pointer = rewrite_overflow(
                store,
                previous_chunk.pointer,
                current_chunk.payload.as_slice(),
                CompressionMode::Never,
            )?;
            new_chunks.push(PersistedTableChunkState {
                pointer,
                checksum,
                row_count: current_chunk.row_count,
                tombstoned_row_ids: Vec::new(),
                overlay_pointer: None,
                overlay_checksum: None,
            });
            persisted_chunks.push(persisted_chunk_from_current(
                pointer,
                checksum,
                current_chunk.row_count,
                current_chunk,
            ));
            continue;
        }

        let pointer = write_overflow(
            store,
            current_chunk.payload.as_slice(),
            CompressionMode::Never,
        )?;
        new_chunks.push(PersistedTableChunkState {
            pointer,
            checksum,
            row_count: current_chunk.row_count,
            tombstoned_row_ids: Vec::new(),
            overlay_pointer: None,
            overlay_checksum: None,
        });
        persisted_chunks.push(persisted_chunk_from_current(
            pointer,
            checksum,
            current_chunk.row_count,
            current_chunk,
        ));
    }

    let updated_manifest_payload =
        encode_paged_table_manifest_payload(&PersistedPagedTableManifest { chunks: new_chunks })?;
    let checksum = crc32c_parts(&[updated_manifest_payload.as_slice()]);
    let pointer = rewrite_overflow(
        store,
        previous_state.pointer.with_table_paged_manifest(false),
        &updated_manifest_payload,
        CompressionMode::Never,
    )?
    .with_table_paged_manifest(true);
    let tail = read_uncompressed_overflow_tail(store, pointer)?.unwrap_or_default();

    Ok(Some((
        PersistedTableState {
            pointer,
            checksum,
            row_count: manifest.row_count(),
            tail,
            pk_index_root: previous_state.pk_index_root,
        },
        persisted_chunks,
    )))
}

fn compact_paged_table_state_for_checkpoint<S: PageStore>(
    store: &mut S,
    state: PersistedTableState,
) -> Result<(PersistedTableState, bool)> {
    if state.pointer.head_page_id == 0 || !state.pointer.is_table_paged_manifest() {
        return Ok((state, false));
    }

    let manifest_payload = read_overflow(store, state.pointer)?;
    if crc32c_parts(&[manifest_payload.as_slice()]) != state.checksum {
        return Err(DbError::corruption(
            "paged table manifest checksum mismatch",
        ));
    }
    let mut manifest = decode_paged_table_manifest_payload(&manifest_payload)?;
    let mut changed = false;
    let chunk_compaction_min_bytes = paged_table_checkpoint_compaction_min_bytes(store.page_size());
    let mut freed_pointers: Vec<OverflowPointer> = Vec::new();
    for chunk in &mut manifest.chunks {
        let needs_merge = !chunk.tombstoned_row_ids.is_empty() || chunk.overlay_pointer.is_some();
        if !needs_merge {
            if chunk.pointer.head_page_id == 0
                || chunk.pointer.is_compressed()
                || usize::try_from(chunk.pointer.logical_len)
                    .ok()
                    .is_none_or(|len| len < chunk_compaction_min_bytes)
            {
                continue;
            }
            let payload = read_overflow(store, chunk.pointer)?;
            let pointer = rewrite_overflow(
                store,
                chunk.pointer,
                &payload,
                CompressionMode::AutoMinBytes(chunk_compaction_min_bytes),
            )?;
            if pointer != chunk.pointer {
                chunk.pointer = pointer;
                changed = true;
            }
            continue;
        }

        // Fold tombstones and overlay into a new base payload.
        let base_payload = read_overflow(store, chunk.pointer)?;
        let base_rows = decode_table_payload_rows(&base_payload)?;
        let mut merged_rows: BTreeMap<i64, StoredRow> = BTreeMap::new();
        for row in base_rows {
            if !chunk.tombstoned_row_ids.contains(&row.row_id) {
                merged_rows.insert(row.row_id, row);
            }
        }
        if let Some(overlay_pointer) = chunk.overlay_pointer {
            let overlay_payload = read_overflow(store, overlay_pointer)?;
            let overlay_rows = decode_table_payload_rows(&overlay_payload)?;
            for row in overlay_rows {
                merged_rows.insert(row.row_id, row);
            }
        }
        let merged: Vec<StoredRow> = merged_rows.into_values().collect();
        let merged_len = merged.len();
        let new_payload = encode_table_payload(&TableData::from_rows(merged))?;
        let new_checksum = crc32c_parts(&[new_payload.as_slice()]);
        let new_pointer = write_overflow(
            store,
            &new_payload,
            CompressionMode::AutoMinBytes(chunk_compaction_min_bytes),
        )?;
        if chunk.pointer.head_page_id != 0 {
            freed_pointers.push(chunk.pointer);
        }
        if let Some(overlay_pointer) = chunk.overlay_pointer {
            if overlay_pointer.head_page_id != 0 {
                freed_pointers.push(overlay_pointer);
            }
        }
        chunk.pointer = new_pointer;
        chunk.checksum = new_checksum;
        chunk.row_count = merged_len;
        chunk.tombstoned_row_ids.clear();
        chunk.overlay_pointer = None;
        chunk.overlay_checksum = None;
        changed = true;
    }

    let should_rewrite_manifest = changed
        || (!state.pointer.is_compressed()
            && usize::try_from(state.pointer.logical_len)
                .ok()
                .is_some_and(|len| len >= AUTO_MIN_PAYLOAD_BYTES));
    if !should_rewrite_manifest {
        return Ok((state, false));
    }

    let manifest_payload = encode_paged_table_manifest_payload(&manifest)?;
    let checksum = crc32c_parts(&[manifest_payload.as_slice()]);
    let pointer = rewrite_overflow(
        store,
        state.pointer.with_table_paged_manifest(false),
        &manifest_payload,
        CompressionMode::Auto,
    )?
    .with_table_paged_manifest(true);
    let tail = if pointer.is_compressed() {
        OverflowTailInfo::default()
    } else {
        read_uncompressed_overflow_tail(store, pointer)?.unwrap_or_default()
    };
    let new_state = PersistedTableState {
        pointer,
        checksum,
        row_count: state.row_count,
        tail,
        pk_index_root: state.pk_index_root,
    };

    // Free old base and overlay pages that were replaced by merge compaction.
    // (Non-merge rewrites use rewrite_overflow which reuses/frees old pages
    // on its own.)
    for old_pointer in freed_pointers {
        if old_pointer.head_page_id != 0 {
            free_overflow(store, old_pointer.head_page_id)?;
        }
    }

    Ok((new_state, new_state != state || changed))
}

fn persist_paged_table<S: PageStore>(
    store: &mut S,
    previous_state: PersistedTableState,
    encoded_chunks: &[EncodedPagedTableChunk],
    row_count: usize,
) -> Result<PersistedTableState> {
    if encoded_chunks.is_empty() {
        if previous_state.pointer.head_page_id != 0 {
            free_persisted_table_bytes(store, previous_state)?;
        }
        return Ok(PersistedTableState {
            pointer: OverflowPointer {
                head_page_id: 0,
                logical_len: 0,
                flags: 0,
            },
            checksum: 0,
            row_count: 0,
            tail: OverflowTailInfo::default(),
            pk_index_root: previous_state.pk_index_root,
        });
    }

    let mut persisted_chunks = Vec::with_capacity(encoded_chunks.len());
    for chunk in encoded_chunks {
        let pointer = write_overflow(store, &chunk.payload, CompressionMode::Never)?;
        persisted_chunks.push(PersistedTableChunkState {
            pointer,
            checksum: chunk.checksum,
            row_count: chunk.row_count,
            tombstoned_row_ids: Vec::new(),
            overlay_pointer: None,
            overlay_checksum: None,
        });
    }
    let manifest = PersistedPagedTableManifest {
        chunks: persisted_chunks,
    };
    let manifest_payload = encode_paged_table_manifest_payload(&manifest)?;
    let checksum = crc32c_parts(&[manifest_payload.as_slice()]);
    let pointer = write_overflow(store, &manifest_payload, CompressionMode::Never)?
        .with_table_paged_manifest(true);
    let tail = read_uncompressed_overflow_tail(store, pointer)?.unwrap_or_default();
    if previous_state.pointer.head_page_id != 0 {
        free_persisted_table_bytes(store, previous_state)?;
    }
    Ok(PersistedTableState {
        pointer,
        checksum,
        row_count,
        tail,
        pk_index_root: previous_state.pk_index_root,
    })
}

fn rewrite_paged_table_from_resident<S: PageStore>(
    store: &mut S,
    previous_state: PersistedTableState,
    data: &TableData,
    page_size: u32,
) -> Result<PersistedTableState> {
    if previous_state.pointer.head_page_id == 0 || !previous_state.pointer.is_table_paged_manifest()
    {
        let encoded_chunks = encode_paged_table_chunks(data, page_size)?;
        return persist_paged_table(store, previous_state, &encoded_chunks, data.rows.len());
    }

    let manifest_payload = read_overflow(store, previous_state.pointer)?;
    if crc32c_parts(&[manifest_payload.as_slice()]) != previous_state.checksum {
        return Err(DbError::corruption(
            "paged table manifest checksum mismatch",
        ));
    }
    let manifest = decode_paged_table_manifest_payload(&manifest_payload)?;
    let mut current_rows_by_id = Int64Map::default();
    for row in &data.rows {
        current_rows_by_id.insert(row.row_id, row);
    }

    let mut seen_old_row_ids = std::collections::BTreeSet::new();
    let mut new_chunks = Vec::with_capacity(manifest.chunks.len());
    let mut replaced_chunk_pointers = Vec::new();
    let mut changed = false;

    for chunk in manifest.chunks {
        let payload = read_overflow(store, chunk.pointer)?;
        if crc32c_parts(&[payload.as_slice()]) != chunk.checksum {
            return Err(DbError::corruption("paged table chunk checksum mismatch"));
        }
        let previous_rows = decode_table_payload_rows(payload.as_slice())?;
        let mut current_chunk_rows = Vec::with_capacity(previous_rows.len());
        let mut chunk_changed = false;

        for previous_row in &previous_rows {
            seen_old_row_ids.insert(previous_row.row_id);
            if let Some(current_row) = current_rows_by_id.get(&previous_row.row_id).copied() {
                if current_row.values != previous_row.values {
                    chunk_changed = true;
                }
                current_chunk_rows.push(current_row.clone());
            } else {
                chunk_changed = true;
            }
        }

        if !chunk_changed {
            new_chunks.push(chunk);
            continue;
        }

        changed = true;
        replaced_chunk_pointers.push(chunk.pointer);
        for encoded_chunk in encode_paged_table_chunks_from_rows(&current_chunk_rows, page_size)? {
            let pointer = write_overflow(store, &encoded_chunk.payload, CompressionMode::Never)?;
            new_chunks.push(PersistedTableChunkState {
                pointer,
                checksum: encoded_chunk.checksum,
                row_count: encoded_chunk.row_count,
                tombstoned_row_ids: Vec::new(),
                overlay_pointer: None,
                overlay_checksum: None,
            });
        }
    }

    let appended_rows = data
        .rows
        .iter()
        .filter(|row| !seen_old_row_ids.contains(&row.row_id))
        .cloned()
        .collect::<Vec<_>>();
    if !appended_rows.is_empty() {
        changed = true;
        for encoded_chunk in encode_paged_table_chunks_from_rows(&appended_rows, page_size)? {
            let pointer = write_overflow(store, &encoded_chunk.payload, CompressionMode::Never)?;
            new_chunks.push(PersistedTableChunkState {
                pointer,
                checksum: encoded_chunk.checksum,
                row_count: encoded_chunk.row_count,
                tombstoned_row_ids: Vec::new(),
                overlay_pointer: None,
                overlay_checksum: None,
            });
        }
    }

    if !changed {
        return Ok(previous_state);
    }

    if new_chunks.is_empty() {
        free_persisted_table_bytes(store, previous_state)?;
        return Ok(PersistedTableState {
            pointer: OverflowPointer {
                head_page_id: 0,
                logical_len: 0,
                flags: 0,
            },
            checksum: 0,
            row_count: 0,
            tail: OverflowTailInfo::default(),
            pk_index_root: previous_state.pk_index_root,
        });
    }

    let updated_manifest_payload =
        encode_paged_table_manifest_payload(&PersistedPagedTableManifest { chunks: new_chunks })?;
    let checksum = crc32c_parts(&[updated_manifest_payload.as_slice()]);
    let pointer = rewrite_overflow(
        store,
        previous_state.pointer.with_table_paged_manifest(false),
        &updated_manifest_payload,
        CompressionMode::Never,
    )?
    .with_table_paged_manifest(true);
    let tail = read_uncompressed_overflow_tail(store, pointer)?.unwrap_or_default();

    for replaced_pointer in replaced_chunk_pointers {
        if replaced_pointer.head_page_id != 0 {
            free_overflow(store, replaced_pointer.head_page_id)?;
        }
    }

    Ok(PersistedTableState {
        pointer,
        checksum,
        row_count: data.rows.len(),
        tail,
        pk_index_root: previous_state.pk_index_root,
    })
}

fn rewrite_paged_table_from_manifest<S: PageStore>(
    store: &mut S,
    previous_state: PersistedTableState,
    manifest: &TablePageManifest,
) -> Result<(PersistedTableState, Vec<TablePageManifestChunk>)> {
    if manifest.chunks.is_empty() {
        if previous_state.pointer.head_page_id != 0 {
            free_persisted_table_bytes(store, previous_state)?;
        }
        return Ok((
            PersistedTableState {
                pointer: OverflowPointer {
                    head_page_id: 0,
                    logical_len: 0,
                    flags: 0,
                },
                checksum: 0,
                row_count: 0,
                tail: OverflowTailInfo::default(),
                pk_index_root: previous_state.pk_index_root,
            },
            Vec::new(),
        ));
    }

    let previous_chunks = if previous_state.pointer.head_page_id != 0
        && previous_state.pointer.is_table_paged_manifest()
    {
        let manifest_payload = read_overflow(store, previous_state.pointer)?;
        if crc32c_parts(&[manifest_payload.as_slice()]) != previous_state.checksum {
            return Err(DbError::corruption(
                "paged table manifest checksum mismatch",
            ));
        }
        decode_paged_table_manifest_payload(&manifest_payload)?.chunks
    } else {
        Vec::new()
    };
    let previous_payloads = if previous_state.pointer.head_page_id != 0
        && previous_state.pointer.is_table_paged_manifest()
    {
        read_paged_table_chunk_payloads(store, previous_state)?
    } else {
        Vec::new()
    };
    let reusable_previous = previous_chunks
        .into_iter()
        .zip(previous_payloads)
        .collect::<Vec<_>>();
    let mut reused_previous = vec![false; reusable_previous.len()];

    let mut new_chunks = Vec::with_capacity(manifest.chunks.len());
    let mut persisted_chunks = Vec::with_capacity(manifest.chunks.len());
    for current_chunk in manifest.chunks.iter() {
        let checksum = crc32c_parts(&[current_chunk.payload.as_slice()]);
        let _overlay_checksum = current_chunk
            .overlay_payload
            .as_ref()
            .map(|p| crc32c_parts(&[p.as_slice()]));
        let reused_index =
            reusable_previous
                .iter()
                .enumerate()
                .find_map(|(index, (chunk_state, payload))| {
                    let overlay_match = matches!(
                        (&chunk_state.overlay_pointer, &current_chunk.overlay_payload),
                        (None, None)
                    );
                    (!reused_previous[index]
                        && chunk_state.checksum == checksum
                        && payload.payload.as_slice() == current_chunk.payload.as_slice()
                        && chunk_state.tombstoned_row_ids.len()
                            == current_chunk.tombstoned_row_ids.len()
                        && chunk_state
                            .tombstoned_row_ids
                            .iter()
                            .all(|id| current_chunk.tombstoned_row_ids.contains(id))
                        && overlay_match)
                        .then_some(index)
                });
        if let Some(index) = reused_index {
            reused_previous[index] = true;
            let chunk_state = reusable_previous[index].0.clone();
            persisted_chunks.push(TablePageManifestChunk {
                pointer: chunk_state.pointer,
                checksum: chunk_state.checksum,
                row_count: chunk_state.row_count,
                payload: Arc::clone(&current_chunk.payload),
                tombstoned_row_ids: Arc::clone(&current_chunk.tombstoned_row_ids),
                overlay_pointer: chunk_state.overlay_pointer,
                overlay_checksum: chunk_state.overlay_checksum,
                overlay_payload: current_chunk.overlay_payload.clone(),
            });
            new_chunks.push(chunk_state);
            continue;
        }

        let pointer = write_overflow(store, &current_chunk.payload, CompressionMode::Never)?;
        let (overlay_pointer, overlay_checksum) =
            if let Some(overlay_payload) = &current_chunk.overlay_payload {
                let overlay_pointer =
                    write_overflow(store, overlay_payload.as_slice(), CompressionMode::Never)?;
                let overlay_checksum = crc32c_parts(&[overlay_payload.as_slice()]);
                (Some(overlay_pointer), Some(overlay_checksum))
            } else {
                (None, None)
            };
        let base_physical = read_table_payload_row_count_from_bytes(&current_chunk.payload)?;
        let overlay_physical = current_chunk
            .overlay_payload
            .as_ref()
            .map(|p| read_table_payload_row_count_from_bytes(p).unwrap_or(0))
            .unwrap_or(0);
        let visible = base_physical
            .saturating_sub(current_chunk.tombstoned_row_ids.len())
            .saturating_add(overlay_physical);
        new_chunks.push(PersistedTableChunkState {
            pointer,
            checksum,
            row_count: visible,
            tombstoned_row_ids: current_chunk.tombstoned_row_ids.iter().copied().collect(),
            overlay_pointer,
            overlay_checksum,
        });
        persisted_chunks.push(TablePageManifestChunk {
            pointer,
            checksum,
            row_count: visible,
            payload: Arc::clone(&current_chunk.payload),
            tombstoned_row_ids: Arc::clone(&current_chunk.tombstoned_row_ids),
            overlay_pointer,
            overlay_checksum,
            overlay_payload: current_chunk.overlay_payload.clone(),
        });
    }

    let updated_manifest_payload =
        encode_paged_table_manifest_payload(&PersistedPagedTableManifest { chunks: new_chunks })?;
    let checksum = crc32c_parts(&[updated_manifest_payload.as_slice()]);
    let pointer = rewrite_overflow(
        store,
        previous_state.pointer.with_table_paged_manifest(false),
        &updated_manifest_payload,
        CompressionMode::Never,
    )?
    .with_table_paged_manifest(true);
    let tail = read_uncompressed_overflow_tail(store, pointer)?.unwrap_or_default();

    for (index, (chunk_state, _)) in reusable_previous.iter().enumerate() {
        if reused_previous[index] || chunk_state.pointer.head_page_id == 0 {
            continue;
        }
        free_overflow(store, chunk_state.pointer.head_page_id)?;
        if let Some(overlay_pointer) = chunk_state.overlay_pointer {
            if overlay_pointer.head_page_id != 0 {
                free_overflow(store, overlay_pointer.head_page_id)?;
            }
        }
    }

    Ok((
        PersistedTableState {
            pointer,
            checksum,
            row_count: manifest.row_count(),
            tail,
            pk_index_root: previous_state.pk_index_root,
        },
        persisted_chunks,
    ))
}

fn build_persistent_pk_index_root(db: &crate::db::Db, payload: &[u8]) -> Result<Option<PageId>> {
    let entries = build_row_locator_entries(payload)?;
    let mut tree = Btree::new(DbTxnPageStore { db });
    tree.replace_entries(entries)?;
    let (_store, root_page_id) = tree.into_parts();
    Ok(root_page_id)
}

fn build_persistent_pk_index_root_from_chunk_payloads(
    db: &crate::db::Db,
    chunk_payloads: &[TablePageManifestChunk],
) -> Result<Option<PageId>> {
    let entries = build_paged_row_locator_entries_from_chunk_payloads(chunk_payloads)?;
    let mut tree = Btree::new(DbTxnPageStore { db });
    tree.replace_entries(entries)?;
    let (_store, root_page_id) = tree.into_parts();
    Ok(root_page_id)
}

fn replace_table_pk_index_root(
    runtime: &mut EngineRuntime,
    db: &crate::db::Db,
    table_name: &str,
    new_pk_index_root: Option<PageId>,
) -> Result<()> {
    let previous_pk_index_root = runtime
        .persisted_tables
        .get(table_name)
        .and_then(|state| state.pk_index_root)
        .or_else(|| {
            runtime
                .catalog
                .tables
                .get(table_name)
                .and_then(|table| table.pk_index_root)
        });
    match previous_pk_index_root {
        Some(previous_pk_index_root) if Some(previous_pk_index_root) != new_pk_index_root => {
            let mut store = DbTxnPageStore { db };
            free_table_btree(&mut store, Some(previous_pk_index_root))?;
        }
        _ => {}
    }
    let table = runtime
        .catalog_mut()
        .tables
        .get_mut(table_name)
        .ok_or_else(|| DbError::internal(format!("table schema for {table_name} is missing")))?;
    table.pk_index_root = new_pk_index_root;
    if let Some(state) = runtime.persisted_tables_mut().get_mut(table_name) {
        state.pk_index_root = new_pk_index_root;
    }
    Ok(())
}

/// Build a new payload by splicing only the modified rows into the cached
/// previous payload.  Unchanged row bytes are copied verbatim from `old`,
/// saving the per-row serialisation cost for the common single-row UPDATE.
/// Result of a splice operation, containing the new payload and dirty byte
/// range metadata.
struct SpliceResult {
    payload: Vec<u8>,
    /// Byte offset of the first modified byte in the OLD payload.
    first_dirty_byte: usize,
    /// Exclusive byte offset of the first byte after the changed range in the
    /// OLD payload, when conservative behavior is used this may be payload
    /// length.
    last_dirty_byte: usize,
    /// Whether the updated payload preserves row offsets and can reuse
    /// the previous persistent PK locator root.
    pk_locator_preserved: bool,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct SpliceDirtyRange {
    first_dirty_byte: usize,
    last_dirty_byte: usize,
}

fn single_dirty_range(range: Range<usize>) -> Vec<Range<usize>> {
    std::iter::once(range).collect()
}

fn splice_updated_rows_payload_in_place(
    payload: &mut [u8],
    data: &TableData,
    dirty_indices: &[usize],
) -> Result<Option<SpliceDirtyRange>> {
    const HEADER_LEN: usize = 8 /* magic */ + 4 /* row_count */;

    if payload.len() < HEADER_LEN || payload[..8] != *TABLE_PAYLOAD_MAGIC {
        return Ok(None);
    }
    let old_row_count =
        u32::from_le_bytes(payload[8..12].try_into().expect("row-count header length")) as usize;
    if old_row_count != data.rows.len() {
        return Ok(None);
    }

    let mut sorted_dirty: Vec<usize> = dirty_indices.to_vec();
    sorted_dirty.sort_unstable();
    sorted_dirty.dedup();
    if sorted_dirty.is_empty() {
        return Ok(Some(SpliceDirtyRange {
            first_dirty_byte: payload.len(),
            last_dirty_byte: payload.len(),
        }));
    }

    let mut row_spans: Vec<(usize, usize)> = Vec::with_capacity(sorted_dirty.len());
    let mut scan_offset = HEADER_LEN;
    let mut dirty_cursor = 0;
    let mut row_idx = 0;
    while dirty_cursor < sorted_dirty.len() && scan_offset + 12 <= payload.len() {
        if row_idx >= old_row_count {
            break;
        }
        let row_id = i64::from_le_bytes(
            payload[scan_offset..scan_offset + 8]
                .try_into()
                .expect("row id length"),
        );
        let row_data_len = u32::from_le_bytes(
            payload[scan_offset + 8..scan_offset + 12]
                .try_into()
                .expect("row data len"),
        ) as usize;
        let row_end = scan_offset.saturating_add(12).saturating_add(row_data_len);
        if row_end > payload.len() {
            return Ok(None);
        }
        if row_idx == sorted_dirty[dirty_cursor] {
            let Some(row) = data.rows.get(row_idx) else {
                return Ok(None);
            };
            if row.row_id != row_id {
                return Ok(None);
            }
            row_spans.push((scan_offset, row_end));
            dirty_cursor += 1;
            if dirty_cursor == sorted_dirty.len() {
                break;
            }
        }
        scan_offset = row_end;
        row_idx += 1;
    }
    if row_spans.len() != sorted_dirty.len() {
        return Ok(None);
    }

    let mut encoded_rows: Vec<Vec<u8>> = Vec::with_capacity(sorted_dirty.len());
    let mut encoded_row = Vec::with_capacity(128);
    for (span_idx, &dirty_row) in sorted_dirty.iter().enumerate() {
        let Some(row) = data.rows.get(dirty_row) else {
            return Ok(None);
        };
        let (span_start, span_end) = row_spans[span_idx];
        let old_row_body_len = span_end.saturating_sub(span_start).saturating_sub(12);
        encoded_row.clear();
        Row::encode_values_into(&row.values, &mut encoded_row)?;
        if encoded_row.len() > old_row_body_len {
            return Ok(None);
        }
        encoded_rows.push(encoded_row.clone());
    }

    for (span_idx, encoded_row) in encoded_rows.iter().enumerate() {
        let (span_start, span_end) = row_spans[span_idx];
        let body_start = span_start.saturating_add(12);
        let body_written_end = body_start.saturating_add(encoded_row.len());
        payload[body_start..body_written_end].copy_from_slice(encoded_row);
        payload[body_written_end..span_end].fill(0);
    }

    Ok(Some(SpliceDirtyRange {
        first_dirty_byte: row_spans
            .first()
            .map_or(0, |span| span.0.saturating_add(12)),
        last_dirty_byte: row_spans.last().map_or(payload.len(), |span| span.1),
    }))
}

fn splice_deleted_rows_payload_in_place(
    payload: &mut Vec<u8>,
    data: &TableData,
    deleted_row_ids: &BTreeSet<i64>,
) -> Result<Option<Vec<Range<usize>>>> {
    const HEADER_LEN: usize = 8 /* magic */ + 4 /* row_count */;

    if deleted_row_ids.is_empty() {
        return Ok(Some(single_dirty_range(payload.len()..payload.len())));
    }
    if payload.len() < HEADER_LEN || payload[..8] != *TABLE_PAYLOAD_MAGIC {
        return Ok(None);
    }
    let old_row_count =
        u32::from_le_bytes(payload[8..12].try_into().expect("row-count header length")) as usize;
    if old_row_count != data.rows.len().saturating_add(deleted_row_ids.len()) {
        return Ok(None);
    }

    let mut deleted_spans: Vec<(usize, usize)> = Vec::with_capacity(deleted_row_ids.len());
    let mut remaining = deleted_row_ids.len();
    let mut scan_offset = HEADER_LEN;
    let mut scanned_rows = 0usize;
    while remaining > 0 && scan_offset + 12 <= payload.len() {
        if scanned_rows >= old_row_count {
            break;
        }
        let row_id = i64::from_le_bytes(
            payload[scan_offset..scan_offset + 8]
                .try_into()
                .expect("row id length"),
        );
        let row_data_len = u32::from_le_bytes(
            payload[scan_offset + 8..scan_offset + 12]
                .try_into()
                .expect("row data len"),
        ) as usize;
        let row_end = scan_offset.saturating_add(12).saturating_add(row_data_len);
        if row_end > payload.len() {
            return Ok(None);
        }
        if deleted_row_ids.contains(&row_id) {
            deleted_spans.push((scan_offset, row_end));
            remaining -= 1;
        }
        scan_offset = row_end;
        scanned_rows += 1;
    }

    if remaining > 0 || deleted_spans.len() != deleted_row_ids.len() {
        return Ok(None);
    }

    let original_len = payload.len();
    let first_deleted_byte = deleted_spans.first().map_or(HEADER_LEN, |span| span.0);
    payload[8..12].copy_from_slice(
        &u32::try_from(data.rows.len())
            .map_err(|_| DbError::constraint("table row count exceeds u32"))?
            .to_le_bytes(),
    );

    let mut copy_from = HEADER_LEN;
    let mut write_at = HEADER_LEN;
    for (span_start, span_end) in deleted_spans {
        if copy_from < span_start {
            if copy_from != write_at {
                payload.copy_within(copy_from..span_start, write_at);
            }
            write_at += span_start - copy_from;
        }
        copy_from = span_end;
    }
    if copy_from < original_len {
        let tail_len = original_len - copy_from;
        if copy_from != write_at {
            payload.copy_within(copy_from..original_len, write_at);
        }
        write_at += tail_len;
    }
    payload.truncate(write_at);

    let mut ranges = single_dirty_range(8..HEADER_LEN);
    if !payload.is_empty() {
        let tail_dirty_start = first_deleted_byte.saturating_sub(1).min(payload.len());
        if tail_dirty_start < payload.len() {
            ranges.push(tail_dirty_start..payload.len());
        }
    }
    Ok(Some(ranges))
}

fn splice_updated_rows_payload(
    old: &[u8],
    data: &TableData,
    dirty_indices: &[usize],
) -> Result<SpliceResult> {
    const HEADER_LEN: usize = 8 /* magic */ + 4 /* row_count */;

    if old.len() < HEADER_LEN || old[..8] != *TABLE_PAYLOAD_MAGIC {
        let payload = encode_table_payload(data)?;
        let payload_len = payload.len();
        return Ok(SpliceResult {
            payload,
            first_dirty_byte: 0,
            last_dirty_byte: payload_len,
            pk_locator_preserved: false,
        });
    }
    let old_row_count =
        u32::from_le_bytes(old[8..12].try_into().expect("row-count header length")) as usize;
    if old_row_count != data.rows.len() {
        // Row count changed (e.g. concurrent insert/delete after the cache
        // was stored) — fall back to full encode for safety.
        let payload = encode_table_payload(data)?;
        let payload_len = payload.len();
        return Ok(SpliceResult {
            payload,
            first_dirty_byte: 0,
            last_dirty_byte: payload_len,
            pk_locator_preserved: false,
        });
    }

    // Fast path: only a handful of rows changed.  Scan the old payload to
    // locate byte ranges of each dirty row, then splice new encodings in.
    //
    // Row wire format:
    //   row_id       (8 bytes, i64 LE)
    //   row_data_len (4 bytes, u32 LE)
    //   row_data     (row_data_len bytes)
    //
    // We need the byte offset of each dirty row (and the one after it) so
    // we can copy unchanged prefix / suffix regions.

    // Sort dirty indices so we splice left-to-right.
    let mut sorted_dirty: Vec<usize> = dirty_indices.to_vec();
    sorted_dirty.sort_unstable();
    sorted_dirty.dedup();

    // Scan the old payload to locate dirty row byte ranges.
    // row_spans[i] = (start, end) byte offsets in `old` for dirty row i.
    let mut row_spans: Vec<(usize, usize)> = Vec::with_capacity(sorted_dirty.len());
    let mut scan_offset = HEADER_LEN;
    let mut dirty_cursor = 0;
    let mut row_idx = 0;
    while dirty_cursor < sorted_dirty.len() && scan_offset + 12 <= old.len() {
        if row_idx >= old_row_count {
            break;
        }
        let rd_len = u32::from_le_bytes(
            old[scan_offset + 8..scan_offset + 12]
                .try_into()
                .expect("row data len"),
        ) as usize;
        let row_end = scan_offset + 12 + rd_len;
        if row_end > old.len() {
            let payload = encode_table_payload(data)?;
            let payload_len = payload.len();
            return Ok(SpliceResult {
                payload,
                first_dirty_byte: 0,
                last_dirty_byte: payload_len,
                pk_locator_preserved: false,
            });
        }
        if row_idx == sorted_dirty[dirty_cursor] {
            row_spans.push((scan_offset, row_end));
            dirty_cursor += 1;
            if dirty_cursor == sorted_dirty.len() {
                break;
            }
        }
        scan_offset = row_end;
        row_idx += 1;
    }

    if row_spans.len() != sorted_dirty.len() {
        // Could not find all dirty rows in the old payload; fall back.
        let payload = encode_table_payload(data)?;
        let payload_len = payload.len();
        return Ok(SpliceResult {
            payload,
            first_dirty_byte: 0,
            last_dirty_byte: payload_len,
            pk_locator_preserved: false,
        });
    }

    if row_spans.is_empty() {
        return Ok(SpliceResult {
            payload: old.to_vec(),
            first_dirty_byte: 0,
            last_dirty_byte: old.len(),
            pk_locator_preserved: false,
        });
    }

    let mut can_preserve_body = true;
    let mut encoded_rows: Vec<Vec<u8>> = Vec::with_capacity(sorted_dirty.len());
    let mut encoded_row = Vec::with_capacity(128);
    for (span_idx, &dirty_row) in sorted_dirty.iter().enumerate() {
        if dirty_row >= data.rows.len() {
            let payload = encode_table_payload(data)?;
            let payload_len = payload.len();
            return Ok(SpliceResult {
                payload,
                first_dirty_byte: 0,
                last_dirty_byte: payload_len,
                pk_locator_preserved: false,
            });
        }
        let (span_start, span_end) = row_spans[span_idx];
        let old_row_body_len = span_end.saturating_sub(span_start).saturating_sub(12);

        let row = &data.rows[dirty_row];
        encoded_row.clear();
        Row::encode_values_into(&row.values, &mut encoded_row)?;
        if encoded_row.len() > old_row_body_len {
            can_preserve_body = false;
        }
        encoded_rows.push(encoded_row.clone());
    }

    let mut output = Vec::with_capacity(if can_preserve_body {
        old.len()
    } else {
        old.len().saturating_add(sorted_dirty.len() * 32)
    });
    output.extend_from_slice(&old[..8]); // magic
    encode_u32(&mut output, data.rows.len() as u32);

    let first_dirty_byte = if can_preserve_body {
        row_spans.first().map_or(0, |s| s.0.saturating_add(12))
    } else {
        row_spans.first().map_or(0, |s| s.0)
    };
    let last_dirty_byte = if can_preserve_body {
        row_spans.last().map_or(first_dirty_byte, |s| s.1)
    } else {
        old.len()
    };

    let mut copy_from = HEADER_LEN;
    for (span_idx, &dirty_row) in sorted_dirty.iter().enumerate() {
        let (span_start, span_end) = row_spans[span_idx];
        let old_row_body_len = span_end.saturating_sub(span_start).saturating_sub(12);
        let encoded_row = &encoded_rows[span_idx];

        // Copy unchanged bytes before this dirty row.
        if copy_from < span_start {
            output.extend_from_slice(&old[copy_from..span_start]);
        }

        // Encode the updated row.
        let row = &data.rows[dirty_row];
        encode_i64(&mut output, row.row_id);
        if can_preserve_body {
            let row_body_len = u32::try_from(old_row_body_len)
                .map_err(|_| DbError::constraint("table row body length exceeds u32"))?;
            output.extend_from_slice(&row_body_len.to_le_bytes());
            output.extend_from_slice(encoded_row);
            output.extend(std::iter::repeat_n(
                0u8,
                old_row_body_len.saturating_sub(encoded_row.len()),
            ));
        } else {
            encode_u32(
                &mut output,
                u32::try_from(encoded_row.len())
                    .map_err(|_| DbError::constraint("table row body length exceeds u32"))?,
            );
            output.extend_from_slice(encoded_row);
        }

        copy_from = span_end;
    }
    // Copy any remaining unchanged tail.
    if copy_from < old.len() {
        output.extend_from_slice(&old[copy_from..]);
    }

    Ok(SpliceResult {
        payload: output,
        first_dirty_byte,
        last_dirty_byte,
        pk_locator_preserved: can_preserve_body,
    })
}

fn splice_deleted_rows_payload(
    old: &[u8],
    data: &TableData,
    deleted_row_ids: &BTreeSet<i64>,
) -> Result<SpliceResult> {
    const HEADER_LEN: usize = 8 /* magic */ + 4 /* row_count */;

    if deleted_row_ids.is_empty() {
        return Ok(SpliceResult {
            payload: old.to_vec(),
            first_dirty_byte: old.len(),
            last_dirty_byte: old.len(),
            pk_locator_preserved: false,
        });
    }
    if old.len() < HEADER_LEN || old[..8] != *TABLE_PAYLOAD_MAGIC {
        let payload = encode_table_payload(data)?;
        let payload_len = payload.len();
        return Ok(SpliceResult {
            payload,
            first_dirty_byte: 0,
            last_dirty_byte: payload_len,
            pk_locator_preserved: false,
        });
    }
    let old_row_count =
        u32::from_le_bytes(old[8..12].try_into().expect("row-count header length")) as usize;
    if old_row_count != data.rows.len().saturating_add(deleted_row_ids.len()) {
        let payload = encode_table_payload(data)?;
        let payload_len = payload.len();
        return Ok(SpliceResult {
            payload,
            first_dirty_byte: 0,
            last_dirty_byte: payload_len,
            pk_locator_preserved: false,
        });
    }

    let mut deleted_spans: Vec<(usize, usize)> = Vec::with_capacity(deleted_row_ids.len());
    let mut remaining = deleted_row_ids.len();
    let mut scan_offset = HEADER_LEN;
    while remaining > 0 && scan_offset + 12 <= old.len() {
        let row_id = i64::from_le_bytes(
            old[scan_offset..scan_offset + 8]
                .try_into()
                .expect("row id length"),
        );
        let row_data_len = u32::from_le_bytes(
            old[scan_offset + 8..scan_offset + 12]
                .try_into()
                .expect("row data len"),
        ) as usize;
        let row_end = scan_offset.saturating_add(12).saturating_add(row_data_len);
        if row_end > old.len() {
            let payload = encode_table_payload(data)?;
            let payload_len = payload.len();
            return Ok(SpliceResult {
                payload,
                first_dirty_byte: 0,
                last_dirty_byte: payload_len,
                pk_locator_preserved: false,
            });
        }
        if deleted_row_ids.contains(&row_id) {
            deleted_spans.push((scan_offset, row_end));
            remaining -= 1;
        }
        scan_offset = row_end;
    }

    if remaining > 0 || deleted_spans.len() != deleted_row_ids.len() {
        let payload = encode_table_payload(data)?;
        let payload_len = payload.len();
        return Ok(SpliceResult {
            payload,
            first_dirty_byte: 0,
            last_dirty_byte: payload_len,
            pk_locator_preserved: false,
        });
    }

    let first_dirty_byte = deleted_spans.first().map_or(0, |span| span.0);
    let mut output = Vec::with_capacity(old.len());
    output.extend_from_slice(&old[..TABLE_PAYLOAD_MAGIC.len()]);
    encode_u32(&mut output, data.rows.len() as u32);

    let mut copy_from = HEADER_LEN;
    for (span_start, span_end) in deleted_spans {
        if copy_from < span_start {
            output.extend_from_slice(&old[copy_from..span_start]);
        }
        copy_from = span_end;
    }
    if copy_from < old.len() {
        output.extend_from_slice(&old[copy_from..]);
    }

    let last_dirty_byte = output.len();
    Ok(SpliceResult {
        payload: output,
        first_dirty_byte,
        last_dirty_byte,
        pk_locator_preserved: false,
    })
}

fn encode_appended_table_rows(data: &TableData, existing_count: usize) -> Result<Vec<u8>> {
    if existing_count > data.rows.len() {
        return Err(DbError::internal(
            "append-only table payload rewrite saw fewer rows than the previous persisted payload",
        ));
    }
    if existing_count == data.rows.len() {
        return Ok(Vec::new());
    }

    let mut appended = Vec::with_capacity((data.rows.len() - existing_count) * 32);
    let mut encoded_row = Vec::with_capacity(64);
    for row in data.rows.iter().skip(existing_count) {
        encode_i64(&mut appended, row.row_id);
        Row::encode_values_into(&row.values, &mut encoded_row)?;
        let row_body_len = encoded_row
            .len()
            .saturating_add(TABLE_PAYLOAD_ROW_BODY_PADDING_BYTES);
        encode_u32(
            &mut appended,
            u32::try_from(row_body_len)
                .map_err(|_| DbError::constraint("table row body length exceeds u32"))?,
        );
        appended.extend_from_slice(&encoded_row);
        appended.extend(std::iter::repeat_n(
            0u8,
            row_body_len.saturating_sub(encoded_row.len()),
        ));
        encoded_row.clear();
    }
    Ok(appended)
}

fn append_encoded_rows_to_table_payload(
    mut previous: Vec<u8>,
    row_count: usize,
    appended_rows: &[u8],
) -> Result<Vec<u8>> {
    if appended_rows.is_empty() {
        return Ok(previous);
    }
    let count_offset = TABLE_PAYLOAD_MAGIC.len();
    if previous.len() < count_offset + 4 {
        return Err(DbError::corruption("table payload header is truncated"));
    }
    if previous[..count_offset] != *TABLE_PAYLOAD_MAGIC {
        return Err(DbError::corruption("table payload magic is invalid"));
    }

    previous[count_offset..count_offset + 4].copy_from_slice(
        &u32::try_from(row_count)
            .map_err(|_| DbError::constraint("table row count exceeds u32"))?
            .to_le_bytes(),
    );
    previous.extend_from_slice(appended_rows);
    Ok(previous)
}

fn append_table_payload(mut previous: Vec<u8>, data: &TableData) -> Result<Vec<u8>> {
    if data.rows.is_empty() {
        return Ok(Vec::new());
    }
    if previous.is_empty() {
        return encode_table_payload(data);
    }
    let count_offset = TABLE_PAYLOAD_MAGIC.len();
    if previous.len() < count_offset + 4 {
        return Err(DbError::corruption("table payload header is truncated"));
    }
    if previous[..count_offset] != *TABLE_PAYLOAD_MAGIC {
        return Err(DbError::corruption("table payload magic is invalid"));
    }

    let existing_count = u32::from_le_bytes(
        previous[count_offset..count_offset + 4]
            .try_into()
            .expect("row-count header length"),
    ) as usize;
    let appended_rows = encode_appended_table_rows(data, existing_count)?;
    if appended_rows.is_empty() {
        return Ok(previous);
    }

    previous[count_offset..count_offset + 4].copy_from_slice(
        &u32::try_from(data.rows.len())
            .map_err(|_| DbError::constraint("table row count exceeds u32"))?
            .to_le_bytes(),
    );
    previous.extend_from_slice(&appended_rows);
    Ok(previous)
}

#[cfg(test)]
fn decode_table_payload(bytes: &[u8]) -> Result<TableData> {
    if bytes.is_empty() {
        return Ok(TableData::default());
    }
    let mut cursor = Cursor::new(bytes);
    let magic = cursor.read_slice(TABLE_PAYLOAD_MAGIC.len())?;
    if magic != TABLE_PAYLOAD_MAGIC {
        return Err(DbError::corruption("table payload magic is invalid"));
    }
    let row_count = cursor.read_u32()? as usize;
    let mut data = TableData::default();
    data.rows.reserve(row_count);
    while cursor.offset < cursor.bytes.len() {
        let row_id = cursor.read_i64()?;
        let row_bytes_len = cursor.read_u32()? as usize;
        let row_bytes = cursor.read_slice(row_bytes_len)?;
        let row = Row::decode(row_bytes)?;
        data.push_row(StoredRow {
            row_id,
            values: row.into_values(),
        });
    }
    if data.rows.len() < row_count {
        return Err(DbError::corruption(
            "table payload row count exceeded decoded row content",
        ));
    }
    Ok(data)
}

fn encode_u32(output: &mut Vec<u8>, value: u32) {
    output.extend_from_slice(&value.to_le_bytes());
}

fn encode_u64(output: &mut Vec<u8>, value: u64) {
    output.extend_from_slice(&value.to_le_bytes());
}

fn encode_i64(output: &mut Vec<u8>, value: i64) {
    output.extend_from_slice(&value.to_le_bytes());
}

fn encode_string(output: &mut Vec<u8>, value: &str) -> Result<()> {
    encode_u32(
        output,
        u32::try_from(value.len()).map_err(|_| DbError::constraint("string length exceeds u32"))?,
    );
    output.extend_from_slice(value.as_bytes());
    Ok(())
}

fn encode_optional_string(output: &mut Vec<u8>, value: Option<&str>) -> Result<()> {
    output.push(u8::from(value.is_some()));
    if let Some(value) = value {
        encode_string(output, value)?;
    }
    Ok(())
}

fn encode_strings(output: &mut Vec<u8>, values: &[String]) -> Result<()> {
    encode_u32(
        output,
        u32::try_from(values.len())
            .map_err(|_| DbError::constraint("string list length exceeds u32"))?,
    );
    for value in values {
        encode_string(output, value)?;
    }
    Ok(())
}

fn encode_bytes(output: &mut Vec<u8>, bytes: &[u8]) -> Result<()> {
    encode_u32(
        output,
        u32::try_from(bytes.len())
            .map_err(|_| DbError::constraint("byte vector length exceeds u32"))?,
    );
    output.extend_from_slice(bytes);
    Ok(())
}

fn encode_foreign_key(
    output: &mut Vec<u8>,
    foreign_key: &crate::catalog::ForeignKeyConstraint,
) -> Result<()> {
    encode_optional_string(output, foreign_key.name.as_deref())?;
    encode_strings(output, &foreign_key.columns)?;
    encode_string(output, &foreign_key.referenced_table)?;
    encode_strings(output, &foreign_key.referenced_columns)?;
    output.push(foreign_key.on_delete as u8);
    output.push(foreign_key.on_update as u8);
    Ok(())
}

fn encode_generated_columns_section(
    output: &mut Vec<u8>,
    tables: &BTreeMap<String, TableSchema>,
) -> Result<()> {
    let generated_columns = tables
        .values()
        .flat_map(|table| {
            table.columns.iter().filter_map(move |column| {
                column.generated_sql.as_ref().map(|generated_sql| {
                    (
                        table.name.as_str(),
                        column.name.as_str(),
                        generated_sql.as_str(),
                        column.generated_stored,
                    )
                })
            })
        })
        .collect::<Vec<_>>();
    output.extend_from_slice(GENERATED_COLUMNS_SECTION_MAGIC);
    output.push(1);
    encode_u32(
        output,
        u32::try_from(generated_columns.len())
            .map_err(|_| DbError::constraint("generated column count exceeds u32"))?,
    );
    for (table_name, column_name, generated_sql, generated_stored) in generated_columns {
        encode_string(output, table_name)?;
        encode_string(output, column_name)?;
        encode_string(output, generated_sql)?;
        output.push(u8::from(generated_stored));
    }
    Ok(())
}

fn encode_spatial_columns_section(
    output: &mut Vec<u8>,
    tables: &BTreeMap<String, TableSchema>,
) -> Result<()> {
    let spatial_columns = tables
        .values()
        .flat_map(|table| {
            table.columns.iter().filter_map(move |column| {
                column
                    .spatial_type
                    .map(|spatial_type| (table.name.as_str(), column.name.as_str(), spatial_type))
            })
        })
        .collect::<Vec<_>>();
    output.extend_from_slice(SPATIAL_COLUMNS_SECTION_MAGIC);
    output.push(1);
    encode_u32(
        output,
        u32::try_from(spatial_columns.len())
            .map_err(|_| DbError::constraint("spatial column count exceeds u32"))?,
    );
    for (table_name, column_name, spatial_type) in spatial_columns {
        encode_string(output, table_name)?;
        encode_string(output, column_name)?;
        output.push(encode_spatial_subtype_tag(spatial_type.subtype));
        output.push(encode_spatial_dimensions_tag(spatial_type.dimensions));
        let srid = u32::try_from(spatial_type.srid)
            .map_err(|_| DbError::constraint("spatial SRID must be non-negative"))?;
        encode_u32(output, srid);
    }
    Ok(())
}

fn encode_enum_columns_section(
    output: &mut Vec<u8>,
    tables: &BTreeMap<String, TableSchema>,
) -> Result<()> {
    let enum_columns = tables
        .values()
        .flat_map(|table| {
            table.columns.iter().filter_map(move |column| {
                column
                    .enum_type
                    .as_ref()
                    .map(|enum_type| (table.name.as_str(), column.name.as_str(), enum_type))
            })
        })
        .collect::<Vec<_>>();
    output.extend_from_slice(ENUM_COLUMNS_SECTION_MAGIC);
    output.push(1);
    encode_u32(
        output,
        u32::try_from(enum_columns.len())
            .map_err(|_| DbError::constraint("enum column count exceeds u32"))?,
    );
    for (table_name, column_name, enum_type) in enum_columns {
        encode_string(output, table_name)?;
        encode_string(output, column_name)?;
        encode_u64(output, enum_type.type_id);
        encode_u32(
            output,
            u32::try_from(enum_type.labels.len())
                .map_err(|_| DbError::constraint("enum label count exceeds u32"))?,
        );
        for label in &enum_type.labels {
            encode_u64(output, label.id);
            encode_string(output, &label.label)?;
        }
    }
    Ok(())
}

fn encode_index_include_columns_section(
    output: &mut Vec<u8>,
    indexes: &BTreeMap<String, IndexSchema>,
) -> Result<()> {
    let include_entries = indexes
        .iter()
        .filter(|(_, index)| !index.include_columns.is_empty())
        .collect::<Vec<_>>();
    output.extend_from_slice(INDEX_INCLUDE_COLUMNS_SECTION_MAGIC);
    output.push(1);
    encode_u32(
        output,
        u32::try_from(include_entries.len())
            .map_err(|_| DbError::constraint("index include entry count exceeds u32"))?,
    );
    for (index_name, index) in include_entries {
        encode_string(output, index_name)?;
        encode_strings(output, &index.include_columns)?;
    }
    Ok(())
}

fn encode_full_text_options_section(
    output: &mut Vec<u8>,
    indexes: &BTreeMap<String, IndexSchema>,
) -> Result<()> {
    let entries = indexes
        .iter()
        .filter_map(|(name, index)| index.full_text.as_ref().map(|config| (name, config)))
        .collect::<Vec<_>>();
    output.extend_from_slice(FULL_TEXT_OPTIONS_SECTION_MAGIC);
    output.push(1);
    encode_u32(
        output,
        u32::try_from(entries.len())
            .map_err(|_| DbError::constraint("fulltext option entry count exceeds u32"))?,
    );
    for (index_name, config) in entries {
        encode_string(output, index_name)?;
        let bytes = config
            .to_json()
            .map_err(|error| DbError::internal(error.message))?;
        encode_bytes(output, &bytes)?;
    }
    Ok(())
}

fn encode_schemas_section(
    output: &mut Vec<u8>,
    schemas: &BTreeMap<String, SchemaInfo>,
) -> Result<()> {
    output.extend_from_slice(SCHEMAS_SECTION_MAGIC);
    output.push(1);
    encode_u32(
        output,
        u32::try_from(schemas.len())
            .map_err(|_| DbError::constraint("schema count exceeds u32"))?,
    );
    for schema in schemas.values() {
        encode_string(output, &schema.name)?;
    }
    Ok(())
}

fn encode_pk_index_roots_section(
    output: &mut Vec<u8>,
    tables: &BTreeMap<String, TableSchema>,
    mut offsets: Option<&mut BTreeMap<String, usize>>,
) -> Result<()> {
    output.extend_from_slice(PK_INDEX_ROOTS_SECTION_MAGIC);
    output.push(1);
    encode_u32(
        output,
        u32::try_from(tables.len())
            .map_err(|_| DbError::constraint("pk index root entry count exceeds u32"))?,
    );
    for table in tables.values() {
        encode_string(output, &table.name)?;
        if let Some(offsets) = offsets.as_deref_mut() {
            offsets.insert(table.name.clone(), output.len());
        }
        encode_u32(output, table.pk_index_root.unwrap_or(0));
    }
    Ok(())
}

fn decode_schemas_section(
    cursor: &mut Cursor<'_>,
    schemas: &mut BTreeMap<String, SchemaInfo>,
) -> Result<()> {
    let section_is_present = cursor
        .bytes
        .get(cursor.offset..cursor.offset + SCHEMAS_SECTION_MAGIC.len())
        .is_some_and(|magic| magic == SCHEMAS_SECTION_MAGIC);
    if !section_is_present {
        return Ok(());
    }
    cursor.offset += SCHEMAS_SECTION_MAGIC.len();
    let version = cursor.read_u8()?;
    if version != 1 {
        return Err(DbError::corruption(format!(
            "unknown schemas section version {version}"
        )));
    }
    let schema_count = cursor.read_u32()?;
    for _ in 0..schema_count {
        let name = cursor.read_string()?;
        schemas.insert(name.clone(), SchemaInfo { name });
    }
    Ok(())
}

fn decode_index_include_columns_section(
    cursor: &mut Cursor<'_>,
    indexes: &mut BTreeMap<String, IndexSchema>,
) -> Result<()> {
    let section_is_present = cursor
        .bytes
        .get(cursor.offset..cursor.offset + INDEX_INCLUDE_COLUMNS_SECTION_MAGIC.len())
        .is_some_and(|magic| magic == INDEX_INCLUDE_COLUMNS_SECTION_MAGIC);
    if !section_is_present {
        return Ok(());
    }
    cursor.offset += INDEX_INCLUDE_COLUMNS_SECTION_MAGIC.len();
    let version = cursor.read_u8()?;
    if version != 1 {
        return Err(DbError::corruption(format!(
            "unknown index include columns section version {version}"
        )));
    }
    let entry_count = cursor.read_u32()?;
    for _ in 0..entry_count {
        let index_name = cursor.read_string()?;
        let include_columns = cursor.read_strings()?;
        let index = indexes.get_mut(&index_name).ok_or_else(|| {
            DbError::corruption(format!(
                "index include metadata referenced unknown index {index_name}"
            ))
        })?;
        index.include_columns = include_columns;
    }
    Ok(())
}

fn decode_full_text_options_section(
    cursor: &mut Cursor<'_>,
    indexes: &mut BTreeMap<String, IndexSchema>,
) -> Result<()> {
    let section_is_present = cursor
        .bytes
        .get(cursor.offset..cursor.offset + FULL_TEXT_OPTIONS_SECTION_MAGIC.len())
        .is_some_and(|magic| magic == FULL_TEXT_OPTIONS_SECTION_MAGIC);
    if !section_is_present {
        return Ok(());
    }
    cursor.offset += FULL_TEXT_OPTIONS_SECTION_MAGIC.len();
    let version = cursor.read_u8()?;
    if version != 1 {
        return Err(DbError::corruption(format!(
            "unknown fulltext options section version {version}"
        )));
    }
    let entry_count = cursor.read_u32()?;
    for _ in 0..entry_count {
        let index_name = cursor.read_string()?;
        let config_bytes_len = cursor.read_u32()? as usize;
        let config_bytes = cursor.read_slice(config_bytes_len)?;
        let config = AnalyzerConfig::from_json(config_bytes)
            .map_err(|error| DbError::corruption(error.message))?;
        let index = indexes.get_mut(&index_name).ok_or_else(|| {
            DbError::corruption(format!(
                "fulltext options metadata referenced unknown index {index_name}"
            ))
        })?;
        if index.kind != IndexKind::FullText {
            return Err(DbError::corruption(format!(
                "fulltext options metadata referenced non-fulltext index {index_name}"
            )));
        }
        index.full_text = Some(config);
    }
    Ok(())
}

#[cfg(test)]
fn drop_index_include_columns_section(payload: &[u8]) -> Result<Vec<u8>> {
    let start = payload
        .windows(INDEX_INCLUDE_COLUMNS_SECTION_MAGIC.len())
        .position(|window| window == INDEX_INCLUDE_COLUMNS_SECTION_MAGIC)
        .ok_or_else(|| DbError::internal("index include columns section not found"))?;
    let mut cursor = Cursor::new(
        payload
            .get(start + INDEX_INCLUDE_COLUMNS_SECTION_MAGIC.len()..)
            .ok_or_else(|| DbError::internal("index include columns section header truncated"))?,
    );
    let _version = cursor.read_u8()?;
    let entry_count = cursor.read_u32()?;
    for _ in 0..entry_count {
        let _index_name = cursor.read_string()?;
        let _include_columns = cursor.read_strings()?;
    }
    let section_len = INDEX_INCLUDE_COLUMNS_SECTION_MAGIC.len() + cursor.offset;
    let end = start
        .checked_add(section_len)
        .ok_or_else(|| DbError::internal("index include section length overflow"))?;
    let mut output = Vec::with_capacity(payload.len().saturating_sub(section_len));
    output.extend_from_slice(
        payload
            .get(..start)
            .ok_or_else(|| DbError::internal("invalid include section start"))?,
    );
    output.extend_from_slice(
        payload
            .get(end..)
            .ok_or_else(|| DbError::internal("invalid include section end"))?,
    );
    Ok(output)
}

fn decode_generated_columns_section(
    cursor: &mut Cursor<'_>,
    tables: &mut BTreeMap<String, TableSchema>,
) -> Result<()> {
    let section_is_versioned = cursor
        .bytes
        .get(cursor.offset..cursor.offset + GENERATED_COLUMNS_SECTION_MAGIC.len())
        .is_some_and(|magic| magic == GENERATED_COLUMNS_SECTION_MAGIC);
    if section_is_versioned {
        cursor.offset += GENERATED_COLUMNS_SECTION_MAGIC.len();
        let version = cursor.read_u8()?;
        if version != 1 {
            return Err(DbError::corruption(format!(
                "unknown generated columns section version {version}"
            )));
        }
    }
    let generated_column_count = cursor.read_u32()?;
    for _ in 0..generated_column_count {
        let table_name = cursor.read_string()?;
        let column_name = cursor.read_string()?;
        let generated_sql = cursor.read_string()?;
        let generated_stored = if section_is_versioned {
            cursor.read_bool()?
        } else {
            true
        };
        let table = tables.get_mut(&table_name).ok_or_else(|| {
            DbError::corruption(format!(
                "generated column metadata referenced unknown table {table_name}"
            ))
        })?;
        let column = table
            .columns
            .iter_mut()
            .find(|column| identifiers_equal(&column.name, &column_name))
            .ok_or_else(|| {
                DbError::corruption(format!(
                    "generated column metadata referenced unknown column {}.{}",
                    table_name, column_name
                ))
            })?;
        column.generated_sql = Some(generated_sql);
        column.generated_stored = generated_stored;
    }
    Ok(())
}

fn decode_spatial_columns_section(
    cursor: &mut Cursor<'_>,
    tables: &mut BTreeMap<String, TableSchema>,
) -> Result<()> {
    let section_is_present = cursor
        .bytes
        .get(cursor.offset..cursor.offset + SPATIAL_COLUMNS_SECTION_MAGIC.len())
        .is_some_and(|magic| magic == SPATIAL_COLUMNS_SECTION_MAGIC);
    if !section_is_present {
        return Ok(());
    }
    cursor.offset += SPATIAL_COLUMNS_SECTION_MAGIC.len();
    let version = cursor.read_u8()?;
    if version != 1 {
        return Err(DbError::corruption(format!(
            "unknown spatial columns section version {version}"
        )));
    }
    let entry_count = cursor.read_u32()?;
    for _ in 0..entry_count {
        let table_name = cursor.read_string()?;
        let column_name = cursor.read_string()?;
        let subtype = decode_spatial_subtype_tag(cursor.read_u8()?)?;
        let dimensions = decode_spatial_dimensions_tag(cursor.read_u8()?)?;
        let srid = i32::try_from(cursor.read_u32()?)
            .map_err(|_| DbError::corruption("spatial SRID exceeds i32"))?;
        let table = tables.get_mut(&table_name).ok_or_else(|| {
            DbError::corruption(format!(
                "spatial column metadata referenced unknown table {table_name}"
            ))
        })?;
        let column = table
            .columns
            .iter_mut()
            .find(|column| identifiers_equal(&column.name, &column_name))
            .ok_or_else(|| {
                DbError::corruption(format!(
                    "spatial column metadata referenced unknown column {}.{}",
                    table_name, column_name
                ))
            })?;
        column.spatial_type = Some(crate::catalog::SpatialTypeInfo {
            subtype,
            dimensions,
            srid,
        });
    }
    Ok(())
}

fn decode_enum_columns_section(
    cursor: &mut Cursor<'_>,
    tables: &mut BTreeMap<String, TableSchema>,
) -> Result<()> {
    let section_is_present = cursor
        .bytes
        .get(cursor.offset..cursor.offset + ENUM_COLUMNS_SECTION_MAGIC.len())
        .is_some_and(|magic| magic == ENUM_COLUMNS_SECTION_MAGIC);
    if !section_is_present {
        return Ok(());
    }
    cursor.offset += ENUM_COLUMNS_SECTION_MAGIC.len();
    let version = cursor.read_u8()?;
    if version != 1 {
        return Err(DbError::corruption(format!(
            "unknown enum columns section version {version}"
        )));
    }
    let entry_count = cursor.read_u32()?;
    for _ in 0..entry_count {
        let table_name = cursor.read_string()?;
        let column_name = cursor.read_string()?;
        let type_id = cursor.read_u64()?;
        let label_count = cursor.read_u32()?;
        let mut labels = Vec::with_capacity(label_count as usize);
        for _ in 0..label_count {
            labels.push(EnumLabel {
                id: cursor.read_u64()?,
                label: cursor.read_string()?,
            });
        }
        let table = tables.get_mut(&table_name).ok_or_else(|| {
            DbError::corruption(format!(
                "enum column metadata referenced unknown table {table_name}"
            ))
        })?;
        let column = table
            .columns
            .iter_mut()
            .find(|column| identifiers_equal(&column.name, &column_name))
            .ok_or_else(|| {
                DbError::corruption(format!(
                    "enum column metadata referenced unknown column {}.{}",
                    table_name, column_name
                ))
            })?;
        column.enum_type = Some(EnumTypeInfo { type_id, labels });
    }
    Ok(())
}

fn decode_pk_index_roots_section(
    cursor: &mut Cursor<'_>,
    tables: &mut BTreeMap<String, TableSchema>,
) -> Result<()> {
    let section_is_present = cursor
        .bytes
        .get(cursor.offset..cursor.offset + PK_INDEX_ROOTS_SECTION_MAGIC.len())
        .is_some_and(|magic| magic == PK_INDEX_ROOTS_SECTION_MAGIC);
    if !section_is_present {
        return Ok(());
    }
    cursor.offset += PK_INDEX_ROOTS_SECTION_MAGIC.len();
    let version = cursor.read_u8()?;
    if version != 1 {
        return Err(DbError::corruption(format!(
            "unknown pk index roots section version {version}"
        )));
    }
    let entry_count = cursor.read_u32()?;
    for _ in 0..entry_count {
        let table_name = cursor.read_string()?;
        let pk_index_root = match cursor.read_u32()? {
            0 => None,
            page_id => Some(page_id),
        };
        let table = tables.get_mut(&table_name).ok_or_else(|| {
            DbError::corruption(format!(
                "pk index root metadata referenced unknown table {table_name}"
            ))
        })?;
        table.pk_index_root = pk_index_root;
    }
    Ok(())
}

