fn from_item_is_all_inner_table_joins(item: &FromItem) -> bool {
    match item {
        FromItem::Table { .. } => true,
        FromItem::Join {
            left,
            right,
            kind: JoinKind::Inner,
            constraint: JoinConstraint::On(_),
        } => from_item_is_all_inner_table_joins(left) && from_item_is_all_inner_table_joins(right),
        _ => false,
    }
}

fn simple_select_item_column_index(
    dataset: &Dataset,
    table: Option<&str>,
    column: &str,
) -> Option<usize> {
    let matches = dataset
        .columns
        .iter()
        .enumerate()
        .filter(|(_, binding)| {
            if !identifiers_equal(&binding.name, column) {
                return false;
            }
            match table {
                Some(table_name) => binding
                    .table
                    .as_deref()
                    .is_some_and(|binding_table| identifiers_equal(binding_table, table_name)),
                None => !binding.hidden,
            }
        })
        .map(|(index, _)| index)
        .collect::<Vec<_>>();
    match matches.as_slice() {
        [index] => Some(*index),
        _ => None,
    }
}

#[allow(clippy::too_many_arguments)]
fn simple_join_projection_plan(
    items: &[SelectItem],
    eval_dataset: &Dataset,
    left_table_name: &str,
    left_alias: &Option<String>,
    left_schema: &TableSchema,
    right_table_name: &str,
    right_alias: &Option<String>,
    right_schema: &TableSchema,
    using_join_columns: &[String],
) -> Option<(Vec<SimpleJoinProjectionSource>, Vec<String>)> {
    let left_binding = left_alias.as_deref().unwrap_or(left_table_name);
    let right_binding = right_alias.as_deref().unwrap_or(right_table_name);
    let mut projection_plan = Vec::new();
    let mut column_names = Vec::new();

    for (index, item) in items.iter().enumerate() {
        match item {
            SelectItem::Wildcard => {
                if !using_join_columns.is_empty() {
                    for using_column in using_join_columns {
                        projection_plan.push(SimpleJoinProjectionSource::Expr(
                            merged_single_column_using_expr(
                                left_binding,
                                right_binding,
                                using_column,
                            ),
                        ));
                        column_names.push(using_column.to_string());
                    }
                    projection_plan.extend(
                        left_schema
                            .columns
                            .iter()
                            .enumerate()
                            .filter(|(_, column)| {
                                !using_join_columns.iter().any(|using_column| {
                                    identifiers_equal(&column.name, using_column)
                                })
                            })
                            .map(|(column_index, _)| {
                                SimpleJoinProjectionSource::Left(column_index)
                            }),
                    );
                    column_names.extend(
                        left_schema
                            .columns
                            .iter()
                            .filter(|column| {
                                !using_join_columns.iter().any(|using_column| {
                                    identifiers_equal(&column.name, using_column)
                                })
                            })
                            .map(|column| column.name.clone()),
                    );
                    projection_plan.extend(
                        right_schema
                            .columns
                            .iter()
                            .enumerate()
                            .filter(|(_, column)| {
                                !using_join_columns.iter().any(|using_column| {
                                    identifiers_equal(&column.name, using_column)
                                })
                            })
                            .map(|(column_index, _)| {
                                SimpleJoinProjectionSource::Right(column_index)
                            }),
                    );
                    column_names.extend(
                        right_schema
                            .columns
                            .iter()
                            .filter(|column| {
                                !using_join_columns.iter().any(|using_column| {
                                    identifiers_equal(&column.name, using_column)
                                })
                            })
                            .map(|column| column.name.clone()),
                    );
                } else {
                    projection_plan.extend(
                        left_schema
                            .columns
                            .iter()
                            .enumerate()
                            .map(|(column_index, _)| {
                                SimpleJoinProjectionSource::Left(column_index)
                            }),
                    );
                    column_names
                        .extend(left_schema.columns.iter().map(|column| column.name.clone()));
                    projection_plan.extend(
                        right_schema
                            .columns
                            .iter()
                            .enumerate()
                            .map(|(column_index, _)| {
                                SimpleJoinProjectionSource::Right(column_index)
                            }),
                    );
                    column_names.extend(
                        right_schema
                            .columns
                            .iter()
                            .map(|column| column.name.clone()),
                    );
                }
            }
            SelectItem::QualifiedWildcard(table_name) => {
                if identifiers_equal(table_name, left_table_name)
                    || identifiers_equal(table_name, left_binding)
                {
                    projection_plan.extend(
                        left_schema
                            .columns
                            .iter()
                            .enumerate()
                            .map(|(column_index, _)| {
                                SimpleJoinProjectionSource::Left(column_index)
                            }),
                    );
                    column_names
                        .extend(left_schema.columns.iter().map(|column| column.name.clone()));
                } else if identifiers_equal(table_name, right_table_name)
                    || identifiers_equal(table_name, right_binding)
                {
                    projection_plan.extend(
                        right_schema
                            .columns
                            .iter()
                            .enumerate()
                            .map(|(column_index, _)| {
                                SimpleJoinProjectionSource::Right(column_index)
                            }),
                    );
                    column_names.extend(
                        right_schema
                            .columns
                            .iter()
                            .map(|column| column.name.clone()),
                    );
                } else {
                    return None;
                }
            }
            SelectItem::Expr { expr, alias } => {
                let source = if let Expr::Column { table, column } = expr {
                    let left_index = left_schema
                        .columns
                        .iter()
                        .position(|candidate| identifiers_equal(&candidate.name, column));
                    let right_index = right_schema
                        .columns
                        .iter()
                        .position(|candidate| identifiers_equal(&candidate.name, column));
                    match table.as_deref() {
                        Some(table_name)
                            if identifiers_equal(table_name, left_table_name)
                                || identifiers_equal(table_name, left_binding) =>
                        {
                            Some(SimpleJoinProjectionSource::Left(left_index?))
                        }
                        Some(table_name)
                            if identifiers_equal(table_name, right_table_name)
                                || identifiers_equal(table_name, right_binding) =>
                        {
                            Some(SimpleJoinProjectionSource::Right(right_index?))
                        }
                        Some(_) => None,
                        None => match (left_index, right_index) {
                            (Some(left_index), None) => {
                                Some(SimpleJoinProjectionSource::Left(left_index))
                            }
                            (None, Some(right_index)) => {
                                Some(SimpleJoinProjectionSource::Right(right_index))
                            }
                            (Some(_), Some(_))
                                if using_join_columns.iter().any(|using_column| {
                                    identifiers_equal(column, using_column)
                                }) =>
                            {
                                Some(SimpleJoinProjectionSource::Expr(
                                    merged_single_column_using_expr(
                                        left_binding,
                                        right_binding,
                                        column,
                                    ),
                                ))
                            }
                            _ => None,
                        },
                    }
                } else if expr_resolves_against_dataset(expr, eval_dataset) {
                    Some(SimpleJoinProjectionSource::Expr(expr.clone()))
                } else {
                    None
                }?;
                projection_plan.push(source);
                column_names.push(
                    alias
                        .clone()
                        .unwrap_or_else(|| infer_expr_name(expr, index + 1)),
                );
            }
        }
    }

    Some((projection_plan, column_names))
}

fn merged_single_column_using_expr(left_binding: &str, right_binding: &str, column: &str) -> Expr {
    Expr::Function {
        name: "coalesce".to_string(),
        args: vec![
            Expr::Column {
                table: Some(left_binding.to_string()),
                column: column.to_string(),
            },
            Expr::Column {
                table: Some(right_binding.to_string()),
                column: column.to_string(),
            },
        ],
    }
}

#[allow(clippy::too_many_arguments)]
fn simple_join_projection_order_by_plan(
    query: &Query,
    projection_items: &[SelectItem],
    projection_plan: &[SimpleJoinProjectionSource],
    column_names: &[String],
    left_table_name: &str,
    left_alias: &Option<String>,
    left_schema: &TableSchema,
    right_table_name: &str,
    right_alias: &Option<String>,
    right_schema: &TableSchema,
) -> Result<Option<Vec<SimpleOrderByPlan>>> {
    if query.order_by.is_empty() {
        return Ok(None);
    }
    let left_binding = TableBindingRef {
        name: left_table_name,
        alias: left_alias,
    };
    let right_binding = TableBindingRef {
        name: right_table_name,
        alias: right_alias,
    };
    let direct_order = query
        .order_by
        .iter()
        .map(|entry| {
            let Expr::Column {
                table: order_table,
                column: order_column,
            } = &entry.expr
            else {
                return None;
            };

            let mut projection_index = None;
            for (index, source) in projection_plan.iter().enumerate() {
                let source_matches = match source {
                    SimpleJoinProjectionSource::Left(column_index) => {
                        identifiers_equal(&left_schema.columns[*column_index].name, order_column)
                            && order_table.as_deref().is_none_or(|qualifier| {
                                matches_table_binding(left_binding, Some(qualifier))
                            })
                    }
                    SimpleJoinProjectionSource::Right(column_index) => {
                        identifiers_equal(&right_schema.columns[*column_index].name, order_column)
                            && order_table.as_deref().is_none_or(|qualifier| {
                                matches_table_binding(right_binding, Some(qualifier))
                            })
                    }
                    SimpleJoinProjectionSource::Expr(_) => false,
                };
                let alias_matches = order_table.is_none()
                    && column_names
                        .get(index)
                        .is_some_and(|candidate| candidate.eq_ignore_ascii_case(order_column));
                if !source_matches && !alias_matches {
                    continue;
                }
                if projection_index.replace(index).is_some() {
                    return None;
                }
            }

            projection_index.map(|projection_index| SimpleOrderByPlan {
                projection_index,
                descending: entry.descending,
                collation: entry.collation.clone(),
            })
        })
        .collect::<Option<Vec<_>>>();
    if direct_order.is_some() {
        return Ok(direct_order);
    }

    Ok(projection_order_by_plan(&query.order_by, projection_items))
}

fn simple_join_eval_row(
    left_values: Option<&[Value]>,
    left_width: usize,
    right_values: Option<&[Value]>,
    right_width: usize,
) -> Vec<Value> {
    let mut values = Vec::with_capacity(left_width + right_width);
    match left_values {
        Some(left_values) => values.extend(left_values.iter().cloned()),
        None => values.extend((0..left_width).map(|_| Value::Null)),
    }
    match right_values {
        Some(right_values) => values.extend(right_values.iter().cloned()),
        None => values.extend((0..right_width).map(|_| Value::Null)),
    }
    values
}

type SimpleJoinHashRows = BTreeMap<Vec<u8>, Vec<(i64, Vec<Value>)>>;

fn simple_join_key_from_indexes(row: &[Value], indexes: &[usize]) -> Result<Option<Vec<u8>>> {
    let join_values = indexes
        .iter()
        .map(|index| {
            row.get(*index)
                .ok_or_else(|| DbError::internal("join row is shorter than table schema"))
        })
        .collect::<Result<Vec<_>>>()?;
    if join_values
        .iter()
        .any(|join_value| matches!(join_value, Value::Null))
    {
        return Ok(None);
    }
    Row::new(join_values.iter().cloned().cloned().collect())
        .encode()
        .map(Some)
}

#[allow(clippy::too_many_arguments)]
fn simple_join_filter_matches(
    runtime: &EngineRuntime,
    filter: Option<&Expr>,
    eval_dataset: &Dataset,
    left_values: Option<&[Value]>,
    left_width: usize,
    right_values: Option<&[Value]>,
    right_width: usize,
    params: &[Value],
) -> Result<bool> {
    let Some(filter) = filter else {
        return Ok(true);
    };
    let joined_values = simple_join_eval_row(left_values, left_width, right_values, right_width);
    Ok(matches!(
        runtime.eval_expr(
            filter,
            eval_dataset,
            &joined_values,
            params,
            &BTreeMap::new(),
            None,
        )?,
        Value::Bool(true)
    ))
}

#[allow(clippy::too_many_arguments)]
fn project_simple_join_row(
    runtime: &EngineRuntime,
    projection_plan: &[SimpleJoinProjectionSource],
    eval_dataset: &Dataset,
    left_values: Option<&[Value]>,
    left_width: usize,
    right_values: Option<&[Value]>,
    right_width: usize,
    params: &[Value],
) -> Result<Vec<Value>> {
    let mut projected = Vec::with_capacity(projection_plan.len());
    let mut joined_values = None::<Vec<Value>>;
    for slot in projection_plan {
        match slot {
            SimpleJoinProjectionSource::Left(index) => {
                let value = left_values
                    .and_then(|row| row.get(*index))
                    .cloned()
                    .unwrap_or(Value::Null);
                projected.push(value);
            }
            SimpleJoinProjectionSource::Right(index) => {
                let value = right_values
                    .and_then(|row| row.get(*index))
                    .cloned()
                    .unwrap_or(Value::Null);
                projected.push(value);
            }
            SimpleJoinProjectionSource::Expr(expr) => {
                let joined_values = joined_values.get_or_insert_with(|| {
                    simple_join_eval_row(left_values, left_width, right_values, right_width)
                });
                projected.push(runtime.eval_expr(
                    expr,
                    eval_dataset,
                    joined_values,
                    params,
                    &BTreeMap::new(),
                    None,
                )?);
            }
        }
    }
    Ok(projected)
}

fn try_project_simple_select_items(
    dataset: &Dataset,
    items: &[SelectItem],
) -> Result<Option<Dataset>> {
    let mut output_columns = Vec::new();
    let mut projection_plan = Vec::<usize>::new();
    for (index, item) in items.iter().enumerate() {
        match item {
            SelectItem::Expr { expr, alias } => {
                let Expr::Column { table, column } = expr else {
                    return Ok(None);
                };
                let Some(source_index) =
                    simple_select_item_column_index(dataset, table.as_deref(), column)
                else {
                    return Ok(None);
                };
                projection_plan.push(source_index);
                output_columns.push(ColumnBinding::visible(
                    None,
                    alias
                        .clone()
                        .unwrap_or_else(|| infer_expr_name(expr, index + 1)),
                ));
            }
            SelectItem::Wildcard => {
                for (source_index, binding) in dataset.columns.iter().enumerate() {
                    if binding.hidden {
                        continue;
                    }
                    projection_plan.push(source_index);
                    output_columns.push(binding.as_output());
                }
            }
            SelectItem::QualifiedWildcard(table) => {
                let mut matched = false;
                for (source_index, binding) in dataset.columns.iter().enumerate() {
                    if binding.hidden || binding.table.as_deref() != Some(table.as_str()) {
                        continue;
                    }
                    projection_plan.push(source_index);
                    output_columns.push(binding.as_output());
                    matched = true;
                }
                if !matched {
                    return Ok(None);
                }
            }
        }
    }

    let mut output_rows = Vec::with_capacity(dataset.rows.len());
    for row in dataset.rows.iter() {
        let mut output_row = Vec::with_capacity(projection_plan.len());
        for source_index in &projection_plan {
            let value = row
                .get(*source_index)
                .ok_or_else(|| DbError::internal("projection source index exceeds row width"))?;
            output_row.push(value.clone());
        }
        output_rows.push(output_row);
    }
    Ok(Some(Dataset::with_rows(output_columns, output_rows)))
}

#[derive(Clone, Copy, Debug)]
struct SimpleTrigramLookup<'a> {
    table_qualifier: Option<&'a str>,
    column_name: &'a str,
    pattern_expr: &'a Expr,
    has_additional_filter: bool,
}

fn simple_trigram_lookup(filter: &Expr) -> Option<SimpleTrigramLookup<'_>> {
    match filter {
        Expr::Like {
            expr,
            pattern,
            escape,
            negated,
            ..
        } if !negated && escape.is_none() => match (&**expr, &**pattern) {
            (Expr::Column { table, column }, pattern @ (Expr::Literal(_) | Expr::Parameter(_))) => {
                Some(SimpleTrigramLookup {
                    table_qualifier: table.as_deref(),
                    column_name: column.as_str(),
                    pattern_expr: pattern,
                    has_additional_filter: false,
                })
            }
            _ => None,
        },
        Expr::Binary {
            left,
            op: BinaryOp::And,
            right,
        } => {
            if let Some(mut lookup) = simple_trigram_lookup(left) {
                lookup.has_additional_filter = true;
                Some(lookup)
            } else {
                simple_trigram_lookup(right).map(|mut lookup| {
                    lookup.has_additional_filter = true;
                    lookup
                })
            }
        }
        _ => None,
    }
}

#[derive(Clone, Copy, Debug)]
struct SimpleFullTextLookup<'a> {
    index_name_expr: &'a Expr,
    query_expr: &'a Expr,
}

fn simple_fulltext_lookup(filter: &Expr) -> Option<SimpleFullTextLookup<'_>> {
    match filter {
        Expr::Function { name, args }
            if name.eq_ignore_ascii_case("fulltext_match") && args.len() == 2 =>
        {
            Some(SimpleFullTextLookup {
                index_name_expr: &args[0],
                query_expr: &args[1],
            })
        }
        Expr::Binary {
            left,
            op: BinaryOp::And,
            right,
        } => simple_fulltext_lookup(left).or_else(|| simple_fulltext_lookup(right)),
        _ => None,
    }
}

#[derive(Clone, Copy, Debug)]
struct SimpleSpatialLookup<'a> {
    table_qualifier: Option<&'a str>,
    column_name: &'a str,
    value_expr: &'a Expr,
    radius_expr: Option<&'a Expr>,
}

#[derive(Clone, Copy, Debug)]
struct SimpleSpatialJoinPredicate<'a> {
    left: QualifiedColumnRef<'a>,
    right: QualifiedColumnRef<'a>,
    radius_expr: Option<&'a Expr>,
}

fn simple_spatial_join_predicate<'a>(
    expr: &'a Expr,
    left_binding: TableBindingRef<'a>,
    right_binding: TableBindingRef<'a>,
) -> Option<SimpleSpatialJoinPredicate<'a>> {
    let Expr::Function { name, args } = expr else {
        return None;
    };
    let lower = name.to_ascii_lowercase();
    let (left, right, radius_expr) = if lower == "st_dwithin" {
        let [left, right, radius] = args.as_slice() else {
            return None;
        };
        if expr_has_column_ref(radius) {
            return None;
        }
        (left, right, Some(radius))
    } else if matches!(
        lower.as_str(),
        "st_intersects" | "st_contains" | "st_within" | "st_equals"
    ) {
        let [left, right] = args.as_slice() else {
            return None;
        };
        (left, right, None)
    } else {
        return None;
    };
    let left_ref = qualified_column_ref_expr(left)?;
    let right_ref = qualified_column_ref_expr(right)?;
    let left_is_left = matches_table_binding(left_binding, left_ref.table);
    let left_is_right = matches_table_binding(right_binding, left_ref.table);
    let right_is_left = matches_table_binding(left_binding, right_ref.table);
    let right_is_right = matches_table_binding(right_binding, right_ref.table);
    if (left_is_left && right_is_right) || (left_is_right && right_is_left) {
        Some(SimpleSpatialJoinPredicate {
            left: left_ref,
            right: right_ref,
            radius_expr,
        })
    } else {
        None
    }
}

fn qualified_column_ref_expr(expr: &Expr) -> Option<QualifiedColumnRef<'_>> {
    let Expr::Column { table, column } = expr else {
        return None;
    };
    Some(QualifiedColumnRef {
        table: table.as_deref(),
        column,
    })
}

fn simple_spatial_lookup(filter: &Expr) -> Option<SimpleSpatialLookup<'_>> {
    match filter {
        Expr::Function { name, args } if name.eq_ignore_ascii_case("st_dwithin") => {
            let [left, right, radius] = args.as_slice() else {
                return None;
            };
            simple_spatial_column_value_pair(left, right).map(
                |(table_qualifier, column_name, value_expr)| SimpleSpatialLookup {
                    table_qualifier,
                    column_name,
                    value_expr,
                    radius_expr: Some(radius),
                },
            )
        }
        Expr::Function { name, args }
            if matches!(
                name.to_ascii_lowercase().as_str(),
                "st_intersects" | "st_contains" | "st_within" | "st_equals"
            ) =>
        {
            let [left, right] = args.as_slice() else {
                return None;
            };
            simple_spatial_column_value_pair(left, right).map(
                |(table_qualifier, column_name, value_expr)| SimpleSpatialLookup {
                    table_qualifier,
                    column_name,
                    value_expr,
                    radius_expr: None,
                },
            )
        }
        Expr::Binary {
            left,
            op: BinaryOp::And,
            right,
        } => simple_spatial_lookup(left).or_else(|| simple_spatial_lookup(right)),
        _ => None,
    }
}

fn simple_spatial_column_value_pair<'a>(
    left: &'a Expr,
    right: &'a Expr,
) -> Option<(Option<&'a str>, &'a str, &'a Expr)> {
    match (left, right) {
        (Expr::Column { table, column }, value) if !expr_has_column_ref(value) => {
            Some((table.as_deref(), column.as_str(), value))
        }
        (value, Expr::Column { table, column }) if !expr_has_column_ref(value) => {
            Some((table.as_deref(), column.as_str(), value))
        }
        _ => None,
    }
}

fn expr_has_column_ref(expr: &Expr) -> bool {
    match expr {
        Expr::Column { .. } => true,
        Expr::Unary { expr, .. }
        | Expr::Cast { expr, .. }
        | Expr::IsNull { expr, .. }
        | Expr::Collate { expr, .. } => expr_has_column_ref(expr),
        Expr::Binary { left, right, .. } => expr_has_column_ref(left) || expr_has_column_ref(right),
        Expr::Between {
            expr, low, high, ..
        } => expr_has_column_ref(expr) || expr_has_column_ref(low) || expr_has_column_ref(high),
        Expr::InList { expr, items, .. } => {
            expr_has_column_ref(expr) || items.iter().any(expr_has_column_ref)
        }
        Expr::Like {
            expr,
            pattern,
            escape,
            ..
        } => {
            expr_has_column_ref(expr)
                || expr_has_column_ref(pattern)
                || escape.as_deref().is_some_and(expr_has_column_ref)
        }
        Expr::Function { args, .. } => args.iter().any(expr_has_column_ref),
        Expr::Aggregate { args, order_by, .. } => {
            args.iter().any(expr_has_column_ref)
                || order_by
                    .iter()
                    .any(|order| expr_has_column_ref(&order.expr))
        }
        Expr::Case {
            operand,
            branches,
            else_expr,
        } => {
            operand.as_deref().is_some_and(expr_has_column_ref)
                || branches.iter().any(|(condition, value)| {
                    expr_has_column_ref(condition) || expr_has_column_ref(value)
                })
                || else_expr.as_deref().is_some_and(expr_has_column_ref)
        }
        Expr::Row(items) => items.iter().any(expr_has_column_ref),
        Expr::InSubquery { expr, .. } | Expr::CompareSubquery { expr, .. } => {
            expr_has_column_ref(expr)
        }
        Expr::Literal(_)
        | Expr::Parameter(_)
        | Expr::RowNumber { .. }
        | Expr::WindowFunction { .. }
        | Expr::ScalarSubquery(_)
        | Expr::Exists(_) => false,
    }
}

fn expr_contains_aggregate(expr: &Expr) -> bool {
    match expr {
        Expr::Aggregate { .. } => true,
        Expr::Unary { expr, .. } | Expr::Collate { expr, .. } => expr_contains_aggregate(expr),
        Expr::Binary { left, right, .. } => {
            expr_contains_aggregate(left) || expr_contains_aggregate(right)
        }
        Expr::Between {
            expr, low, high, ..
        } => {
            expr_contains_aggregate(expr)
                || expr_contains_aggregate(low)
                || expr_contains_aggregate(high)
        }
        Expr::InList { expr, items, .. } => {
            expr_contains_aggregate(expr) || items.iter().any(expr_contains_aggregate)
        }
        Expr::InSubquery { expr, .. } => expr_contains_aggregate(expr),
        Expr::CompareSubquery { expr, .. } => expr_contains_aggregate(expr),
        Expr::ScalarSubquery(_) | Expr::Exists(_) => false,
        Expr::Like {
            expr,
            pattern,
            escape,
            ..
        } => {
            expr_contains_aggregate(expr)
                || expr_contains_aggregate(pattern)
                || escape.as_deref().is_some_and(expr_contains_aggregate)
        }
        Expr::IsNull { expr, .. } => expr_contains_aggregate(expr),
        Expr::Function { args, .. } => args.iter().any(expr_contains_aggregate),
        Expr::RowNumber { .. } | Expr::WindowFunction { .. } => false,
        Expr::Case {
            operand,
            branches,
            else_expr,
        } => {
            operand.as_deref().is_some_and(expr_contains_aggregate)
                || branches.iter().any(|(left, right)| {
                    expr_contains_aggregate(left) || expr_contains_aggregate(right)
                })
                || else_expr.as_deref().is_some_and(expr_contains_aggregate)
        }
        Expr::Row(items) => items.iter().any(expr_contains_aggregate),
        Expr::Cast { expr, .. } => expr_contains_aggregate(expr),
        Expr::Literal(_) | Expr::Column { .. } | Expr::Parameter(_) => false,
    }
}

fn expr_contains_runtime_extension_aggregate(runtime: &EngineRuntime, expr: &Expr) -> Result<bool> {
    Ok(match expr {
        Expr::Aggregate { .. } => true,
        Expr::Function { name, args } => {
            crate::extensions::runtime_has_aggregate_function(runtime, name)?
                || args.iter().try_fold(false, |found, arg| {
                    if found {
                        Ok(true)
                    } else {
                        expr_contains_runtime_extension_aggregate(runtime, arg)
                    }
                })?
        }
        Expr::Unary { expr, .. } | Expr::Collate { expr, .. } | Expr::Cast { expr, .. } => {
            expr_contains_runtime_extension_aggregate(runtime, expr)?
        }
        Expr::Binary { left, right, .. } => {
            expr_contains_runtime_extension_aggregate(runtime, left)?
                || expr_contains_runtime_extension_aggregate(runtime, right)?
        }
        Expr::Between {
            expr, low, high, ..
        } => {
            expr_contains_runtime_extension_aggregate(runtime, expr)?
                || expr_contains_runtime_extension_aggregate(runtime, low)?
                || expr_contains_runtime_extension_aggregate(runtime, high)?
        }
        Expr::InList { expr, items, .. } => {
            expr_contains_runtime_extension_aggregate(runtime, expr)?
                || items.iter().try_fold(false, |found, item| {
                    if found {
                        Ok(true)
                    } else {
                        expr_contains_runtime_extension_aggregate(runtime, item)
                    }
                })?
        }
        Expr::InSubquery { expr, .. } | Expr::CompareSubquery { expr, .. } => {
            expr_contains_runtime_extension_aggregate(runtime, expr)?
        }
        Expr::Like {
            expr,
            pattern,
            escape,
            ..
        } => {
            expr_contains_runtime_extension_aggregate(runtime, expr)?
                || expr_contains_runtime_extension_aggregate(runtime, pattern)?
                || escape
                    .as_deref()
                    .map(|expr| expr_contains_runtime_extension_aggregate(runtime, expr))
                    .transpose()?
                    .unwrap_or(false)
        }
        Expr::IsNull { expr, .. } => expr_contains_runtime_extension_aggregate(runtime, expr)?,
        Expr::Case {
            operand,
            branches,
            else_expr,
        } => {
            operand
                .as_deref()
                .map(|expr| expr_contains_runtime_extension_aggregate(runtime, expr))
                .transpose()?
                .unwrap_or(false)
                || branches.iter().try_fold(false, |found, (left, right)| {
                    if found {
                        Ok(true)
                    } else {
                        Ok(expr_contains_runtime_extension_aggregate(runtime, left)?
                            || expr_contains_runtime_extension_aggregate(runtime, right)?)
                    }
                })?
                || else_expr
                    .as_deref()
                    .map(|expr| expr_contains_runtime_extension_aggregate(runtime, expr))
                    .transpose()?
                    .unwrap_or(false)
        }
        Expr::Row(items) => items.iter().try_fold(false, |found, item| {
            if found {
                Ok(true)
            } else {
                expr_contains_runtime_extension_aggregate(runtime, item)
            }
        })?,
        Expr::ScalarSubquery(_) | Expr::Exists(_) => false,
        Expr::RowNumber { .. }
        | Expr::WindowFunction { .. }
        | Expr::Literal(_)
        | Expr::Column { .. }
        | Expr::Parameter(_) => false,
    })
}

fn expr_contains_window(expr: &Expr) -> bool {
    match expr {
        Expr::RowNumber { .. } | Expr::WindowFunction { .. } => true,
        Expr::Unary { expr, .. }
        | Expr::Cast { expr, .. }
        | Expr::IsNull { expr, .. }
        | Expr::Collate { expr, .. } => expr_contains_window(expr),
        Expr::Binary { left, right, .. } => {
            expr_contains_window(left) || expr_contains_window(right)
        }
        Expr::Between {
            expr, low, high, ..
        } => expr_contains_window(expr) || expr_contains_window(low) || expr_contains_window(high),
        Expr::InList { expr, items, .. } => {
            expr_contains_window(expr) || items.iter().any(expr_contains_window)
        }
        Expr::Like {
            expr,
            pattern,
            escape,
            ..
        } => {
            expr_contains_window(expr)
                || expr_contains_window(pattern)
                || escape.as_ref().is_some_and(|e| expr_contains_window(e))
        }
        Expr::Function { args, .. } => args.iter().any(expr_contains_window),
        Expr::Case {
            operand,
            branches,
            else_expr,
        } => {
            operand.as_ref().is_some_and(|e| expr_contains_window(e))
                || branches
                    .iter()
                    .any(|(c, v)| expr_contains_window(c) || expr_contains_window(v))
                || else_expr.as_ref().is_some_and(|e| expr_contains_window(e))
        }
        Expr::Row(items) => items.iter().any(expr_contains_window),
        Expr::Aggregate { args, .. } => args.iter().any(expr_contains_window),
        Expr::InSubquery { .. }
        | Expr::CompareSubquery { .. }
        | Expr::ScalarSubquery(_)
        | Expr::Exists(_) => false,
        Expr::Literal(_) | Expr::Column { .. } | Expr::Parameter(_) => false,
    }
}

#[derive(Clone, Debug)]
struct JoinUsingColumn {
    name: String,
    left_index: usize,
    right_index: usize,
}

struct JoinEvalContext<'a> {
    dataset: &'a Dataset,
    runtime: &'a EngineRuntime,
    params: &'a [Value],
    ctes: &'a BTreeMap<String, Dataset>,
}

fn visible_column_names(dataset: &Dataset) -> Vec<String> {
    let mut names = Vec::<String>::new();
    for binding in dataset.columns.iter().filter(|binding| !binding.hidden) {
        if !names
            .iter()
            .any(|name| identifiers_equal(name, &binding.name))
        {
            names.push(binding.name.clone());
        }
    }
    names
}

fn visible_column_exists(dataset: &Dataset, column: &str) -> bool {
    dataset
        .columns
        .iter()
        .any(|binding| !binding.hidden && identifiers_equal(&binding.name, column))
}

fn resolve_visible_join_column(
    dataset: &Dataset,
    column: &str,
    join_form: &str,
    side: &str,
) -> Result<usize> {
    let matches = dataset
        .columns
        .iter()
        .enumerate()
        .filter(|(_, binding)| !binding.hidden && identifiers_equal(&binding.name, column))
        .collect::<Vec<_>>();
    match matches.as_slice() {
        [single] => Ok(single.0),
        [] => Err(DbError::sql(format!(
            "{join_form} column {column} does not exist in {side} input"
        ))),
        _ => Err(DbError::sql(format!(
            "{join_form} column {column} is ambiguous in {side} input"
        ))),
    }
}

fn resolve_join_using_columns(
    left: &Dataset,
    right: &Dataset,
    constraint: &JoinConstraint,
) -> Result<Vec<JoinUsingColumn>> {
    match constraint {
        JoinConstraint::On(_) => Ok(Vec::new()),
        JoinConstraint::Using(columns) => {
            let mut pairs = Vec::with_capacity(columns.len());
            let mut seen = Vec::<String>::new();
            for column in columns {
                if seen
                    .iter()
                    .any(|existing| identifiers_equal(existing, column))
                {
                    return Err(DbError::sql(format!(
                        "JOIN USING column {column} specified more than once"
                    )));
                }
                let left_index = resolve_visible_join_column(left, column, "JOIN USING", "left")?;
                let right_index =
                    resolve_visible_join_column(right, column, "JOIN USING", "right")?;
                pairs.push(JoinUsingColumn {
                    name: left.columns[left_index].name.clone(),
                    left_index,
                    right_index,
                });
                seen.push(column.clone());
            }
            Ok(pairs)
        }
        JoinConstraint::Natural => {
            let mut pairs = Vec::new();
            for column in visible_column_names(left) {
                if !visible_column_exists(right, &column) {
                    continue;
                }
                let left_index =
                    resolve_visible_join_column(left, &column, "NATURAL JOIN", "left")?;
                let right_index =
                    resolve_visible_join_column(right, &column, "NATURAL JOIN", "right")?;
                pairs.push(JoinUsingColumn {
                    name: left.columns[left_index].name.clone(),
                    left_index,
                    right_index,
                });
            }
            Ok(pairs)
        }
    }
}

fn resolve_join_using_columns_for_schemas(
    left_columns: &[ColumnBinding],
    right_columns: &[ColumnBinding],
    constraint: &JoinConstraint,
    _left_table: &TableSchema,
    _right_table: &TableSchema,
) -> Result<Vec<JoinUsingColumn>> {
    match constraint {
        JoinConstraint::Using(names) => {
            let mut result = Vec::new();
            for name in names {
                let left_idx = left_columns
                    .iter()
                    .position(|c| identifiers_equal(&c.name, name))
                    .ok_or_else(|| {
                        DbError::sql(format!("column \"{name}\" not found in left table"))
                    })?;
                let right_idx = right_columns
                    .iter()
                    .position(|c| identifiers_equal(&c.name, name))
                    .ok_or_else(|| {
                        DbError::sql(format!("column \"{name}\" not found in right table"))
                    })?;
                result.push(JoinUsingColumn {
                    name: left_columns[left_idx].name.clone(),
                    left_index: left_idx,
                    right_index: right_idx,
                });
            }
            Ok(result)
        }
        JoinConstraint::Natural => {
            let mut result = Vec::new();
            for lc in left_columns.iter() {
                if let Some(right_idx) = right_columns
                    .iter()
                    .position(|rc| identifiers_equal(&rc.name, &lc.name))
                {
                    let left_idx = left_columns
                        .iter()
                        .position(|c| identifiers_equal(&c.name, &lc.name))
                        .ok_or_else(|| {
                            DbError::internal(
                                "internal: NATURAL join column is missing on left table",
                            )
                        })?;
                    result.push(JoinUsingColumn {
                        name: left_columns[left_idx].name.clone(),
                        left_index: left_idx,
                        right_index: right_idx,
                    });
                }
            }
            Ok(result)
        }
        JoinConstraint::On(_) => Ok(Vec::new()),
    }
}

fn join_output_columns(
    left: &Dataset,
    right: &Dataset,
    using_columns: &[JoinUsingColumn],
) -> Vec<ColumnBinding> {
    if using_columns.is_empty() {
        let mut columns = left.columns.clone();
        columns.extend(right.columns.clone());
        return columns;
    }

    let left_hidden = using_columns
        .iter()
        .map(|column| column.left_index)
        .collect::<BTreeSet<_>>();
    let right_hidden = using_columns
        .iter()
        .map(|column| column.right_index)
        .collect::<BTreeSet<_>>();

    let mut columns =
        Vec::with_capacity(using_columns.len() + left.columns.len() + right.columns.len());
    for column in using_columns {
        columns.push(ColumnBinding::visible(None, column.name.clone()));
    }
    for (index, binding) in left.columns.iter().enumerate() {
        let mut binding = binding.clone();
        if left_hidden.contains(&index) {
            binding.hidden = true;
        }
        columns.push(binding);
    }
    for (index, binding) in right.columns.iter().enumerate() {
        let mut binding = binding.clone();
        if right_hidden.contains(&index) {
            binding.hidden = true;
        }
        columns.push(binding);
    }
    columns
}

fn merged_join_value(left: &Value, right: &Value) -> Value {
    if matches!(left, Value::Null) {
        right.clone()
    } else {
        left.clone()
    }
}

fn join_output_row(
    left_row: &[Value],
    right_row: &[Value],
    using_columns: &[JoinUsingColumn],
) -> Result<Vec<Value>> {
    if using_columns.is_empty() {
        let mut row = left_row.to_vec();
        row.extend_from_slice(right_row);
        return Ok(row);
    }

    let mut row = Vec::with_capacity(using_columns.len() + left_row.len() + right_row.len());
    for column in using_columns {
        let left_value = left_row
            .get(column.left_index)
            .ok_or_else(|| DbError::internal("left join row is shorter than its bindings"))?;
        let right_value = right_row
            .get(column.right_index)
            .ok_or_else(|| DbError::internal("right join row is shorter than its bindings"))?;
        row.push(merged_join_value(left_value, right_value));
    }
    row.extend_from_slice(left_row);
    row.extend_from_slice(right_row);
    Ok(row)
}

fn join_rows_match(
    constraint: &JoinConstraint,
    using_columns: &[JoinUsingColumn],
    eval_row: &[Value],
    left_row: &[Value],
    right_row: &[Value],
    context: &JoinEvalContext<'_>,
) -> Result<bool> {
    match constraint {
        JoinConstraint::On(on) => Ok(matches!(
            context.runtime.eval_expr(
                on,
                context.dataset,
                eval_row,
                context.params,
                context.ctes,
                None
            )?,
            Value::Bool(true)
        )),
        JoinConstraint::Using(_) | JoinConstraint::Natural => {
            for column in using_columns {
                let left_value = left_row.get(column.left_index).ok_or_else(|| {
                    DbError::internal("left join row is shorter than its bindings")
                })?;
                let right_value = right_row.get(column.right_index).ok_or_else(|| {
                    DbError::internal("right join row is shorter than its bindings")
                })?;
                if matches!(left_value, Value::Null) || matches!(right_value, Value::Null) {
                    return Ok(false);
                }
                if compare_values(left_value, right_value)? != std::cmp::Ordering::Equal {
                    return Ok(false);
                }
            }
            Ok(true)
        }
    }
}

fn nested_loop_join(
    left: Dataset,
    right: Dataset,
    kind: JoinKind,
    constraint: &JoinConstraint,
    runtime: &EngineRuntime,
    params: &[Value],
    ctes: &BTreeMap<String, Dataset>,
) -> Result<Dataset> {
    let using_columns = resolve_join_using_columns(&left, &right, constraint)?;

    let mut eval_columns = left.columns.clone();
    eval_columns.extend(right.columns.clone());
    let eval_dataset = Dataset::with_rows(eval_columns, Vec::new());
    let eval_context = JoinEvalContext {
        dataset: &eval_dataset,
        runtime,
        params,
        ctes,
    };
    let columns = join_output_columns(&left, &right, &using_columns);
    let mut rows = Vec::new();
    let mut matched_right = vec![false; right.rows.len()];
    let left_nulls = vec![Value::Null; left.columns.len()];
    let right_nulls = vec![Value::Null; right.columns.len()];
    for left_row in left.rows.iter() {
        let mut matched = false;
        for (right_index, right_row) in right.rows.iter().enumerate() {
            let mut eval_row = left_row.clone();
            eval_row.extend(right_row.clone());
            if join_rows_match(
                constraint,
                &using_columns,
                &eval_row,
                left_row,
                right_row,
                &eval_context,
            )? {
                matched = true;
                matched_right[right_index] = true;
                rows.push(join_output_row(left_row, right_row, &using_columns)?);
            }
        }
        if !matched && matches!(kind, JoinKind::Left | JoinKind::Full) {
            rows.push(join_output_row(left_row, &right_nulls, &using_columns)?);
        }
    }
    if matches!(kind, JoinKind::Right | JoinKind::Full) {
        for (matched, right_row) in matched_right.iter().zip(right.rows.iter()) {
            if !matched {
                rows.push(join_output_row(&left_nulls, right_row, &using_columns)?);
            }
        }
    }
    Ok(Dataset::with_rows(columns, rows))
}

impl EngineRuntime {
    fn evaluate_set_operation(
        &self,
        op: crate::sql::ast::SetOperation,
        all: bool,
        left: Dataset,
        right: Dataset,
    ) -> Result<Dataset> {
        if left.columns.len() != right.columns.len() {
            return Err(DbError::sql(
                "set operations require matching column counts",
            ));
        }
        let columns = left.columns.clone();
        let left_rows = left.into_rows();
        let right_rows = right.into_rows();
        let rows = match op {
            crate::sql::ast::SetOperation::Union => {
                let mut rows = left_rows;
                rows.extend(right_rows);
                if !all {
                    deduplicate_rows(rows)?
                } else {
                    rows
                }
            }
            crate::sql::ast::SetOperation::Intersect => {
                let right_counts = count_row_identities(&right_rows)?;
                let mut rows = Vec::new();
                if all {
                    let mut remaining = right_counts;
                    for row in left_rows {
                        let identity = row_identity(&row)?;
                        if consume_row_identity_count(&mut remaining, &identity) {
                            rows.push(row);
                        }
                    }
                } else {
                    for row in left_rows {
                        let identity = row_identity(&row)?;
                        if right_counts.contains_key(&identity) {
                            rows.push(row);
                        }
                    }
                    rows = deduplicate_rows(rows)?;
                }
                rows
            }
            crate::sql::ast::SetOperation::Except => {
                let right_counts = count_row_identities(&right_rows)?;
                let mut rows = Vec::new();
                if all {
                    let mut remaining = right_counts;
                    for row in left_rows {
                        let identity = row_identity(&row)?;
                        if !consume_row_identity_count(&mut remaining, &identity) {
                            rows.push(row);
                        }
                    }
                } else {
                    for row in left_rows {
                        let identity = row_identity(&row)?;
                        if !right_counts.contains_key(&identity) {
                            rows.push(row);
                        }
                    }
                    rows = deduplicate_rows(rows)?;
                }
                rows
            }
        };
        Ok(Dataset::with_rows(columns, rows))
    }

    fn project_dataset(
        &self,
        dataset: &Dataset,
        items: &[SelectItem],
        params: &[Value],
        ctes: &BTreeMap<String, Dataset>,
        excluded: Option<&Dataset>,
    ) -> Result<Dataset> {
        if !self.security_masks_active()? {
            if let Some(projected) = try_project_simple_select_items(dataset, items)? {
                return Ok(projected);
            }
        }
        let window_values = items
            .iter()
            .map(|item| match item {
                SelectItem::Expr {
                    expr:
                        Expr::RowNumber {
                            partition_by,
                            order_by,
                            frame,
                        },
                    ..
                } => self
                    .compute_row_number_values(
                        dataset,
                        partition_by,
                        order_by,
                        frame.as_ref(),
                        params,
                        ctes,
                    )
                    .map(Some),
                SelectItem::Expr {
                    expr:
                        Expr::WindowFunction {
                            name,
                            args,
                            partition_by,
                            order_by,
                            frame,
                            distinct,
                            star,
                        },
                    ..
                } => self
                    .compute_window_function_values(
                        dataset,
                        name,
                        args,
                        partition_by,
                        order_by,
                        frame.as_ref(),
                        *distinct,
                        *star,
                        params,
                        ctes,
                    )
                    .map(Some),
                _ => Ok(None),
            })
            .collect::<Result<Vec<_>>>()?;
        let mut columns = Vec::new();
        for (index, item) in items.iter().enumerate() {
            match item {
                SelectItem::Expr { expr, alias } => columns.push(ColumnBinding::visible(
                    None,
                    alias
                        .clone()
                        .unwrap_or_else(|| infer_expr_name(expr, index + 1)),
                )),
                SelectItem::Wildcard => columns.extend(
                    dataset
                        .columns
                        .iter()
                        .filter(|binding| !binding.hidden)
                        .map(ColumnBinding::as_output),
                ),
                SelectItem::QualifiedWildcard(table) => columns.extend(
                    dataset
                        .columns
                        .iter()
                        .filter(|column| {
                            !column.hidden && column.table.as_deref() == Some(table.as_str())
                        })
                        .map(ColumnBinding::as_output),
                ),
            }
        }
        let mut rows = Vec::with_capacity(dataset.rows.len());
        for (row_index, row) in dataset.rows.iter().enumerate() {
            let mut output = Vec::new();
            for (item_index, item) in items.iter().enumerate() {
                match item {
                    SelectItem::Expr { expr, .. } => match expr {
                        Expr::RowNumber { .. } | Expr::WindowFunction { .. } => output.push(
                            window_values[item_index]
                                .as_ref()
                                .and_then(|values| values.get(row_index))
                                .cloned()
                                .ok_or_else(|| {
                                    DbError::internal("window-function values were not precomputed")
                                })?,
                        ),
                        Expr::Column { table, column } if excluded.is_none() => {
                            let binding = dataset
                                .columns
                                .iter()
                                .find(|binding| {
                                    identifiers_equal(&binding.name, column)
                                        && match table {
                                            Some(table) => binding
                                                .table
                                                .as_deref()
                                                .is_some_and(|name| identifiers_equal(name, table)),
                                            None => true,
                                        }
                                })
                                .cloned()
                                .unwrap_or_else(|| {
                                    ColumnBinding::visible(table.clone(), column.clone())
                                });
                            let value =
                                self.eval_expr(expr, dataset, row, params, ctes, excluded)?;
                            output.push(self.masked_output_value(
                                &binding, &value, dataset, row, params, ctes,
                            )?);
                        }
                        _ => {
                            output.push(self.eval_expr(expr, dataset, row, params, ctes, excluded)?)
                        }
                    },
                    SelectItem::Wildcard => {
                        for (binding, value) in dataset.columns.iter().zip(row) {
                            if !binding.hidden {
                                output.push(self.masked_output_value(
                                    binding, value, dataset, row, params, ctes,
                                )?);
                            }
                        }
                    }
                    SelectItem::QualifiedWildcard(table) => {
                        for (binding, value) in dataset.columns.iter().zip(row) {
                            if !binding.hidden && binding.table.as_deref() == Some(table.as_str()) {
                                output.push(self.masked_output_value(
                                    binding, value, dataset, row, params, ctes,
                                )?);
                            }
                        }
                    }
                }
            }
            rows.push(output);
        }
        Ok(Dataset::with_rows(columns, rows))
    }

    fn compute_row_number_values(
        &self,
        dataset: &Dataset,
        partition_by: &[Expr],
        order_by: &[crate::sql::ast::OrderBy],
        _frame: Option<&crate::sql::ast::WindowFrame>,
        params: &[Value],
        ctes: &BTreeMap<String, Dataset>,
    ) -> Result<Vec<Value>> {
        let mut partitions = BTreeMap::<Vec<u8>, Vec<usize>>::new();
        for (row_index, row) in dataset.rows.iter().enumerate() {
            let key = if partition_by.is_empty() {
                vec![0]
            } else {
                let values = partition_by
                    .iter()
                    .map(|expr| self.eval_expr(expr, dataset, row, params, ctes, None))
                    .collect::<Result<Vec<_>>>()?;
                row_identity(&values)?
            };
            partitions.entry(key).or_default().push(row_index);
        }

        let mut row_numbers = vec![Value::Null; dataset.rows.len()];
        for indices in partitions.into_values() {
            let mut sorted = indices;
            sorted.sort_by(|left, right| {
                for order in order_by {
                    let left_value = self
                        .eval_expr(
                            &order.expr,
                            dataset,
                            &dataset.rows[*left],
                            params,
                            ctes,
                            None,
                        )
                        .unwrap_or(Value::Null);
                    let right_value = self
                        .eval_expr(
                            &order.expr,
                            dataset,
                            &dataset.rows[*right],
                            params,
                            ctes,
                            None,
                        )
                        .unwrap_or(Value::Null);
                    let ordering = compare_values(&left_value, &right_value)
                        .unwrap_or(std::cmp::Ordering::Equal);
                    if ordering != std::cmp::Ordering::Equal {
                        return if order.descending {
                            ordering.reverse()
                        } else {
                            ordering
                        };
                    }
                }
                left.cmp(right)
            });

            for (ordinal, row_index) in sorted.into_iter().enumerate() {
                row_numbers[row_index] = Value::Int64((ordinal + 1) as i64);
            }
        }
        Ok(row_numbers)
    }

    #[allow(clippy::too_many_arguments)]
    fn compute_window_function_values(
        &self,
        dataset: &Dataset,
        name: &str,
        args: &[Expr],
        partition_by: &[Expr],
        order_by: &[crate::sql::ast::OrderBy],
        _frame: Option<&crate::sql::ast::WindowFrame>,
        _distinct: bool,
        _star: bool,
        params: &[Value],
        ctes: &BTreeMap<String, Dataset>,
    ) -> Result<Vec<Value>> {
        let mut partitions = BTreeMap::<Vec<u8>, Vec<usize>>::new();
        for (row_index, row) in dataset.rows.iter().enumerate() {
            let key = if partition_by.is_empty() {
                vec![0]
            } else {
                let values = partition_by
                    .iter()
                    .map(|expr| self.eval_expr(expr, dataset, row, params, ctes, None))
                    .collect::<Result<Vec<_>>>()?;
                row_identity(&values)?
            };
            partitions.entry(key).or_default().push(row_index);
        }

        let mut results = vec![Value::Null; dataset.rows.len()];
        for indices in partitions.into_values() {
            let mut sorted = indices;
            sorted.sort_by(|left, right| {
                for order in order_by {
                    let left_value = self
                        .eval_expr(
                            &order.expr,
                            dataset,
                            &dataset.rows[*left],
                            params,
                            ctes,
                            None,
                        )
                        .unwrap_or(Value::Null);
                    let right_value = self
                        .eval_expr(
                            &order.expr,
                            dataset,
                            &dataset.rows[*right],
                            params,
                            ctes,
                            None,
                        )
                        .unwrap_or(Value::Null);
                    let ordering = compare_values(&left_value, &right_value)
                        .unwrap_or(std::cmp::Ordering::Equal);
                    if ordering != std::cmp::Ordering::Equal {
                        return if order.descending {
                            ordering.reverse()
                        } else {
                            ordering
                        };
                    }
                }
                left.cmp(right)
            });

            let order_keys = sorted
                .iter()
                .map(|row_index| {
                    order_by
                        .iter()
                        .map(|order| {
                            self.eval_expr(
                                &order.expr,
                                dataset,
                                &dataset.rows[*row_index],
                                params,
                                ctes,
                                None,
                            )
                        })
                        .collect::<Result<Vec<_>>>()
                })
                .collect::<Result<Vec<_>>>()?;
            let (peer_starts, peer_ends) = compute_window_peer_bounds(&order_keys)?;

            match name {
                "rank" => {
                    if _distinct || _star {
                        return Err(DbError::sql("RANK does not support DISTINCT or *"));
                    }
                    let mut current_rank = 1_i64;
                    for (ordinal, row_index) in sorted.iter().enumerate() {
                        if ordinal > 0
                            && !window_order_keys_equal(
                                &order_keys[ordinal - 1],
                                &order_keys[ordinal],
                            )?
                        {
                            current_rank = (ordinal + 1) as i64;
                        }
                        results[*row_index] = Value::Int64(current_rank);
                    }
                }
                "dense_rank" => {
                    if _distinct || _star {
                        return Err(DbError::sql("DENSE_RANK does not support DISTINCT or *"));
                    }
                    let mut current_rank = 1_i64;
                    for (ordinal, row_index) in sorted.iter().enumerate() {
                        if ordinal > 0
                            && !window_order_keys_equal(
                                &order_keys[ordinal - 1],
                                &order_keys[ordinal],
                            )?
                        {
                            current_rank += 1;
                        }
                        results[*row_index] = Value::Int64(current_rank);
                    }
                }
                "percent_rank" => {
                    if _distinct || _star || !args.is_empty() {
                        return Err(DbError::sql("PERCENT_RANK expects no arguments"));
                    }
                    if sorted.len() == 1 {
                        results[sorted[0]] = Value::Float64(0.0);
                        continue;
                    }
                    let mut current_rank = 1_i64;
                    let denominator = (sorted.len() - 1) as f64;
                    for (ordinal, row_index) in sorted.iter().enumerate() {
                        if ordinal > 0
                            && !window_order_keys_equal(
                                &order_keys[ordinal - 1],
                                &order_keys[ordinal],
                            )?
                        {
                            current_rank = (ordinal + 1) as i64;
                        }
                        let value = (current_rank - 1) as f64 / denominator;
                        results[*row_index] = Value::Float64(value);
                    }
                }
                "cume_dist" => {
                    if _distinct || _star || !args.is_empty() {
                        return Err(DbError::sql("CUME_DIST expects no arguments"));
                    }
                    let partition_len = sorted.len() as f64;
                    let mut ordinal = 0_usize;
                    while ordinal < sorted.len() {
                        let peer_end = peer_ends[ordinal];
                        let value = Value::Float64((peer_end + 1) as f64 / partition_len);
                        for peer_ordinal in ordinal..=peer_end {
                            results[sorted[peer_ordinal]] = value.clone();
                        }
                        ordinal = peer_end + 1;
                    }
                }
                "ntile" => {
                    if _distinct || _star || args.len() != 1 {
                        return Err(DbError::sql("NTILE expects exactly 1 argument"));
                    }
                    let first_row = dataset
                        .rows
                        .get(sorted[0])
                        .map(Vec::as_slice)
                        .ok_or_else(|| DbError::internal("window row index is invalid"))?;
                    let buckets = match self
                        .eval_expr(&args[0], dataset, first_row, params, ctes, None)?
                    {
                        Value::Int64(value) if value > 0 => usize::try_from(value)
                            .map_err(|_| DbError::sql("NTILE bucket count is out of range"))?,
                        Value::Int64(_) => {
                            return Err(DbError::sql("NTILE bucket count must be greater than 0"))
                        }
                        Value::Null => {
                            return Err(DbError::sql("NTILE bucket count cannot be NULL"))
                        }
                        other => {
                            return Err(DbError::sql(format!(
                                "NTILE bucket count must be INT64, got {other:?}"
                            )))
                        }
                    };
                    let partition_len = sorted.len();
                    let base_size = partition_len / buckets;
                    let extra = partition_len % buckets;
                    for (ordinal, row_index) in sorted.iter().enumerate() {
                        let bucket = if ordinal < (base_size + 1) * extra {
                            (ordinal / (base_size + 1)) + 1
                        } else {
                            ((ordinal - (base_size + 1) * extra) / base_size.max(1)) + extra + 1
                        };
                        results[*row_index] = Value::Int64(bucket as i64);
                    }
                }
                "lag" | "lead" => {
                    if _distinct || _star {
                        return Err(DbError::sql(format!(
                            "{} does not support DISTINCT or *",
                            name.to_ascii_uppercase()
                        )));
                    }
                    if args.is_empty() || args.len() > 3 {
                        return Err(DbError::sql(format!(
                            "{} expects 1 to 3 arguments",
                            name.to_ascii_uppercase()
                        )));
                    }
                    let offset = match args.get(1) {
                        Some(expr) => {
                            match self.eval_expr(expr, dataset, &[], params, ctes, None)? {
                                Value::Int64(value) if value >= 0 => value as usize,
                                Value::Int64(_) => {
                                    return Err(DbError::sql(format!(
                                        "{} offset must be non-negative",
                                        name.to_ascii_uppercase()
                                    )))
                                }
                                other => {
                                    return Err(DbError::sql(format!(
                                        "{} offset must be INT64, got {other:?}",
                                        name.to_ascii_uppercase()
                                    )))
                                }
                            }
                        }
                        None => 1,
                    };
                    let ordered_values = sorted
                        .iter()
                        .map(|row_index| {
                            self.eval_expr(
                                &args[0],
                                dataset,
                                &dataset.rows[*row_index],
                                params,
                                ctes,
                                None,
                            )
                        })
                        .collect::<Result<Vec<_>>>()?;
                    for (ordinal, row_index) in sorted.iter().enumerate() {
                        let target_ordinal = if name == "lag" {
                            ordinal.checked_sub(offset)
                        } else {
                            ordinal
                                .checked_add(offset)
                                .filter(|target| *target < sorted.len())
                        };
                        results[*row_index] = if let Some(target_ordinal) = target_ordinal {
                            ordered_values[target_ordinal].clone()
                        } else if let Some(default_expr) = args.get(2) {
                            self.eval_expr(
                                default_expr,
                                dataset,
                                &dataset.rows[*row_index],
                                params,
                                ctes,
                                None,
                            )?
                        } else {
                            Value::Null
                        };
                    }
                }
                "first_value" | "last_value" => {
                    if _distinct || _star {
                        return Err(DbError::sql(format!(
                            "{} does not support DISTINCT or *",
                            name.to_ascii_uppercase()
                        )));
                    }
                    if args.len() != 1 {
                        return Err(DbError::sql(format!(
                            "{} expects exactly 1 argument",
                            name.to_ascii_uppercase()
                        )));
                    }
                    let ordered_values = sorted
                        .iter()
                        .map(|row_index| {
                            self.eval_expr(
                                &args[0],
                                dataset,
                                &dataset.rows[*row_index],
                                params,
                                ctes,
                                None,
                            )
                        })
                        .collect::<Result<Vec<_>>>()?;
                    for (ordinal, row_index) in sorted.iter().enumerate() {
                        let frame_range = self.window_frame_bounds_for_row(
                            dataset,
                            &sorted,
                            order_by,
                            &peer_starts,
                            &peer_ends,
                            ordinal,
                            _frame,
                            params,
                            ctes,
                        )?;
                        results[*row_index] = if let Some((frame_start, frame_end)) = frame_range {
                            if name == "first_value" {
                                ordered_values[frame_start].clone()
                            } else {
                                ordered_values[frame_end].clone()
                            }
                        } else {
                            Value::Null
                        };
                    }
                }
                "nth_value" => {
                    if _distinct || _star {
                        return Err(DbError::sql("NTH_VALUE does not support DISTINCT or *"));
                    }
                    if args.len() != 2 {
                        return Err(DbError::sql(
                            "NTH_VALUE expects exactly 2 arguments".to_string(),
                        ));
                    }
                    let position =
                        match self.eval_expr(&args[1], dataset, &[], params, ctes, None)? {
                            Value::Int64(value) if value >= 1 => value as usize,
                            Value::Int64(_) => {
                                return Err(DbError::sql("NTH_VALUE position must be >= 1"))
                            }
                            other => {
                                return Err(DbError::sql(format!(
                                    "NTH_VALUE position must be INT64, got {other:?}"
                                )))
                            }
                        };
                    let ordered_values = sorted
                        .iter()
                        .map(|row_index| {
                            self.eval_expr(
                                &args[0],
                                dataset,
                                &dataset.rows[*row_index],
                                params,
                                ctes,
                                None,
                            )
                        })
                        .collect::<Result<Vec<_>>>()?;
                    for (ordinal, row_index) in sorted.iter().enumerate() {
                        let frame_range = self.window_frame_bounds_for_row(
                            dataset,
                            &sorted,
                            order_by,
                            &peer_starts,
                            &peer_ends,
                            ordinal,
                            _frame,
                            params,
                            ctes,
                        )?;
                        results[*row_index] = if let Some((frame_start, frame_end)) = frame_range {
                            frame_start
                                .checked_add(position.saturating_sub(1))
                                .filter(|index| *index <= frame_end)
                                .and_then(|index| ordered_values.get(index))
                                .cloned()
                                .unwrap_or(Value::Null)
                        } else {
                            Value::Null
                        };
                    }
                }
                "count" | "sum" | "avg" | "min" | "max" | "total" | "stddev" | "stddev_samp"
                | "stddev_pop" | "variance" | "var_samp" | "var_pop" | "bool_and" | "bool_or"
                | "group_concat" | "string_agg" => {
                    for (ordinal, row_index) in sorted.iter().enumerate() {
                        let frame_range = self.window_frame_bounds_for_row(
                            dataset,
                            &sorted,
                            order_by,
                            &peer_starts,
                            &peer_ends,
                            ordinal,
                            _frame,
                            params,
                            ctes,
                        )?;
                        results[*row_index] = self.eval_window_aggregate(
                            name,
                            args,
                            _distinct,
                            _star,
                            dataset,
                            &sorted,
                            frame_range,
                            params,
                            ctes,
                        )?;
                    }
                }
                other => {
                    return Err(DbError::sql(format!(
                        "unsupported window function {}",
                        other.to_ascii_uppercase()
                    )))
                }
            }
        }
        Ok(results)
    }

    #[allow(clippy::too_many_arguments)]
    fn window_frame_bounds_for_row(
        &self,
        dataset: &Dataset,
        sorted: &[usize],
        order_by: &[crate::sql::ast::OrderBy],
        peer_starts: &[usize],
        peer_ends: &[usize],
        ordinal: usize,
        frame: Option<&crate::sql::ast::WindowFrame>,
        params: &[Value],
        ctes: &BTreeMap<String, Dataset>,
    ) -> Result<Option<(usize, usize)>> {
        if sorted.is_empty() {
            return Ok(None);
        }

        if frame.is_none() {
            if order_by.is_empty() {
                return Ok(Some((0, sorted.len() - 1)));
            }
            return Ok(Some((0, peer_ends[ordinal])));
        }

        let frame = frame.ok_or_else(|| DbError::internal("window frame is missing"))?;
        let row_index = *sorted
            .get(ordinal)
            .ok_or_else(|| DbError::internal("window row index is invalid"))?;
        let row = dataset
            .rows
            .get(row_index)
            .map(Vec::as_slice)
            .ok_or_else(|| DbError::internal("window row index is invalid"))?;
        let default_end = crate::sql::ast::WindowFrameBound::CurrentRow;
        let end_bound = frame.end.as_ref().unwrap_or(&default_end);
        let start = self.window_frame_bound_index(
            dataset,
            row,
            &frame.start,
            true,
            ordinal,
            sorted.len(),
            peer_starts,
            peer_ends,
            frame.unit,
            params,
            ctes,
        )?;
        let end = self.window_frame_bound_index(
            dataset,
            row,
            end_bound,
            false,
            ordinal,
            sorted.len(),
            peer_starts,
            peer_ends,
            frame.unit,
            params,
            ctes,
        )?;
        normalize_window_frame_range(start, end, sorted.len())
    }

    #[allow(clippy::too_many_arguments)]
    fn window_frame_bound_index(
        &self,
        dataset: &Dataset,
        row: &[Value],
        bound: &crate::sql::ast::WindowFrameBound,
        start: bool,
        ordinal: usize,
        partition_len: usize,
        peer_starts: &[usize],
        peer_ends: &[usize],
        unit: crate::sql::ast::WindowFrameUnit,
        params: &[Value],
        ctes: &BTreeMap<String, Dataset>,
    ) -> Result<i64> {
        let partition_len = i64::try_from(partition_len)
            .map_err(|_| DbError::internal("window partition is too large"))?;
        let ordinal =
            i64::try_from(ordinal).map_err(|_| DbError::internal("window ordinal is too large"))?;
        match (unit, bound) {
            (
                crate::sql::ast::WindowFrameUnit::Range,
                crate::sql::ast::WindowFrameBound::Preceding(_)
                | crate::sql::ast::WindowFrameBound::Following(_),
            ) => Err(DbError::sql(
                "RANGE frames with offset bounds are not supported yet",
            )),
            (_, crate::sql::ast::WindowFrameBound::UnboundedPreceding) => Ok(0),
            (_, crate::sql::ast::WindowFrameBound::UnboundedFollowing) => {
                if start {
                    Ok(partition_len)
                } else {
                    Ok(partition_len - 1)
                }
            }
            (
                crate::sql::ast::WindowFrameUnit::Rows,
                crate::sql::ast::WindowFrameBound::CurrentRow,
            ) => Ok(ordinal),
            (
                crate::sql::ast::WindowFrameUnit::Range,
                crate::sql::ast::WindowFrameBound::CurrentRow,
            ) => {
                if start {
                    i64::try_from(peer_starts[ordinal as usize])
                        .map_err(|_| DbError::internal("window peer start is too large"))
                } else {
                    i64::try_from(peer_ends[ordinal as usize])
                        .map_err(|_| DbError::internal("window peer end is too large"))
                }
            }
            (
                crate::sql::ast::WindowFrameUnit::Rows,
                crate::sql::ast::WindowFrameBound::Preceding(offset),
            ) => {
                let offset = self.eval_window_frame_offset(dataset, row, offset, params, ctes)?;
                Ok(ordinal - offset)
            }
            (
                crate::sql::ast::WindowFrameUnit::Rows,
                crate::sql::ast::WindowFrameBound::Following(offset),
            ) => {
                let offset = self.eval_window_frame_offset(dataset, row, offset, params, ctes)?;
                Ok(ordinal + offset)
            }
        }
    }

    fn eval_window_frame_offset(
        &self,
        dataset: &Dataset,
        row: &[Value],
        offset: &Expr,
        params: &[Value],
        ctes: &BTreeMap<String, Dataset>,
    ) -> Result<i64> {
        match self.eval_expr(offset, dataset, row, params, ctes, None)? {
            Value::Int64(value) if value >= 0 => Ok(value),
            Value::Int64(_) => Err(DbError::sql(
                "window frame offset must be a non-negative integer",
            )),
            Value::Null => Err(DbError::sql("window frame offset cannot be NULL")),
            other => Err(DbError::sql(format!(
                "window frame offset must be INT64, got {other:?}"
            ))),
        }
    }

    #[allow(clippy::too_many_arguments)]
    fn eval_window_aggregate(
        &self,
        name: &str,
        args: &[Expr],
        distinct: bool,
        star: bool,
        dataset: &Dataset,
        sorted_partition: &[usize],
        frame_range: Option<(usize, usize)>,
        params: &[Value],
        ctes: &BTreeMap<String, Dataset>,
    ) -> Result<Value> {
        let aggregate_ctx = AggregateEvalContext {
            runtime: self,
            dataset,
            params,
            ctes,
        };
        let empty_indexes: [usize; 0] = [];
        let row_indexes = if let Some((start, end)) = frame_range {
            sorted_partition
                .get(start..=end)
                .ok_or_else(|| DbError::internal("window frame range is invalid"))?
        } else {
            &empty_indexes
        };

        match name {
            "count" => {
                if star {
                    if distinct {
                        return Err(DbError::sql("COUNT(DISTINCT *) is not supported"));
                    }
                    return Ok(Value::Int64(row_indexes.len() as i64));
                }
                if args.len() != 1 {
                    return Err(DbError::sql("COUNT expects exactly 1 argument"));
                }
                if distinct {
                    let mut vals = Vec::new();
                    for row_index in row_indexes {
                        let row = dataset
                            .rows
                            .get(*row_index)
                            .map(Vec::as_slice)
                            .ok_or_else(|| DbError::internal("window row index is invalid"))?;
                        let val = self.eval_expr(&args[0], dataset, row, params, ctes, None)?;
                        if !matches!(val, Value::Null) {
                            vals.push(val);
                        }
                    }
                    vals.sort_by(|a, b| compare_values(a, b).unwrap_or(std::cmp::Ordering::Equal));
                    vals.dedup_by(|a, b| {
                        compare_values(a, b).unwrap_or(std::cmp::Ordering::Equal)
                            == std::cmp::Ordering::Equal
                    });
                    Ok(Value::Int64(vals.len() as i64))
                } else {
                    let mut count = 0_i64;
                    for row_index in row_indexes {
                        let row = dataset
                            .rows
                            .get(*row_index)
                            .map(Vec::as_slice)
                            .ok_or_else(|| DbError::internal("window row index is invalid"))?;
                        if !matches!(
                            self.eval_expr(&args[0], dataset, row, params, ctes, None)?,
                            Value::Null
                        ) {
                            count += 1;
                        }
                    }
                    Ok(Value::Int64(count))
                }
            }
            "sum" => {
                if star || args.len() != 1 {
                    return Err(DbError::sql("SUM expects exactly 1 argument"));
                }
                aggregate_numeric(
                    &aggregate_ctx,
                    row_indexes,
                    &args[0],
                    NumericAgg::Sum,
                    distinct,
                )
            }
            "avg" => {
                if star || args.len() != 1 {
                    return Err(DbError::sql("AVG expects exactly 1 argument"));
                }
                aggregate_numeric(
                    &aggregate_ctx,
                    row_indexes,
                    &args[0],
                    NumericAgg::Avg,
                    distinct,
                )
            }
            "total" => {
                if star || args.len() != 1 {
                    return Err(DbError::sql("TOTAL expects exactly 1 argument"));
                }
                aggregate_numeric(
                    &aggregate_ctx,
                    row_indexes,
                    &args[0],
                    NumericAgg::Total,
                    distinct,
                )
            }
            "stddev" | "stddev_samp" => {
                if star || args.len() != 1 {
                    return Err(DbError::sql("STDDEV expects exactly 1 argument"));
                }
                aggregate_variance(
                    &aggregate_ctx,
                    row_indexes,
                    &args[0],
                    VarianceAgg::StddevSamp,
                    distinct,
                )
            }
            "stddev_pop" => {
                if star || args.len() != 1 {
                    return Err(DbError::sql("STDDEV_POP expects exactly 1 argument"));
                }
                aggregate_variance(
                    &aggregate_ctx,
                    row_indexes,
                    &args[0],
                    VarianceAgg::StddevPop,
                    distinct,
                )
            }
            "variance" | "var_samp" => {
                if star || args.len() != 1 {
                    return Err(DbError::sql("VAR_SAMP expects exactly 1 argument"));
                }
                aggregate_variance(
                    &aggregate_ctx,
                    row_indexes,
                    &args[0],
                    VarianceAgg::VarSamp,
                    distinct,
                )
            }
            "var_pop" => {
                if star || args.len() != 1 {
                    return Err(DbError::sql("VAR_POP expects exactly 1 argument"));
                }
                aggregate_variance(
                    &aggregate_ctx,
                    row_indexes,
                    &args[0],
                    VarianceAgg::VarPop,
                    distinct,
                )
            }
            "bool_and" => {
                if star || args.len() != 1 {
                    return Err(DbError::sql("BOOL_AND expects exactly 1 argument"));
                }
                aggregate_bool(
                    &aggregate_ctx,
                    row_indexes,
                    &args[0],
                    BoolAgg::And,
                    distinct,
                )
            }
            "bool_or" => {
                if star || args.len() != 1 {
                    return Err(DbError::sql("BOOL_OR expects exactly 1 argument"));
                }
                aggregate_bool(&aggregate_ctx, row_indexes, &args[0], BoolAgg::Or, distinct)
            }
            "min" => {
                if star || args.len() != 1 {
                    return Err(DbError::sql("MIN expects exactly 1 argument"));
                }
                aggregate_extreme(self, dataset, row_indexes, &args[0], params, ctes, true)
            }
            "max" => {
                if star || args.len() != 1 {
                    return Err(DbError::sql("MAX expects exactly 1 argument"));
                }
                aggregate_extreme(self, dataset, row_indexes, &args[0], params, ctes, false)
            }
            name @ ("group_concat" | "string_agg") => {
                if star {
                    return Err(DbError::sql(format!(
                        "{} does not support *",
                        name.to_ascii_uppercase()
                    )));
                }
                if distinct {
                    return Err(DbError::sql(format!(
                        "{} DISTINCT is not supported in window context",
                        name.to_ascii_uppercase()
                    )));
                }
                aggregate_group_concat(&aggregate_ctx, row_indexes, args, false, &[], name)
            }
            other => Err(DbError::sql(format!(
                "unsupported aggregate window function {other}"
            ))),
        }
    }

    fn evaluate_grouped_select(
        &self,
        select: &Select,
        dataset: Dataset,
        params: &[Value],
        ctes: &BTreeMap<String, Dataset>,
    ) -> Result<Dataset> {
        if select.group_by.iter().any(expr_contains_collation) {
            return Err(DbError::sql(
                "COLLATE in GROUP BY keys is not supported in this compatibility slice",
            ));
        }
        let mut groups = BTreeMap::<Vec<u8>, Vec<usize>>::new();
        if dataset.rows.is_empty() && select.group_by.is_empty() {
            groups.insert(Vec::new(), Vec::new());
        } else {
            for (row_index, row) in dataset.rows.iter().enumerate() {
                let key_values = select
                    .group_by
                    .iter()
                    .map(|expr| self.eval_expr(expr, &dataset, row, params, ctes, None))
                    .collect::<Result<Vec<_>>>()?;
                groups
                    .entry(row_identity(&key_values)?)
                    .or_default()
                    .push(row_index);
            }
        }
        let columns = select
            .projection
            .iter()
            .enumerate()
            .map(|(index, item)| match item {
                SelectItem::Expr { expr, alias } => ColumnBinding::visible(
                    None,
                    alias
                        .clone()
                        .unwrap_or_else(|| infer_expr_name(expr, index + 1)),
                ),
                SelectItem::Wildcard => ColumnBinding::visible(None, format!("col{}", index + 1)),
                SelectItem::QualifiedWildcard(_) => {
                    ColumnBinding::visible(None, format!("col{}", index + 1))
                }
            })
            .collect::<Vec<_>>();
        let mut rows = Vec::new();
        for group_row_indexes in groups.into_values() {
            if let Some(having) = &select.having {
                if !matches!(
                    self.eval_group_expr(having, &dataset, &group_row_indexes, params, ctes)?,
                    Value::Bool(true)
                ) {
                    continue;
                }
            }
            let mut output = Vec::new();
            for item in &select.projection {
                match item {
                    SelectItem::Expr { expr, .. } => output.push(self.eval_group_expr(
                        expr,
                        &dataset,
                        &group_row_indexes,
                        params,
                        ctes,
                    )?),
                    SelectItem::Wildcard | SelectItem::QualifiedWildcard(_) => {
                        return Err(DbError::sql(
                            "wildcards are not supported in grouped SELECT output",
                        ))
                    }
                }
            }
            rows.push(output);
        }
        Ok(Dataset::with_rows(columns, rows))
    }

    fn sort_dataset(
        &self,
        dataset: &mut Dataset,
        order_by: &[crate::sql::ast::OrderBy],
        params: &[Value],
        ctes: &BTreeMap<String, Dataset>,
    ) -> Result<()> {
        if order_by.is_empty() || dataset.rows.len() <= 1 {
            return Ok(());
        }
        let eval_dataset = Dataset::with_rows(dataset.columns.clone(), Vec::new());
        let sort_keys = dataset
            .rows
            .iter()
            .map(|row| {
                order_by
                    .iter()
                    .map(|order| {
                        self.eval_expr(&order.expr, &eval_dataset, row, params, ctes, None)
                            .unwrap_or(Value::Null)
                    })
                    .collect::<Vec<_>>()
            })
            .collect::<Vec<_>>();

        let mut sort_error = None;
        let mut order = (0..dataset.rows.len()).collect::<Vec<_>>();
        order.sort_by(|left_index, right_index| {
            let left_key = &sort_keys[*left_index];
            let right_key = &sort_keys[*right_index];
            for (order_clause, (left_value, right_value)) in
                order_by.iter().zip(left_key.iter().zip(right_key.iter()))
            {
                let ordering = match compare_values_with_runtime_collation(
                    Some(self),
                    left_value,
                    right_value,
                    order_clause.collation.clone(),
                ) {
                    Ok(ordering) => ordering,
                    Err(error) => {
                        if sort_error.is_none() {
                            sort_error = Some(error);
                        }
                        std::cmp::Ordering::Equal
                    }
                };
                if ordering != std::cmp::Ordering::Equal {
                    return if order_clause.descending {
                        ordering.reverse()
                    } else {
                        ordering
                    };
                }
            }
            left_index.cmp(right_index)
        });
        if let Some(error) = sort_error {
            return Err(error);
        }

        let mut rows = dataset
            .take_rows()
            .into_iter()
            .map(Some)
            .collect::<Vec<_>>();
        dataset.set_rows(
            order
                .into_iter()
                .map(|row_index| {
                    rows.get_mut(row_index)
                        .and_then(Option::take)
                        .ok_or_else(|| DbError::internal("sorted row index is invalid"))
                })
                .collect::<Result<Vec<_>>>()?,
        );
        Ok(())
    }

    fn eval_constant_i64(
        &self,
        expr: &Expr,
        params: &[Value],
        ctes: &BTreeMap<String, Dataset>,
    ) -> Result<i64> {
        match self.eval_expr(expr, &Dataset::empty(), &[], params, ctes, None)? {
            Value::Int64(value) => Ok(value),
            other => Err(DbError::sql(format!(
                "expected integer constant, got {other:?}"
            ))),
        }
    }

    fn eval_group_membership_value(
        &self,
        expr: &Expr,
        dataset: &Dataset,
        group_row_indexes: &[usize],
        params: &[Value],
        ctes: &BTreeMap<String, Dataset>,
    ) -> Result<MembershipValue> {
        match expr {
            Expr::Row(items) => Ok(MembershipValue::Row(
                items
                    .iter()
                    .map(|item| {
                        self.eval_group_expr(item, dataset, group_row_indexes, params, ctes)
                    })
                    .collect::<Result<Vec<_>>>()?,
            )),
            _ => Ok(MembershipValue::Scalar(self.eval_group_expr(
                expr,
                dataset,
                group_row_indexes,
                params,
                ctes,
            )?)),
        }
    }

    fn eval_membership_value(
        &self,
        expr: &Expr,
        dataset: &Dataset,
        row: &[Value],
        params: &[Value],
        ctes: &BTreeMap<String, Dataset>,
        excluded: Option<&Dataset>,
    ) -> Result<MembershipValue> {
        match expr {
            Expr::Row(items) => Ok(MembershipValue::Row(
                items
                    .iter()
                    .map(|item| self.eval_expr(item, dataset, row, params, ctes, excluded))
                    .collect::<Result<Vec<_>>>()?,
            )),
            _ => Ok(MembershipValue::Scalar(
                self.eval_expr(expr, dataset, row, params, ctes, excluded)?,
            )),
        }
    }

    fn eval_group_expr(
        &self,
        expr: &Expr,
        dataset: &Dataset,
        group_row_indexes: &[usize],
        params: &[Value],
        ctes: &BTreeMap<String, Dataset>,
    ) -> Result<Value> {
        let aggregate_ctx = AggregateEvalContext {
            runtime: self,
            dataset,
            params,
            ctes,
        };
        match expr {
            Expr::Aggregate {
                name,
                args,
                star,
                distinct,
                order_by,
                within_group,
            } => match name.as_str() {
                "array_agg" | "median" | "percentile_cont" | "percentile_disc" => {
                    match name.as_str() {
                        "array_agg" => {
                            if *within_group {
                                return Err(DbError::sql(
                                    "ARRAY_AGG does not support WITHIN GROUP",
                                ));
                            }
                            if *star || args.len() != 1 {
                                return Err(DbError::sql("ARRAY_AGG expects exactly 1 argument"));
                            }
                            aggregate_array_agg(
                                &aggregate_ctx,
                                group_row_indexes,
                                &args[0],
                                *distinct,
                                order_by,
                            )
                        }
                        "median" => {
                            if *within_group {
                                return Err(DbError::sql(
                                    "MEDIAN does not support WITHIN GROUP; use MEDIAN(expr)",
                                ));
                            }
                            if !order_by.is_empty() {
                                return Err(DbError::sql(
                                    "MEDIAN does not support aggregate ORDER BY",
                                ));
                            }
                            if *star || args.len() != 1 {
                                return Err(DbError::sql("MEDIAN expects exactly 1 argument"));
                            }
                            aggregate_median(&aggregate_ctx, group_row_indexes, &args[0], *distinct)
                        }
                        "percentile_cont" => {
                            if !*within_group {
                                return Err(DbError::sql(
                                    "PERCENTILE_CONT requires WITHIN GROUP (ORDER BY ...)",
                                ));
                            }
                            if *distinct {
                                return Err(DbError::sql(
                                    "PERCENTILE_CONT does not support DISTINCT",
                                ));
                            }
                            if *star || args.len() != 1 {
                                return Err(DbError::sql(
                                    "PERCENTILE_CONT expects exactly 1 argument",
                                ));
                            }
                            aggregate_percentile_cont(
                                self,
                                dataset,
                                group_row_indexes,
                                &args[0],
                                order_by,
                                params,
                                ctes,
                            )
                        }
                        "percentile_disc" => {
                            if !*within_group {
                                return Err(DbError::sql(
                                    "PERCENTILE_DISC requires WITHIN GROUP (ORDER BY ...)",
                                ));
                            }
                            if *distinct {
                                return Err(DbError::sql(
                                    "PERCENTILE_DISC does not support DISTINCT",
                                ));
                            }
                            if *star || args.len() != 1 {
                                return Err(DbError::sql(
                                    "PERCENTILE_DISC expects exactly 1 argument",
                                ));
                            }
                            aggregate_percentile_disc(
                                self,
                                dataset,
                                group_row_indexes,
                                &args[0],
                                order_by,
                                params,
                                ctes,
                            )
                        }
                        _ => Err(DbError::sql(format!(
                            "unsupported aggregate function {}",
                            name.to_ascii_uppercase()
                        ))),
                    }
                }
                name if *within_group => Err(DbError::sql(format!(
                    "{} does not support WITHIN GROUP",
                    name.to_ascii_uppercase()
                ))),
                name if !order_by.is_empty() && !matches!(name, "group_concat" | "string_agg") => {
                    Err(DbError::sql(format!(
                        "{} does not support aggregate ORDER BY",
                        name.to_ascii_uppercase()
                    )))
                }
                "count" => {
                    if *star {
                        Ok(Value::Int64(group_row_indexes.len() as i64))
                    } else if *distinct {
                        let mut vals = Vec::new();
                        for row_index in group_row_indexes {
                            let row =
                                dataset.rows.get(*row_index).map(Vec::as_slice).ok_or_else(
                                    || DbError::internal("group row index is invalid"),
                                )?;
                            let val = self.eval_expr(&args[0], dataset, row, params, ctes, None)?;
                            if !matches!(val, Value::Null) {
                                vals.push(val);
                            }
                        }
                        vals.sort_by(|a, b| {
                            compare_values(a, b).unwrap_or(std::cmp::Ordering::Equal)
                        });
                        vals.dedup_by(|a, b| {
                            compare_values(a, b).unwrap_or(std::cmp::Ordering::Equal)
                                == std::cmp::Ordering::Equal
                        });
                        Ok(Value::Int64(vals.len() as i64))
                    } else {
                        let mut count = 0_i64;
                        for row_index in group_row_indexes {
                            let row =
                                dataset.rows.get(*row_index).map(Vec::as_slice).ok_or_else(
                                    || DbError::internal("group row index is invalid"),
                                )?;
                            if !matches!(
                                self.eval_expr(&args[0], dataset, row, params, ctes, None)?,
                                Value::Null
                            ) {
                                count += 1;
                            }
                        }
                        Ok(Value::Int64(count))
                    }
                }
                "sum" => aggregate_numeric(
                    &aggregate_ctx,
                    group_row_indexes,
                    &args[0],
                    NumericAgg::Sum,
                    *distinct,
                ),
                "avg" => aggregate_numeric(
                    &aggregate_ctx,
                    group_row_indexes,
                    &args[0],
                    NumericAgg::Avg,
                    *distinct,
                ),
                "total" => aggregate_numeric(
                    &aggregate_ctx,
                    group_row_indexes,
                    &args[0],
                    NumericAgg::Total,
                    *distinct,
                ),
                "stddev" | "stddev_samp" => aggregate_variance(
                    &aggregate_ctx,
                    group_row_indexes,
                    &args[0],
                    VarianceAgg::StddevSamp,
                    *distinct,
                ),
                "stddev_pop" => aggregate_variance(
                    &aggregate_ctx,
                    group_row_indexes,
                    &args[0],
                    VarianceAgg::StddevPop,
                    *distinct,
                ),
                "variance" | "var_samp" => aggregate_variance(
                    &aggregate_ctx,
                    group_row_indexes,
                    &args[0],
                    VarianceAgg::VarSamp,
                    *distinct,
                ),
                "var_pop" => aggregate_variance(
                    &aggregate_ctx,
                    group_row_indexes,
                    &args[0],
                    VarianceAgg::VarPop,
                    *distinct,
                ),
                "bool_and" => aggregate_bool(
                    &aggregate_ctx,
                    group_row_indexes,
                    &args[0],
                    BoolAgg::And,
                    *distinct,
                ),
                "bool_or" => aggregate_bool(
                    &aggregate_ctx,
                    group_row_indexes,
                    &args[0],
                    BoolAgg::Or,
                    *distinct,
                ),
                "min" => aggregate_extreme(
                    self,
                    dataset,
                    group_row_indexes,
                    &args[0],
                    params,
                    ctes,
                    true,
                ),
                "max" => aggregate_extreme(
                    self,
                    dataset,
                    group_row_indexes,
                    &args[0],
                    params,
                    ctes,
                    false,
                ),
                name @ ("group_concat" | "string_agg") => aggregate_group_concat(
                    &aggregate_ctx,
                    group_row_indexes,
                    args,
                    *distinct,
                    order_by,
                    name,
                ),
                other => {
                    let mut arg_rows = Vec::with_capacity(group_row_indexes.len());
                    for row_index in group_row_indexes {
                        let row = dataset
                            .rows
                            .get(*row_index)
                            .map(Vec::as_slice)
                            .ok_or_else(|| DbError::internal("group row index is invalid"))?;
                        let values = args
                            .iter()
                            .map(|arg| self.eval_expr(arg, dataset, row, params, ctes, None))
                            .collect::<Result<Vec<_>>>()?;
                        arg_rows.push(values);
                    }
                    if let Some(value) =
                        crate::extensions::invoke_aggregate_from_runtime(self, other, arg_rows)?
                    {
                        return Ok(value);
                    }
                    Err(DbError::sql(format!(
                        "unsupported aggregate function {other}"
                    )))
                }
            },
            Expr::Unary { op, expr } => {
                let value = self.eval_group_expr(expr, dataset, group_row_indexes, params, ctes)?;
                match op {
                    UnaryOp::Not => Ok(match truthy(&value) {
                        Some(value) => Value::Bool(!value),
                        None => Value::Null,
                    }),
                    UnaryOp::Negate => match value {
                        Value::Int64(value) => Ok(Value::Int64(-value)),
                        Value::Float64(value) => Ok(Value::Float64(-value)),
                        Value::Null => Ok(Value::Null),
                        other => Err(DbError::sql(format!("cannot negate {other:?}"))),
                    },
                }
            }
            Expr::Binary { left, op, right } => {
                let collation = expr_collation(left).or_else(|| expr_collation(right));
                eval_binary_with_collation(
                    Some(self),
                    op,
                    self.eval_group_expr(left, dataset, group_row_indexes, params, ctes)?,
                    self.eval_group_expr(right, dataset, group_row_indexes, params, ctes)?,
                    collation,
                )
            }
            Expr::Between {
                expr,
                low,
                high,
                negated,
            } => {
                let value = self.eval_group_expr(expr, dataset, group_row_indexes, params, ctes)?;
                let low = self.eval_group_expr(low, dataset, group_row_indexes, params, ctes)?;
                let high = self.eval_group_expr(high, dataset, group_row_indexes, params, ctes)?;
                if matches!(value, Value::Null)
                    || matches!(low, Value::Null)
                    || matches!(high, Value::Null)
                {
                    return Ok(Value::Null);
                }
                let collation = expr_collation(expr);
                let in_range = compare_values_with_runtime_collation(
                    Some(self),
                    &value,
                    &low,
                    collation.clone(),
                )? != std::cmp::Ordering::Less
                    && compare_values_with_runtime_collation(Some(self), &value, &high, collation)?
                        != std::cmp::Ordering::Greater;
                Ok(Value::Bool(if *negated { !in_range } else { in_range }))
            }
            Expr::InList {
                expr,
                items,
                negated,
            } => {
                let value = self.eval_group_membership_value(
                    expr,
                    dataset,
                    group_row_indexes,
                    params,
                    ctes,
                )?;
                if membership_value_has_nulls(&value) {
                    return Ok(Value::Null);
                }
                let mut saw_null = false;
                for item in items {
                    let candidate = self.eval_group_membership_value(
                        item,
                        dataset,
                        group_row_indexes,
                        params,
                        ctes,
                    )?;
                    match compare_membership_values(&value, &candidate)? {
                        Some(true) => return Ok(Value::Bool(!*negated)),
                        Some(false) => {}
                        None => saw_null = true,
                    }
                }
                if saw_null {
                    Ok(Value::Null)
                } else {
                    Ok(Value::Bool(*negated))
                }
            }
            Expr::Like {
                expr,
                pattern,
                escape,
                case_insensitive,
                negated,
                ..
            } => {
                let left = self.eval_group_expr(expr, dataset, group_row_indexes, params, ctes)?;
                let right =
                    self.eval_group_expr(pattern, dataset, group_row_indexes, params, ctes)?;
                let escape = escape
                    .as_ref()
                    .map(|expr| {
                        self.eval_group_expr(expr, dataset, group_row_indexes, params, ctes)
                    })
                    .transpose()?;
                eval_like(left, right, escape, *case_insensitive, *negated)
            }
            Expr::IsNull { expr, negated } => {
                let is_null = matches!(
                    self.eval_group_expr(expr, dataset, group_row_indexes, params, ctes)?,
                    Value::Null
                );
                Ok(Value::Bool(if *negated { !is_null } else { is_null }))
            }
            Expr::Function { name, args } => {
                let args_contain_aggregate = args.iter().any(expr_contains_aggregate)
                    || args.iter().try_fold(false, |found, arg| {
                        if found {
                            Ok(true)
                        } else {
                            expr_contains_runtime_extension_aggregate(self, arg)
                        }
                    })?;
                if !args_contain_aggregate {
                    let mut arg_rows = Vec::with_capacity(group_row_indexes.len());
                    for row_index in group_row_indexes {
                        let row = dataset
                            .rows
                            .get(*row_index)
                            .map(Vec::as_slice)
                            .ok_or_else(|| DbError::internal("group row index is invalid"))?;
                        let values = args
                            .iter()
                            .map(|arg| self.eval_expr(arg, dataset, row, params, ctes, None))
                            .collect::<Result<Vec<_>>>()?;
                        arg_rows.push(values);
                    }
                    if let Some(value) =
                        crate::extensions::invoke_aggregate_from_runtime(self, name, arg_rows)?
                    {
                        return Ok(value);
                    }
                }
                let row = if let Some(row_index) = group_row_indexes.first().copied() {
                    dataset
                        .rows
                        .get(row_index)
                        .map(Vec::as_slice)
                        .ok_or_else(|| DbError::internal("group row index is invalid"))?
                } else {
                    &[]
                };
                let values = args
                    .iter()
                    .map(|arg| self.eval_group_expr(arg, dataset, group_row_indexes, params, ctes))
                    .collect::<Result<Vec<_>>>()?;
                match name.as_str() {
                    "coalesce" => Ok(values
                        .into_iter()
                        .find(|value| !matches!(value, Value::Null))
                        .unwrap_or(Value::Null)),
                    "nullif" => {
                        if values.len() != 2 {
                            return Err(DbError::sql("NULLIF expects exactly two arguments"));
                        }
                        if compare_values(&values[0], &values[1])? == std::cmp::Ordering::Equal {
                            Ok(Value::Null)
                        } else {
                            Ok(values[0].clone())
                        }
                    }
                    "length" => unary_text_fn(values, |value| value.len().to_string())
                        .and_then(|value| cast_value(value, crate::catalog::ColumnType::Int64)),
                    "lower" => unary_text_fn(values, |value| value.to_ascii_lowercase()),
                    "upper" => unary_text_fn(values, |value| value.to_ascii_uppercase()),
                    "trim" => unary_text_fn(values, |value| value.trim().to_string()),
                    other => self.eval_expr(
                        &Expr::Function {
                            name: other.to_string(),
                            args: args.to_vec(),
                        },
                        dataset,
                        row,
                        params,
                        ctes,
                        None,
                    ),
                }
            }
            Expr::Case {
                operand,
                branches,
                else_expr,
            } => {
                let operand_value = operand
                    .as_deref()
                    .map(|expr| {
                        self.eval_group_expr(expr, dataset, group_row_indexes, params, ctes)
                    })
                    .transpose()?;
                for (condition, result) in branches {
                    let matches = if let Some(operand_value) = &operand_value {
                        compare_values(
                            operand_value,
                            &self.eval_group_expr(
                                condition,
                                dataset,
                                group_row_indexes,
                                params,
                                ctes,
                            )?,
                        )? == std::cmp::Ordering::Equal
                    } else {
                        matches!(
                            self.eval_group_expr(
                                condition,
                                dataset,
                                group_row_indexes,
                                params,
                                ctes,
                            )?,
                            Value::Bool(true)
                        )
                    };
                    if matches {
                        return self.eval_group_expr(
                            result,
                            dataset,
                            group_row_indexes,
                            params,
                            ctes,
                        );
                    }
                }
                else_expr
                    .as_deref()
                    .map(|expr| {
                        self.eval_group_expr(expr, dataset, group_row_indexes, params, ctes)
                    })
                    .transpose()?
                    .map_or(Ok(Value::Null), Ok)
            }
            Expr::Cast { expr, target_type } => cast_value(
                self.eval_group_expr(expr, dataset, group_row_indexes, params, ctes)?,
                *target_type,
            ),
            Expr::Collate { expr, .. } => {
                self.eval_group_expr(expr, dataset, group_row_indexes, params, ctes)
            }
            Expr::Row(_) => Err(DbError::sql(
                "row values are only supported in IN comparisons",
            )),
            Expr::RowNumber { .. } | Expr::WindowFunction { .. } => Err(DbError::sql(
                "window functions cannot be nested inside grouped expressions",
            )),
            _ => {
                let row = if let Some(row_index) = group_row_indexes.first().copied() {
                    dataset
                        .rows
                        .get(row_index)
                        .map(Vec::as_slice)
                        .ok_or_else(|| DbError::internal("group row index is invalid"))?
                } else {
                    &[]
                };
                self.eval_expr(expr, dataset, row, params, ctes, None)
            }
        }
    }

    fn eval_expr(
        &self,
        expr: &Expr,
        dataset: &Dataset,
        row: &[Value],
        params: &[Value],
        ctes: &BTreeMap<String, Dataset>,
        excluded: Option<&Dataset>,
    ) -> Result<Value> {
        match expr {
            Expr::Literal(value) => Ok(value.clone()),
            Expr::Column { table, column } => {
                self.resolve_column(dataset, row, table.as_deref(), column, excluded)
            }
            Expr::Parameter(number) => params
                .get(number.saturating_sub(1))
                .cloned()
                .ok_or_else(|| DbError::sql(format!("missing value for parameter ${number}"))),
            Expr::Unary { op, expr } => {
                let value = self.eval_expr(expr, dataset, row, params, ctes, excluded)?;
                match op {
                    UnaryOp::Not => Ok(match truthy(&value) {
                        Some(value) => Value::Bool(!value),
                        None => Value::Null,
                    }),
                    UnaryOp::Negate => match value {
                        Value::Int64(value) => Ok(Value::Int64(-value)),
                        Value::Float64(value) => Ok(Value::Float64(-value)),
                        Value::Null => Ok(Value::Null),
                        other => Err(DbError::sql(format!("cannot negate {other:?}"))),
                    },
                }
            }
            Expr::Binary { left, op, right } => {
                let collation = expr_collation(left).or_else(|| expr_collation(right));
                let left = self.eval_expr(left, dataset, row, params, ctes, excluded)?;
                let right = self.eval_expr(right, dataset, row, params, ctes, excluded)?;
                eval_binary_with_collation(Some(self), op, left, right, collation)
            }
            Expr::Between {
                expr,
                low,
                high,
                negated,
            } => {
                let value = self.eval_expr(expr, dataset, row, params, ctes, excluded)?;
                let low = self.eval_expr(low, dataset, row, params, ctes, excluded)?;
                let high = self.eval_expr(high, dataset, row, params, ctes, excluded)?;
                if matches!(value, Value::Null)
                    || matches!(low, Value::Null)
                    || matches!(high, Value::Null)
                {
                    return Ok(Value::Null);
                }
                let collation = expr_collation(expr);
                let in_range = compare_values_with_runtime_collation(
                    Some(self),
                    &value,
                    &low,
                    collation.clone(),
                )? != std::cmp::Ordering::Less
                    && compare_values_with_runtime_collation(Some(self), &value, &high, collation)?
                        != std::cmp::Ordering::Greater;
                Ok(Value::Bool(if *negated { !in_range } else { in_range }))
            }
            Expr::InList {
                expr,
                items,
                negated,
            } => {
                let value =
                    self.eval_membership_value(expr, dataset, row, params, ctes, excluded)?;
                if membership_value_has_nulls(&value) {
                    return Ok(Value::Null);
                }
                let mut saw_null = false;
                for item in items {
                    let candidate =
                        self.eval_membership_value(item, dataset, row, params, ctes, excluded)?;
                    match compare_membership_values(&value, &candidate)? {
                        Some(true) => return Ok(Value::Bool(!*negated)),
                        Some(false) => {}
                        None => saw_null = true,
                    }
                }
                if saw_null {
                    Ok(Value::Null)
                } else {
                    Ok(Value::Bool(*negated))
                }
            }
            Expr::InSubquery {
                expr,
                query,
                negated,
            } => {
                let value =
                    self.eval_membership_value(expr, dataset, row, params, ctes, excluded)?;
                if membership_value_has_nulls(&value) {
                    return Ok(Value::Null);
                }
                let subquery = self.evaluate_query_with_outer(query, params, ctes, dataset, row)?;
                let expected_width = match &value {
                    MembershipValue::Scalar(_) => 1,
                    MembershipValue::Row(values) => values.len(),
                };
                if subquery.columns.len() != expected_width {
                    return Err(DbError::sql(format!(
                        "IN subquery must return exactly {} column{}",
                        expected_width,
                        if expected_width == 1 { "" } else { "s" }
                    )));
                }
                let mut saw_null = false;
                for subquery_row in subquery.rows.iter() {
                    let candidate = if expected_width == 1 {
                        MembershipValue::Scalar(
                            subquery_row.first().cloned().unwrap_or(Value::Null),
                        )
                    } else {
                        MembershipValue::Row(subquery_row.clone())
                    };
                    match compare_membership_values(&value, &candidate)? {
                        Some(true) => return Ok(Value::Bool(!*negated)),
                        Some(false) => {}
                        None => saw_null = true,
                    }
                }
                if saw_null {
                    Ok(Value::Null)
                } else {
                    Ok(Value::Bool(*negated))
                }
            }
            Expr::CompareSubquery {
                expr,
                op,
                quantifier,
                query,
            } => {
                let left_value = self.eval_expr(expr, dataset, row, params, ctes, excluded)?;
                let subquery = self.evaluate_query_with_outer(query, params, ctes, dataset, row)?;
                if subquery.columns.len() != 1 {
                    return Err(DbError::sql(
                        "subquery comparison must return exactly one column",
                    ));
                }
                let mut saw_null = false;
                let mut saw_row = false;
                for subquery_row in subquery.rows.iter() {
                    saw_row = true;
                    let candidate = subquery_row.first().cloned().unwrap_or(Value::Null);
                    match eval_binary_with_collation(
                        Some(self),
                        op,
                        left_value.clone(),
                        candidate,
                        expr_collation(expr),
                    )? {
                        Value::Bool(result) => match quantifier {
                            SubqueryQuantifier::Any if result => return Ok(Value::Bool(true)),
                            SubqueryQuantifier::All if !result => return Ok(Value::Bool(false)),
                            _ => {}
                        },
                        Value::Null => saw_null = true,
                        other => {
                            return Err(DbError::internal(format!(
                                "subquery comparison did not evaluate to boolean: {other:?}"
                            )))
                        }
                    }
                }
                if !saw_row {
                    return Ok(Value::Bool(matches!(quantifier, SubqueryQuantifier::All)));
                }
                if saw_null {
                    Ok(Value::Null)
                } else {
                    Ok(Value::Bool(matches!(quantifier, SubqueryQuantifier::All)))
                }
            }
            Expr::ScalarSubquery(query) => {
                let subquery = self.evaluate_query_with_outer(query, params, ctes, dataset, row)?;
                if subquery.columns.len() != 1 {
                    return Err(DbError::sql(
                        "scalar subquery must return exactly one column",
                    ));
                }
                Ok(subquery
                    .rows
                    .first()
                    .and_then(|subquery_row| subquery_row.first())
                    .cloned()
                    .unwrap_or(Value::Null))
            }
            Expr::Exists(query) => Ok(Value::Bool(
                !self
                    .evaluate_query_with_outer(query, params, ctes, dataset, row)?
                    .rows
                    .is_empty(),
            )),
            Expr::Like {
                expr,
                pattern,
                escape,
                case_insensitive,
                negated,
                ..
            } => {
                let left = self.eval_expr(expr, dataset, row, params, ctes, excluded)?;
                let right = self.eval_expr(pattern, dataset, row, params, ctes, excluded)?;
                let escape = escape
                    .as_ref()
                    .map(|expr| self.eval_expr(expr, dataset, row, params, ctes, excluded))
                    .transpose()?;
                eval_like(left, right, escape, *case_insensitive, *negated)
            }
            Expr::IsNull { expr, negated } => {
                let is_null = matches!(
                    self.eval_expr(expr, dataset, row, params, ctes, excluded)?,
                    Value::Null
                );
                Ok(Value::Bool(if *negated { !is_null } else { is_null }))
            }
            Expr::Function { name, args } => {
                eval_function(self, name, args, dataset, row, params, ctes, excluded)
            }
            Expr::Aggregate { .. } => Err(DbError::sql(
                "aggregate expressions require grouped evaluation",
            )),
            Expr::RowNumber { .. } | Expr::WindowFunction { .. } => Err(DbError::sql(
                "window-function execution is not yet implemented",
            )),
            Expr::Case {
                operand,
                branches,
                else_expr,
            } => {
                let operand_value = operand
                    .as_deref()
                    .map(|expr| self.eval_expr(expr, dataset, row, params, ctes, excluded))
                    .transpose()?;
                for (condition, result) in branches {
                    let matches = if let Some(operand_value) = &operand_value {
                        compare_values(
                            operand_value,
                            &self.eval_expr(condition, dataset, row, params, ctes, excluded)?,
                        )? == std::cmp::Ordering::Equal
                    } else {
                        matches!(
                            self.eval_expr(condition, dataset, row, params, ctes, excluded)?,
                            Value::Bool(true)
                        )
                    };
                    if matches {
                        return self.eval_expr(result, dataset, row, params, ctes, excluded);
                    }
                }
                else_expr
                    .as_deref()
                    .map(|expr| self.eval_expr(expr, dataset, row, params, ctes, excluded))
                    .transpose()?
                    .map_or(Ok(Value::Null), Ok)
            }
            Expr::Cast { expr, target_type } => cast_value(
                self.eval_expr(expr, dataset, row, params, ctes, excluded)?,
                *target_type,
            ),
            Expr::Collate { expr, .. } => {
                self.eval_expr(expr, dataset, row, params, ctes, excluded)
            }
            Expr::Row(_) => Err(DbError::sql(
                "row values are only supported in IN comparisons",
            )),
        }
    }

    fn resolve_column(
        &self,
        dataset: &Dataset,
        row: &[Value],
        table: Option<&str>,
        column: &str,
        excluded: Option<&Dataset>,
    ) -> Result<Value> {
        if let Some(table_name) = table {
            if identifiers_equal(table_name, "excluded") {
                let excluded = excluded.ok_or_else(|| {
                    DbError::sql("EXCLUDED is only valid in ON CONFLICT DO UPDATE")
                })?;
                return self.resolve_column(
                    excluded,
                    excluded.rows.first().map(Vec::as_slice).unwrap_or(&[]),
                    None,
                    column,
                    None,
                );
            }
        }
        let mut matched_index = None;
        for (index, binding) in dataset.columns.iter().enumerate() {
            let visible_match = table.is_some() || !binding.hidden;
            if !visible_match || !identifiers_equal(&binding.name, column) {
                continue;
            }
            if table.is_some_and(|table| {
                !binding
                    .table
                    .as_deref()
                    .is_some_and(|binding_table| identifiers_equal(binding_table, table))
            }) {
                continue;
            }
            if matched_index.replace(index).is_some() {
                return Err(DbError::sql(format!("ambiguous column reference {column}")));
            }
        }
        if let Some(index) = matched_index {
            row.get(index)
                .cloned()
                .ok_or_else(|| DbError::internal("row is shorter than its bindings"))
        } else {
            Err(DbError::sql(format!("unknown column {column}")))
        }
    }

    pub(super) fn apply_virtual_generated_columns(
        &self,
        table: &TableSchema,
        row: &mut [Value],
    ) -> Result<()> {
        if generated_columns_are_stored(table) {
            return Ok(());
        }
        let mut base_values = row.to_vec();
        for (index, column) in table.columns.iter().enumerate() {
            let Some(generated_sql) = &column.generated_sql else {
                continue;
            };
            if column.generated_stored {
                base_values[index] = row
                    .get(index)
                    .cloned()
                    .ok_or_else(|| DbError::internal("row is shorter than table schema"))?;
                continue;
            }
            let expr = crate::sql::parser::parse_expression_sql(generated_sql)?;
            let dataset = table_row_dataset(table, &base_values, &table.name);
            let eval_row = dataset.rows.first().map(Vec::as_slice).unwrap_or(&[]);
            let value = self.eval_expr(&expr, &dataset, eval_row, &[], &BTreeMap::new(), None)?;
            let cast_value = self::constraints::coerce_column_value(column, value)?;
            if let Some(slot) = row.get_mut(index) {
                *slot = cast_value.clone();
            } else {
                return Err(DbError::internal("row is shorter than table schema"));
            }
            base_values[index] = cast_value;
        }
        Ok(())
    }
}

pub(crate) fn statement_is_read_only(statement: &Statement) -> bool {
    matches!(statement, Statement::Query(_) | Statement::Explain(_))
}

#[cfg(test)]
mod tests;

pub(super) fn column_position(table: &TableSchema, column_name: &str) -> Option<usize> {
    table
        .columns
        .iter()
        .position(|column| identifiers_equal(&column.name, column_name))
}

pub(super) fn column_schema<'a>(
    table: &'a TableSchema,
    column_name: &str,
) -> Option<&'a ColumnSchema> {
    table
        .columns
        .iter()
        .find(|column| identifiers_equal(&column.name, column_name))
}

